                                )}
                            >
                                <Globe className="w-4 h-4" />
                                {isRTL ? 'استيراد' : 'IMPORT'}
                            </button>
                        )}
                    </div>
                )}
            >
                <AnimatePresence>
                    {showImportSettings && inventorySource === 'korean_import' && (
                        <motion.div
                            initial={{ height: 0, opacity: 0 }}
