                                                    <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-orange-500/40" />
                                                    <input
                                                        type="number"
                                                        step="0.01"
                                                        value={currencySettings.usdToSar}
