        });
        setEditingPart(null); // [[ARABIC_COMMENT]] تصفير حالة التعديل لضمان عدم الكتابة على قطعة قديمة عند إضافة جديدة
    };

    return (
        <div className="relative min-h-screen text-white font-sans overflow-hidden" dir={isRTL ? 'rtl' : 'ltr'}>

