                                    </div>
                                    <div>
                                        <label className="block cockpit-mono text-[9px] text-orange-400/60 uppercase tracking-[0.15em] mb-2">{isRTL ? 'الحالة' : 'CONDITION'}</label>
                                        <select value={formData.condition} onChange={(e) => setFormData({ ...formData, condition: e.target.value })} className="ck-select">
                                            <option value="New">{isRTL ? 'جديد' : 'New'}</option>
                                            <option value="Used">{isRTL ? 'مستعمل' : 'Used'}</option>
                                            <option value="Refurbished">{isRTL ? 'مجدد' : 'Refurbished'}</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block cockpit-mono text-[9px] text-orange-400/60 uppercase tracking-[0.15em] mb-2">{isRTL ? 'الكمية' : 'QTY IN STOCK'}</label>
                                        <input type="number" required min="1" value={formData.stockQty}
                                            onChange={(e) => setFormData({ ...formData, stockQty: parseInt(e.target.value) })} className="ck-input" />
                                    </div>
                                </div>

                                <div className="flex gap-3 pt-4">
                                    <button type="button" onClick={() => setShowModal(false)} className="ck-btn-ghost flex-1">{isRTL ? 'إلغاء' : 'CANCEL'}</button>
                                    <button type="submit" disabled={submitting}
                                        className={cn('ck-btn-primary flex-1 flex items-center justify-center gap-2', submitting && 'opacity-50 cursor-not-allowed')}>
                                        {submitting ? <div className="ck-radar w-4 h-4" /> : <Save className="w-4 h-4" />}
                                        {submitting ? (isRTL ? 'جاري الحفظ...' : 'SAVING...') : (isRTL ? 'حفظ القطعة' : 'SAVE PART')}
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import {
    Download, type LucideIcon, ArrowLeft, DollarSign, ShoppingCart, Car, Gavel, Users, BarChart3, TrendingUp, ArrowUpRight, ArrowDownRight
} from 'lucide-react';
import Link from 'next/link';
import { useLanguage } from '@/lib/LanguageContext';
import { cn } from '@/lib/utils';
import { api } from '@/lib/api';
import { useSettings } from '@/lib/SettingsContext';

interface ReportStat {
    label: string;
    value: string | number;
    sub: string;
    trend: number;
    icon: LucideIcon;
    color: string;
    bgColor: string;
}

interface MonthData {
    month: string;
    revenue: number;
    orders: number;
    cars: number;
}

interface DetailedStatItem {
    _id: {
        year: number;
        month: number;
    };
    revenue: number;
    revenueUsd?: number;
    revenueKrw?: number;
    orders: number;
    count?: number;
}

interface TopCarItem {
    name: string;
    sales: number;
    revenueSar: number;
    revenueUsd?: number;
    revenueKrw?: number;
}

export default function AdminReportsPage() {
    const { isRTL } = useLanguage();
    const { displayCurrency } = useSettings();
    const [loading, setLoading] = useState(true);
    const [period, setPeriod] = useState<'week' | 'month' | 'year'>('month');
    const [stats, setStats] = useState<ReportStat[]>([]);
    const [chartData, setChartData] = useState<MonthData[]>([]);
    const [topCars, setTopCars] = useState<TopCarItem[]>([]);

    // [[ARABIC_COMMENT]] اختيار قيمة الإيراد حسب العملة النشطة في الواجهة
    const pickRevenueByCurrency = (obj: { revenue?: number; revenueUsd?: number; revenueKrw?: number; totalRevenue?: number; totalRevenueUsd?: number; totalRevenueKrw?: number; }) => {
        if (displayCurrency === 'USD') {
            return Number(obj.revenueUsd ?? obj.totalRevenueUsd ?? 0);
        }
        if (displayCurrency === 'KRW') {
            return Number(obj.revenueKrw ?? obj.totalRevenueKrw ?? 0);
        }
        return Number(obj.revenue ?? obj.totalRevenue ?? 0);
    };

    // [[ARABIC_COMMENT]] تنسيق رقم خام إلى نص مالي مناسب (SAR/USD/KRW)
    const formatRawByCurrency = (value: number) => {
        const locale = displayCurrency === 'USD' ? 'en-US' : displayCurrency === 'KRW' ? 'ko-KR' : 'ar-SA';
        const symbol = displayCurrency === 'USD' ? '$' : displayCurrency === 'KRW' ? '₩' : 'ر.س';
        return `${symbol} ${new Intl.NumberFormat(locale, {
            minimumFractionDigits: 0,
            maximumFractionDigits: displayCurrency === 'USD' ? 2 : 0,
        }).format(Number(value || 0))}`;
    };

    const loadReports = async () => {
        setLoading(true);
        try {
            // [[ARABIC_COMMENT]] جلب الملخص + البيانات التفصيلية للفترة المختارة من نفس API
            const [summaryRes, detailedRes] = await Promise.all([
                api.analytics.getSummary(period),
                api.analytics.getDetailed(period)
            ]);

            const summary = summaryRes?.stats || {};
            const detailed = detailedRes?.detailed || { monthlyRevenue: [], monthlyCars: [], topCars: [] };

            setStats([
                {
                    label: isRTL ? 'إجمالي الإيرادات' : 'TOTAL REVENUE',
                    value: formatRawByCurrency(pickRevenueByCurrency(summary)),
                    sub: isRTL ? 'تراكمي' : 'Cumulative',
                    trend: 12.5,
                    icon: DollarSign,
                    color: 'text-green-400',
                    bgColor: 'bg-green-400/10 border-green-400/20',
                },
                {
                    label: isRTL ? 'إجمالي الطلبات' : 'TOTAL ORDERS',
                    value: summary.totalOrders || 0,
                    sub: isRTL ? 'طلبات مكتملة' : 'Completed',
                    trend: 8.3,
                    icon: ShoppingCart,
                    color: 'text-orange-400',
                    bgColor: 'bg-orange-400/10 border-orange-400/20',
                },
                {
                    label: isRTL ? 'السيارات المباعة' : 'CARS SOLD',
                    value: summary.carsSold || 0,
                    sub: isRTL ? 'من إجمالي المخزون' : 'From inventory',
                    trend: -3.1,
                    icon: Car,
                    color: 'text-yellow-400',
                    bgColor: 'bg-yellow-400/10 border-yellow-400/20',
                },
                {
                    label: isRTL ? 'المزادات الجارية' : 'RUNNING AUCTIONS',
                    value: summary.runningAuctions || 0,
                    sub: isRTL ? 'بانتظار المزايدات' : 'Awaiting bids',
                    trend: 22.0,
                    icon: Gavel,
                    color: 'text-red-400',
                    bgColor: 'bg-red-400/10 border-red-400/20',
                },
                {
                    label: isRTL ? 'العملاء الجدد' : 'NEW CLIENTS',
                    value: summary.totalUsers || 0,
                    sub: isRTL ? 'تسجيل جديد' : 'Registered',
                    trend: 5.7,
                    icon: Users,
                    color: 'text-purple-400',
                    bgColor: 'bg-purple-400/10 border-purple-400/20',
                },
                {
                    label: isRTL ? 'قطع الغيار' : 'PARTS COUNT',
                    value: summary.totalParts || 0,
                    sub: isRTL ? 'إجمالي القطع في المعرض' : 'Total units',
                    trend: 15.2,
                    icon: BarChart3,
                    color: 'text-orange-400',
                    bgColor: 'bg-orange-400/10 border-orange-400/20',
                },
            ]);

            // Map detailed monthly revenue
            const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
            const formattedChartData: MonthData[] = detailed.monthlyRevenue.map((item: DetailedStatItem) => {
                const carCount = detailed.monthlyCars.find((c: DetailedStatItem) => c._id.month === item._id.month && c._id.year === item._id.year)?.count || 0;
                return {
                    month: months[item._id.month - 1],
                    revenue: pickRevenueByCurrency(item),
                    orders: item.orders,
                    cars: carCount
                };
            });

            // Ensure we have at least some data if database is empty for the last 6 months
            if (formattedChartData.length === 0) {
                setChartData([
                    { month: 'Sep', revenue: pickRevenueByCurrency({ revenue: 180000, revenueUsd: 48000, revenueKrw: 64800000 }), orders: 8, cars: 5 },
                    { month: 'Oct', revenue: pickRevenueByCurrency({ revenue: 320000, revenueUsd: 85333, revenueKrw: 115200000 }), orders: 14, cars: 9 },
                    { month: 'Nov', revenue: pickRevenueByCurrency({ revenue: 280000, revenueUsd: 74666, revenueKrw: 100800000 }), orders: 11, cars: 7 },
                    { month: 'Dec', revenue: pickRevenueByCurrency({ revenue: 480000, revenueUsd: 128000, revenueKrw: 172800000 }), orders: 19, cars: 13 },
                    { month: 'Jan', revenue: pickRevenueByCurrency({ revenue: 390000, revenueUsd: 104000, revenueKrw: 140400000 }), orders: 16, cars: 10 },
                    { month: 'Feb', revenue: pickRevenueByCurrency({ revenue: 520000, revenueUsd: 138666, revenueKrw: 187200000 }), orders: 21, cars: 14 },
                ]);
            } else {
                setChartData(formattedChartData);
            }

            // [[ARABIC_COMMENT]] ربط أفضل المبيعات (Top Cars) مباشرة من الباكند
            const apiTopCars: TopCarItem[] = Array.isArray(detailed.topCars)
                ? detailed.topCars.map((car: any) => ({
                    name: String(car.name || 'Unknown'),
                    sales: Number(car.sales || 0),
                    revenueSar: Number(car.revenueSar || 0),
                    revenueUsd: Number(car.revenueUsd || 0),
                    revenueKrw: Number(car.revenueKrw || 0),
                }))
                : [];

            if (apiTopCars.length > 0) {
                setTopCars(apiTopCars);
            } else {
                setTopCars([
                    { name: 'Mercedes-Benz S-Class 2024', sales: 8, revenueSar: 3600000, revenueUsd: 960000, revenueKrw: 1296000000 },
                    { name: 'BMW M5 Competition 2023', sales: 6, revenueSar: 2280000, revenueUsd: 608000, revenueKrw: 820800000 },
                    { name: 'Porsche 911 Turbo S 2024', sales: 5, revenueSar: 3600000, revenueUsd: 960000, revenueKrw: 1296000000 },
                    { name: 'Range Rover Autobiography 2024', sales: 7, revenueSar: 2800000, revenueUsd: 746667, revenueKrw: 1008000000 },
                    { name: 'Ferrari Roma 2023', sales: 3, revenueSar: 2400000, revenueUsd: 640000, revenueKrw: 864000000 },
                ]);
            }

        } catch (err) {
            console.error("Failed to load reports", err);
            // Default placeholder stats on error
            setStats([
                { label: isRTL ? 'إجمالي الإيرادات' : 'TOTAL REVENUE', value: formatRawByCurrency(pickRevenueByCurrency({ totalRevenue: 2450000, totalRevenueUsd: 653333, totalRevenueKrw: 882000000 })), sub: isRTL ? 'هذا الشهر' : 'This period', trend: 12.5, icon: DollarSign, color: 'text-green-400', bgColor: 'bg-green-400/10 border-green-400/20' },
                { label: isRTL ? 'إجمالي الطلبات' : 'TOTAL ORDERS', value: 48, sub: isRTL ? 'طلبات مكتملة' : 'Completed', trend: 8.3, icon: ShoppingCart, color: 'text-orange-400', bgColor: 'bg-orange-400/10 border-orange-400/20' },
                { label: isRTL ? 'السيارات المباعة' : 'CARS SOLD', value: 32, sub: isRTL ? 'من المخزون' : 'From inventory', trend: -3.1, icon: Car, color: 'text-yellow-400', bgColor: 'bg-yellow-400/10 border-yellow-400/20' },
            ]);

            setTopCars([
                { name: 'Mercedes-Benz S-Class 2024', sales: 8, revenueSar: 3600000, revenueUsd: 960000, revenueKrw: 1296000000 },
                { name: 'BMW M5 Competition 2023', sales: 6, revenueSar: 2280000, revenueUsd: 608000, revenueKrw: 820800000 },
                { name: 'Porsche 911 Turbo S 2024', sales: 5, revenueSar: 3600000, revenueUsd: 960000, revenueKrw: 1296000000 },
            ]);
        }

        setLoading(false);
    };

    useEffect(() => {
        loadReports();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [period, displayCurrency]);

    const maxRevenue = Math.max(...chartData.map(d => d.revenue));

    const exportToCSV = () => {
        const rows: string[] = [];
        // Header
        rows.push(`HM Car Auction - Admin Report`);
        rows.push(`Period: ${period.toUpperCase()}`);
        rows.push(`Generated: ${new Date().toLocaleDateString()}`);
        rows.push('');

        // Stats section
        rows.push('=== KEY STATISTICS ===');
        rows.push('Metric,Value,Trend');
        stats.forEach(s => {
            rows.push(`"${s.label}","${s.value}","${s.trend >= 0 ? '+' : ''}${s.trend}%"`);
        });
        rows.push('');

        // Chart section
        rows.push('=== MONTHLY REVENUE ===');
        rows.push(`Month,Revenue (${displayCurrency}),Orders,Cars Sold`);
        chartData.forEach(d => {
            rows.push(`${d.month},${Number(d.revenue || 0)},${d.orders},${d.cars}`);
        });
        rows.push('');

        // Top cars section
        rows.push('=== TOP SELLING CARS ===');
        rows.push(`Rank,Car,Units Sold,Revenue (${displayCurrency})`);
        topCars.forEach((car, i) => {
            rows.push(`${i + 1},"${car.name}",${car.sales},${pickRevenueByCurrency({ revenue: car.revenueSar, revenueUsd: car.revenueUsd, revenueKrw: car.revenueKrw })}`);
        });

        const csvContent = rows.join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `hm-report-${period}-${new Date().toISOString().split('T')[0]}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    return (
        <div className="min-h-screen text-white" dir={isRTL ? 'rtl' : 'ltr'}>
            <main className="relative z-10 pt-6 pb-24 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
                {/* HUD Header */}
                <div className="ck-page-header pb-6 mb-8">
                    <div className="flex items-center gap-6">
                        <Link href="/admin/dashboard">
                            <motion.button
                                whileHover={{ scale: 1.1, x: isRTL ? 5 : -5 }}
                                whileTap={{ scale: 0.9 }}
                                className="p-4 rounded-2xl bg-white/5 border border-white/10 hover:border-orange-500/40 hover:bg-orange-500/10 transition-all group shadow-xl"
                            >
                                <ArrowLeft className={cn(
                                    "w-6 h-6 text-white/40 group-hover:text-orange-400 transition-colors",
                                    isRTL && "rotate-180"
                                )} />
                            </motion.button>
                        </Link>
                        <div className="flex-1">
                            <nav className="ck-breadcrumb mb-1">
                                <Link href="/admin/dashboard" className="hover:text-orange-400 transition-colors">HM-CTRL</Link>
                                <span className="ck-breadcrumb-sep">›</span>
                                <span className="text-orange-400/70">{isRTL ? 'التقارير' : 'REPORTS'}</span>
                            </nav>
                            <h1 className="ck-page-title text-3xl md:text-4xl">{isRTL ? 'مركز البيانات والتحليل' : 'ANALYTICS HUB'}</h1>
                        </div>
                    </div>

                    <div className="flex items-center justify-between gap-4 mt-6 flex-wrap">
                        <div className="ck-tab-group">
                            {(['week', 'month', 'year'] as const).map(p => (
                                <button key={p} onClick={() => setPeriod(p)} className={cn('ck-tab', period === p && 'ck-tab-active')}>
                                    {p === 'week' ? (isRTL ? 'أسبوع' : 'WEEK') : p === 'month' ? (isRTL ? 'شهر' : 'MONTH') : (isRTL ? 'سنة' : 'YEAR')}
                                </button>
                            ))}
                        </div>
                        <button onClick={exportToCSV} className="ck-btn-ghost flex items-center gap-2 border-white/10">
                            <Download className="w-3.5 h-3.5" />{isRTL ? 'تصدير البيانات' : 'DATA EXPORT'}
                        </button>
                    </div>
                </div>

                {/* Stats Grid */}
                <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-6 gap-4 mb-10">
                    {loading ? (
                        Array.from({ length: 6 }).map((_, i) => (
                            <div key={i} className="h-28 rounded-2xl bg-white/[0.02] animate-pulse border border-orange-500/10" />
                        ))
                    ) : (
                        stats.map((stat, i) => (
                            <motion.div key={i}
                                initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: i * 0.07 }}
                                className="ck-stat">
                                <div className="flex items-start justify-between mb-3">
                                    <div className={cn('p-2 rounded-xl bg-black/30', stat.color)}>
                                        <stat.icon size={16} />
                                    </div>
                                    <div className={cn('flex items-center gap-0.5 cockpit-mono text-[9px]', stat.trend >= 0 ? 'text-green-400' : 'text-red-400')}>
                                        {stat.trend >= 0 ? <ArrowUpRight className="w-3 h-3" /> : <ArrowDownRight className="w-3 h-3" />}
                                        {Math.abs(stat.trend)}%
                                    </div>
                                </div>
                                <div className={cn('cockpit-num text-xl font-black mb-0.5', stat.color)}>{stat.value}</div>
                                <div className="cockpit-mono text-[8px] text-white/40 uppercase tracking-[0.15em]">{stat.label}</div>
                            </motion.div>
                        ))
                    )}
                </div>

                <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                    {/* Revenue Chart */}
                    <div className="xl:col-span-2 ck-card p-6">
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <p className="cockpit-mono text-[9px] text-orange-500/50 uppercase tracking-[0.2em] mb-1">{isRTL ? 'الإيرادات الشهرية' : 'MONTHLY REVENUE'}</p>
                                <div className="cockpit-num text-2xl font-black text-orange-400">
                                    {formatRawByCurrency(chartData.reduce((sum, d) => sum + d.revenue, 0))}
                                </div>
                            </div>
                        </div>
                        <div className="h-48 flex items-end gap-2">
                            {chartData.map((d, i) => (
                                <div key={i} className="flex-1 flex flex-col items-center gap-1">
                                    <motion.div
                                        initial={{ height: 0 }}
                                        animate={{ height: `${(d.revenue / maxRevenue) * 100}%` }}
                                        transition={{ duration: 1, delay: i * 0.1, ease: 'easeOut' }}
                                        className="w-full bg-gradient-to-t from-orange-500/30 to-orange-500/80 rounded-t-lg relative group cursor-pointer hover:from-orange-500/50 hover:to-orange-400 transition-all"
                                    >
                                        <div className="absolute -top-7 left-1/2 -translate-x-1/2 bg-[#070711] border border-orange-500/20 rounded-lg px-2 py-0.5 cockpit-mono text-[8px] whitespace-nowrap opacity-0 group-hover:opacity-100 transition-all z-10">
                                            {(d.revenue / 1000).toFixed(0)}K
                                        </div>
                                    </motion.div>
                                    <span className="cockpit-mono text-[8px] text-white/30">{d.month}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Top Cars */}
                    <div className="ck-card p-6">
                        <div className="cockpit-mono text-[9px] text-orange-500/50 uppercase tracking-[0.2em] mb-5 flex items-center gap-2">
                            <TrendingUp className="w-3.5 h-3.5 text-orange-400" />
                            {isRTL ? 'أعلى السيارات مبيعاً' : 'TOP SELLING CARS'}
                        </div>
                        <div className="space-y-4">
                            {topCars.map((car, i) => (
                                <motion.div key={i}
                                    initial={{ opacity: 0, x: isRTL ? 20 : -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: i * 0.1 }}
                                    className="flex items-center gap-3">
                                    <div className={cn(
                                        'w-7 h-7 rounded-xl flex items-center justify-center cockpit-mono text-[10px] font-black shrink-0',
                                        i === 0 ? 'bg-yellow-400/20 text-yellow-400 border border-yellow-400/30' :
                                            i === 1 ? 'bg-white/10 text-white/60 border border-white/10' :
                                                i === 2 ? 'bg-orange-400/10 text-orange-400 border border-orange-400/20' :
                                                    'bg-white/5 text-white/30 border border-white/5'
                                    )}>{i + 1}</div>
                                    <div className="flex-1 min-w-0">
                                        <div className="cockpit-mono text-[9px] text-white/70 uppercase tracking-wide truncate mb-1">{car.name}</div>
                                        <div className="flex items-center gap-2">
                                            <div className="flex-1 h-1 bg-white/5 rounded-full overflow-hidden">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${(car.sales / topCars[0].sales) * 100}%` }}
                                                    transition={{ duration: 1, delay: i * 0.1 }}
                                                    className="h-full bg-gradient-to-r from-orange-500 to-orange-400/60 rounded-full"
                                                />
                                            </div>
                                            <span className="cockpit-mono text-[9px] text-white/30 shrink-0">{car.sales}</span>
                                        </div>
                                    </div>
                                </motion.div>
                            ))}
                        </div>
                        <div className="mt-6 pt-4 border-t border-orange-500/10 space-y-2">
                            <div className="flex justify-between items-center">
                                <span className="cockpit-mono text-[9px] text-white/30 uppercase">{isRTL ? 'إجمالي الإيرادات' : 'TOTAL REVENUE'}</span>
                                <span className="cockpit-num text-[11px] text-orange-400">
                                    {formatRawByCurrency(
                                        topCars.reduce(
                                            (s, c) => s + pickRevenueByCurrency({ revenue: c.revenueSar, revenueUsd: c.revenueUsd, revenueKrw: c.revenueKrw }),
                                            0
                                        )
                                    )}
                                </span>
                            </div>
                            <div className="flex justify-between items-center">
                                <span className="cockpit-mono text-[9px] text-white/30 uppercase">{isRTL ? 'إجمالي المبيعات' : 'TOTAL UNITS'}</span>
                                <span className="cockpit-num text-[11px] text-green-400">{topCars.reduce((s, c) => s + c.sales, 0)} {isRTL ? 'سيارة' : 'Cars'}</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Quick Summary */}
                <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-4">
                    {[
                        { label: isRTL ? 'معدل التحويل' : 'CONVERSION RATE', value: '68%', icon: TrendingUp, color: 'text-green-400' },
                        { label: isRTL ? 'متوسط قيمة الطلب' : 'AVG ORDER VALUE', value: formatRawByCurrency(pickRevenueByCurrency({ revenue: 51000, revenueUsd: 13600, revenueKrw: 18360000 })), icon: DollarSign, color: 'text-orange-400' },
                        { label: isRTL ? 'معدل الاسترداد' : 'RETURN RATE', value: '2.1%', icon: ArrowDownRight, color: 'text-red-400' },
                        { label: isRTL ? 'رضا العملاء' : 'CLIENT SATISFACTION', value: '96%', icon: Users, color: 'text-purple-400' },
                    ].map((item, i) => (
                        <motion.div key={i}
                            initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.5 + i * 0.07 }}
                            className="ck-card p-4 flex items-center gap-3">
                            <item.icon className={cn('w-5 h-5 shrink-0', item.color)} />
                            <div>
                                <div className={cn('cockpit-num text-lg font-black', item.color)}>{item.value}</div>
                                <div className="cockpit-mono text-[8px] text-white/30 uppercase tracking-widest mt-0.5">{item.label}</div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            </main>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Shield, ShieldAlert, ShieldCheck, Lock, Unlock,
    Smartphone, Search, RefreshCw, History,
    AlertTriangle, Server, X
} from 'lucide-react';
import { api } from '@/lib/api';
import { useLanguage } from '@/lib/LanguageContext';
import { cn } from '@/lib/utils';
import { useToast } from '@/lib/ToastContext';
import AdminPageShell from '@/components/AdminPageShell';

interface SecurityDevice {
    _id: string;
    deviceId?: string;
    banCode?: string;
    ip?: string;
    userAgent?: string;
    banned: boolean;
    exemptFromSecurity: boolean;
    banReason?: string;
    lastSeenAt?: string;
    updatedAt?: string;
    createdAt?: string;
    deviceInfo?: string;
}

export default function AdminSecurity() {
    const { isRTL } = useLanguage();
    const { showToast } = useToast();
    const [devices, setDevices] = useState<SecurityDevice[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterTab, setFilterTab] = useState<'all' | 'banned' | 'clean' | 'exempt'>('all');
    const [selectedDevice, setSelectedDevice] = useState<SecurityDevice | null>(null);
    const [stats, setStats] = useState({ total: 0, banned: 0, exempt: 0 });

    const loadData = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.security.getDevices();
            const deviceList = Array.isArray(res.data) ? res.data : (Array.isArray(res.devices) ? res.devices : []);

            if (deviceList.length > 0) {
                const seen = new Set();
                const unique = deviceList
                    .sort((a: SecurityDevice, b: SecurityDevice) => {
                        const dateA = new Date(a.lastSeenAt || a.updatedAt || a._id).getTime();
                        const dateB = new Date(b.lastSeenAt || b.updatedAt || b._id).getTime();
                        return dateB - dateA;
                    })
                    .filter((d: SecurityDevice) => {
                        const key = d.deviceId || d.banCode || d.ip;
                        if (!key || seen.has(key)) return false;
                        seen.add(key);
                        return true;
                    });
                setDevices(unique as SecurityDevice[]);
                setStats({
                    total: unique.length,
                    banned: unique.filter((d: SecurityDevice) => d.banned).length,
                    exempt: unique.filter((d: SecurityDevice) => d.exemptFromSecurity).length
                });
            } else {
                setDevices([]);
                setStats({ total: 0, banned: 0, exempt: 0 });
            }
        } catch (err) {
            console.error('Failed to load security data:', err);
            showToast(isRTL ? 'فشل تحميل بيانات الأمان' : 'Failed to load security data', 'error');
        } finally {
            setLoading(false);
        }
    }, [isRTL, showToast]);

    useEffect(() => { loadData(); }, [loadData]);

    const toggleBan = async (device: SecurityDevice) => {
        try {
            const res = await api.security.banDevice(device.banCode || '', !device.banned);
            if (res.success) {
                showToast(isRTL ? 'تم تحديث حالة الحظر' : 'Ban status updated', 'success');
                loadData();
            }
        } catch (err) {
            showToast(isRTL ? 'فشل تحديث الحظر' : 'Failed to update ban', 'error');
        }
    };

    const toggleExempt = async (device: SecurityDevice) => {
        try {
            const res = await api.security.exemptDevice(device.banCode || '', !device.exemptFromSecurity);
            if (res.success) {
                showToast(isRTL ? 'تم تحديث الاستثناء' : 'Exemption updated', 'success');
                loadData();
            }
        } catch (err) {
            showToast(isRTL ? 'فشل تحديث الاستثناء' : 'Failed to update exemption', 'error');
        }
    };

    const filtered = devices.filter(d => {
        const matchesSearch = (d.banCode?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
                            (d.deviceId?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
                            (d.ip?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
                            (d.deviceInfo?.toLowerCase() || '').includes(searchTerm.toLowerCase());

        if (!matchesSearch) return false;
        if (filterTab === 'banned') return d.banned;
        if (filterTab === 'exempt') return d.exemptFromSecurity && !d.banned;
        if (filterTab === 'clean') return !d.banned && !d.exemptFromSecurity;
        return true;
    });

    return (
        <div className="min-h-screen text-white bg-black overflow-hidden" dir={isRTL ? 'rtl' : 'ltr'}>
            <div className="fixed inset-0 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,rgba(255,59,48,0.1),transparent_70%)]" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:100px_100px]" />
            </div>

            <AdminPageShell
                title={isRTL ? 'الأمن والحماية' : 'SECURITY OPS'}
                titleEn="ENDPOINT PROTECTION"
                backHref="/admin/dashboard"
                isRTL={isRTL}
                actions={
                    <button 
                        onClick={loadData} 
                        title={isRTL ? 'تحديث البيانات' : 'Refresh Data'}
                        className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-red-500 shadow-[0_0_15px_rgba(255,59,48,0.2)]"
                    >
                        <RefreshCw className={cn('w-5 h-5', loading && 'animate-spin')} />
                    </button>
                }
            >
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
                    <div className="ck-card p-6 border-red-500/10 bg-red-500/5">
                        <div className="flex justify-between items-start mb-4">
                            <div className="w-10 h-10 rounded-xl bg-red-500/10 flex items-center justify-center">
                                <Smartphone className="w-5 h-5 text-red-500" />
                            </div>
                            <span className="cockpit-mono text-[10px] text-red-500/50 uppercase">Tracked</span>
                        </div>
                        <div className="text-3xl font-black mb-1 italic">{stats.total}</div>
                        <div className="cockpit-mono text-[9px] text-white/30 uppercase tracking-widest">{isRTL ? 'إجمالي الأجهزة' : 'TOTAL ENDPOINTS'}</div>
                    </div>

                    <div className="ck-card p-6 border-red-500/10 bg-red-500/5">
                        <div className="flex justify-between items-start mb-4">
                            <div className="w-10 h-10 rounded-xl bg-red-500/10 flex items-center justify-center">
                                <ShieldAlert className="w-5 h-5 text-red-500" />
                            </div>
                            <span className="cockpit-mono text-[10px] text-red-500/50 uppercase">Restricted</span>
                        </div>
                        <div className="text-3xl font-black mb-1 italic text-red-500">{stats.banned}</div>
                        <div className="cockpit-mono text-[9px] text-white/30 uppercase tracking-widest">{isRTL ? 'المحظورين' : 'BANNED DEVICES'}</div>
                    </div>

                    <div className="ck-card p-6 border-red-500/10 bg-red-500/5">
                        <div className="flex justify-between items-start mb-4">
                            <div className="w-10 h-10 rounded-xl bg-red-500/10 flex items-center justify-center">
                                <ShieldCheck className="w-5 h-5 text-red-500" />
                            </div>
                            <span className="cockpit-mono text-[10px] text-red-500/50 uppercase">Whitelisted</span>
                        </div>
                        <div className="text-3xl font-black mb-1 italic">{stats.exempt}</div>
                        <div className="cockpit-mono text-[9px] text-white/30 uppercase tracking-widest">{isRTL ? 'المستثنون' : 'EXEMPTED LIST'}</div>
                    </div>
                </div>

                <div className="flex flex-col md:flex-row gap-4 mb-6">
                    <div className="relative flex-1">
                        <Search className={cn('absolute top-1/2 -translate-y-1/2 w-4 h-4 text-white/20', isRTL ? 'right-4' : 'left-4')} />
                        <input 
                            type="text"
                            placeholder={isRTL ? 'بحث عن طريق IP، معرف الجهاز، أو المتصفح...' : 'Search by IP, Device ID, or UA...'}
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className={cn('ck-input h-12 text-sm focus:border-red-500/40', isRTL ? 'pr-12' : 'pl-12')}
                        />
                    </div>
                    <div className="ck-tab-group p-1 bg-red-500/5 border border-red-500/10 rounded-2xl flex">
                        {[
                            { id: 'all', label: isRTL ? 'الكل' : 'ALL' },
                            { id: 'banned', label: isRTL ? 'محظور' : 'BANNED' },
                            { id: 'clean', label: isRTL ? 'نشط' : 'ACTIVE' },
                            { id: 'exempt', label: isRTL ? 'مستثنى' : 'EXEMPT' },
                        ].map(t => (
                            <button
                                key={t.id}
                                onClick={() => setFilterTab(t.id as 'all' | 'banned' | 'clean' | 'exempt')}
                                title={t.label}
                                className={cn(
                                    'px-6 py-2 rounded-xl text-[10px] font-black tracking-widest transition-all',
                                    filterTab === t.id ? 'bg-red-500 text-white shadow-[0_0_15px_rgba(255,59,48,0.5)]' : 'text-white/40 hover:text-white/70'
                                )}
                            >
                                {t.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto ck-scroll space-y-3 pb-8">
                    {loading ? (
                        Array.from({ length: 5 }).map((_, i) => (
                            <div key={i} className="h-24 rounded-2xl bg-white/[0.02] animate-pulse border border-white/5" />
                        ))
                    ) : filtered.length === 0 ? (
                        <div className="ck-empty py-24">
                            <div className="ck-empty-icon"><Shield className="w-8 h-8" /></div>
                            <p className="cockpit-mono text-sm">{isRTL ? 'لا توجد أجهزة مطابقة للبحث' : 'NO ENDPOINTS MATCH YOUR SEARCH'}</p>
                        </div>
                    ) : (
                        filtered.map((device, i) => (
                            <motion.div
                                key={device._id}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: i * 0.05 }}
                                className={cn(
                                    'ck-card group hover:bg-white/[0.03] p-5 transition-all flex flex-col md:flex-row items-start md:items-center gap-6 border',
                                    device.banned ? 'border-red-500/20 bg-red-500/[0.02]' : 'border-white/5 bg-white/[0.01]'
                                )}
                            >
                                <div className={cn(
                                    'w-12 h-12 rounded-2xl flex items-center justify-center shrink-0 border transition-all',
                                    device.banned ? 'bg-red-500/10 border-red-500/20 text-red-500 shadow-[0_0_15px_rgba(255,59,48,0.1)]' : 'bg-red-500/5 border-white/10 text-white/40'
                                )}>
                                    {device.banned ? <ShieldAlert className="w-6 h-6" /> : <Smartphone className="w-6 h-6" />}
                                </div>

                                <div className="flex-1 min-w-0">
                                    <div className="flex flex-wrap items-center gap-3 mb-1.5">
                                        <h3 className="text-sm font-black tracking-tight font-mono">
                                            {device.deviceId || device.banCode || device.ip || (isRTL ? 'غير معرف' : 'UNKNOWN ID')}
                                        </h3>
                                        {device.ip && <span className="ck-badge bg-white/5 text-white/40 border-white/10 font-mono text-[9px]">{device.ip}</span>}
                                        {device.banned && <span className="ck-badge ck-badge-danger text-[8px]">{isRTL ? 'محظور نأئياً' : 'HARD BANNED'}</span>}
                                        {device.exemptFromSecurity && <span className="ck-badge bg-green-500/10 text-green-400 border-green-500/20 text-[8px]">{isRTL ? 'مستثنى من الحماية' : 'SECURITY EXEMPT'}</span>}
                                    </div>
                                    <p className="text-[10px] text-white/30 truncate max-w-2xl font-mono">
                                        {device.deviceInfo || device.userAgent || 'No hardware details available'}
                                    </p>
                                    <div className="flex items-center gap-4 mt-2">
                                        <div className="flex items-center gap-1 cockpit-mono text-[8px] text-white/20 uppercase tracking-widest">
                                            <History className="w-3 h-3" />
                                            {isRTL ? 'آخر نشاط:' : 'LAST SEEN:'} {device.lastSeenAt ? new Date(device.lastSeenAt).toLocaleString() : '---'}
                                        </div>
                                        {device.banReason && (
                                            <div className="flex items-center gap-1 cockpit-mono text-[8px] text-red-400/50 uppercase tracking-widest">
                                                <AlertTriangle className="w-3 h-3" />
                                                {isRTL ? 'السبب:' : 'REASON:'} {device.banReason}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="flex gap-2 w-full md:w-auto">
                                    <button 
                                        onClick={() => toggleBan(device)}
                                        title={device.banned ? (isRTL ? 'إلغاء الحظر' : 'Unban') : (isRTL ? 'حظر' : 'Ban')}
                                        className={cn(
                                            "flex-1 md:flex-none h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all flex items-center justify-center gap-2",
                                            device.banned ? "bg-green-500/10 border border-green-500/20 text-green-400 hover:bg-green-500 hover:text-black" : "bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500 hover:text-white"
                                        )}
                                    >
                                        {device.banned ? <Unlock className="w-3.5 h-3.5" /> : <Lock className="w-3.5 h-3.5" />}
                                        {device.banned ? (isRTL ? 'فك الحظر' : 'UNBAN') : (isRTL ? 'حظر' : 'RESTRICT')}
                                    </button>

                                    <button 
                                        onClick={() => toggleExempt(device)}
                                        className={cn(
                                            'flex-1 md:flex-none h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all flex items-center justify-center gap-2 border',
                                            device.exemptFromSecurity 
                                                ? 'bg-orange-500/10 border-orange-500/20 text-orange-400 hover:bg-orange-500/20' 
                                                : 'bg-white/5 border-white/10 text-white/30 hover:bg-white/10'
                                        )}
                                        title={isRTL ? 'استثناء من فحوصات الأمان' : 'Exempt from security checks'}
                                    >
                                        <ShieldCheck className="w-3.5 h-3.5" />
                                        {isRTL ? 'استثناء' : 'EXEMPT'}
                                    </button>

                                    <button 
                                        onClick={() => setSelectedDevice(device)}
                                        title={isRTL ? 'عرض التفاصيل' : 'View Details'}
                                        className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 border border-white/10 text-white/40 hover:bg-white/10 hover:text-white transition-all"
                                    >
                                        <Server className="w-4 h-4" />
                                    </button>
                                </div>
                            </motion.div>
                        ))
                    )}
                </div>
            </AdminPageShell>

            <AnimatePresence>
                {selectedDevice && (
                    <motion.div 
                        initial={{ opacity: 0 }} 
                        animate={{ opacity: 1 }} 
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md"
                        onClick={() => setSelectedDevice(null)}
                    >
                        <motion.div 
                            initial={{ scale: 0.9, y: 20 }} 
                            animate={{ scale: 1, y: 0 }} 
                            exit={{ scale: 0.9, y: 20 }}
                            onClick={(e) => e.stopPropagation()}
                            className="bg-cinematic-dark border border-white/15 rounded-[2.5rem] p-8 max-w-2xl w-full shadow-[0_0_100px_rgba(59,130,246,0.15)] relative overflow-hidden"
                            dir={isRTL ? 'rtl' : 'ltr'}
                        >
                            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-48 h-1 bg-red-500 shadow-[0_0_20px_rgba(239,68,68,1)] rounded-full" />

                            <div className="flex items-center justify-between mb-8">
                                <div className="flex items-center gap-4">
                                    <div className="w-14 h-14 rounded-2xl bg-red-500/10 border border-red-500/20 flex items-center justify-center">
                                        <Smartphone className="w-7 h-7 text-red-400" />
                                    </div>
                                    <div>
                                        <div className="cockpit-mono text-[10px] text-red-400 tracking-[0.3em] uppercase mb-1">ENDPOINT ANALYTICS</div>
                                        <h2 className="text-2xl font-black italic tracking-tighter truncate max-w-[300px]">{selectedDevice.deviceId || selectedDevice.banCode || 'INTERNAL-ID'}</h2>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => setSelectedDevice(null)} 
                                    title={isRTL ? 'إغلاق' : 'Close'}
                                    className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all"
                                >
                                    <X className="w-5 h-5" />
                                </button>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                                <div className="p-4 bg-white/[0.03] border border-white/5 rounded-2xl">
                                    <div className="text-[9px] font-black text-white/20 uppercase tracking-widest mb-1.5">{isRTL ? 'عنوان الـ IP' : 'NETWORK IP'}</div>
                                    <div className="font-mono text-sm text-blue-400">{selectedDevice.ip || '---.---.---.---'}</div>
                                </div>
                                <div className="p-4 bg-white/[0.03] border border-white/5 rounded-2xl">
                                    <div className="text-[9px] font-black text-white/20 uppercase tracking-widest mb-1.5">{isRTL ? 'الحالة الأمنية' : 'SECURITY STATUS'}</div>
                                    <div className={cn('font-black text-sm uppercase', selectedDevice.banned ? 'text-red-500' : 'text-green-500')}>
                                        {selectedDevice.banned ? (isRTL ? 'محظور نأئياً' : 'BANNED') : (isRTL ? 'نشط / آمن' : 'SECURE / ACTIVE')}
                                    </div>
                                </div>
                            </div>

                            <div className="p-6 bg-black/40 border border-white/8 rounded-3xl mb-8">
                                <div className="text-[10px] font-black text-red-400/50 uppercase tracking-widest mb-4 flex items-center gap-2">
                                    <Server className="w-3.5 h-3.5" />
                                    {isRTL ? 'بصمة الجهاز والبيئة:' : 'HARDWARE FINGERPRINT & AGENT:'}
                                </div>
                                <div className="font-mono text-[11px] leading-relaxed text-white/60 bg-white/[0.02] p-4 rounded-xl border border-white/5 break-all">
                                    {selectedDevice.userAgent || 'No User Agent string recorded.'}
                                </div>
                                <div className="mt-4 font-mono text-xs text-red-400/60 break-all">
                                    {selectedDevice.deviceInfo || 'Detailed hardware identifiers not available.'}
                                </div>
                            </div>

                            <div className="flex gap-4">
                                <button 
                                    onClick={() => { toggleBan(selectedDevice); setSelectedDevice(null); }}
                                    className={cn(
                                        "flex-1 h-14 rounded-2xl text-xs font-black uppercase tracking-[0.2em] shadow-[0_0_20px_rgba(34,197,94,0.3)] hover:scale-[1.02] active:scale-[0.98] transition-all",
                                        selectedDevice.banned ? "bg-green-500 text-black shadow-[0_0_20px_rgba(34,197,94,0.3)]" : "bg-red-600 text-white shadow-[0_0_20px_rgba(220,38,38,0.3)]"
                                    )}
                                >
                                    {selectedDevice.banned ? (isRTL ? 'إلغاء الحظر الآن' : 'RESTORE ACCESS') : (isRTL ? 'حظر الجهاز نهائياً' : 'PERMANENT BAN')}
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';

/**
 * تبويبات إعدادات النظام المتبقية
 * ─────────────────────────────────
 * يحتوي على 6 تبويبات:
 * 1. SocialTab    - روابط التواصل الاجتماعي
 * 2. ContactTab   - معلومات الاتصال
 * 3. CurrencyTab  - إعدادات العملة وأسعار الصرف
 * 4. SiteTab      - هوية الموقع (الشعار والوصف)
 * 5. HomeTab      - محتوى الصفحة الرئيسية (Hero)
 * 6. FeaturesTab  - قسم "لماذا تختارنا"
 */

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
    Save, Globe, MessageCircle, Instagram, Youtube, Facebook, Camera,
    Send, Linkedin, Phone, Mail, MapPin, Clock, DollarSign, LayoutDashboard, Shield
} from 'lucide-react';
import NextImage from 'next/image';
import { api } from '@/lib/api';

const EMPTY_STRING = '';
const rawText = (value: string) => value;

// ── أنواع البيانات ──
interface SocialLinks { whatsapp: string; instagram: string; twitter: string; facebook: string; youtube: string; tiktok: string; snapchat: string; telegram: string; linkedin: string; }
interface ContactInfo { phone: string; email: string; address: string; workingHours: string; }
interface CurrencySettings { usdToSar: number; usdToKrw: number; activeCurrency: string; partsMultiplier: number; auctionMultiplier: number; }
interface SiteInfo { siteName: string; siteDescription: string; logoUrl: string; faviconUrl: string; }
interface HomeContent { heroTitle: string; heroSubtitle: string; heroVideoUrl: string; }
interface Feature { icon: string; title: string; desc: string;[key: string]: string; }

// ─────────────────────────────────
// تبويب التواصل الاجتماعي
// ─────────────────────────────────
export function SocialTab({ socialLinks, loading, isRTL, onSave, onLinkChange, setMessage }: {
    socialLinks: SocialLinks;
    loading: boolean;
    isRTL: boolean;
    onSave: () => void;
    onLinkChange: (links: SocialLinks) => void;
    setMessage: (msg: { type: string; text: string }) => void;
}) {
    // قائمة منصات التواصل الاجتماعي المدعومة
    const socialFields = [
        { key: 'whatsapp', label: 'WhatsApp', icon: MessageCircle, placeholder: '+966XXXXXXXXX', color: 'text-green-500' },
        { key: 'instagram', label: 'Instagram', icon: Instagram, placeholder: 'https://instagram.com/...', color: 'text-pink-500' },
        { key: 'twitter', label: 'X (Twitter)', icon: Globe, placeholder: 'https://x.com/...', color: 'text-white' },
        { key: 'facebook', label: 'Facebook', icon: Facebook, placeholder: 'https://facebook.com/...', color: 'text-blue-500' },
        { key: 'youtube', label: 'YouTube', icon: Youtube, placeholder: 'https://youtube.com/...', color: 'text-red-500' },
        { key: 'tiktok', label: 'TikTok', icon: Camera, placeholder: 'https://tiktok.com/@...', color: 'text-white' },
        { key: 'snapchat', label: 'Snapchat', icon: Camera, placeholder: 'snapchat_username', color: 'text-yellow-400' },
        { key: 'telegram', label: 'Telegram', icon: Send, placeholder: 'https://t.me/...', color: 'text-blue-400' },
        { key: 'linkedin', label: 'LinkedIn', icon: Linkedin, placeholder: 'https://linkedin.com/...', color: 'text-blue-600' },
    ];

    return (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="space-y-4">
            <div className="p-8 bg-white/2 border border-white/5 rounded-3xl">
                <h2 className="text-lg font-black uppercase tracking-wider mb-2 flex items-center gap-3">
                    <Globe className="w-5 h-5 text-cinematic-neon-red" />
                    {isRTL ? rawText('روابط التواصل الاجتماعي') : rawText('Social Media Links')}
                </h2>
                <p className="text-xs text-white/40 mb-8">
                    {isRTL
                        ? rawText('✅ الروابط التي تضيفها فقط ستظهر — الروابط الفارغة لا تظهر أبداً')
                        : rawText('✅ Only links you add will appear — empty links are hidden')}
                </p>
                <div className="space-y-3">
                    {socialFields.map(field => {
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                        const currentVal = ((socialLinks as any)[field.key] as string) || EMPTY_STRING;
                        const hasValue = currentVal.trim() !== EMPTY_STRING;
                        const Icon = field.icon;
                        return (
                            <div key={field.key}
                                className={`flex items-center gap-3 p-4 rounded-2xl border transition-all ${hasValue ? 'bg-white/4 border-white/15' : 'bg-white/1 border-white/5 opacity-60'}`}>
                                {/* أيقونة المنصة */}
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${hasValue ? 'bg-white/10' : 'bg-white/5'}`}>
                                    <Icon className={`w-5 h-5 ${field.color}`} />
                                </div>
                                {/* حقل الرابط */}
                                <div className="flex-1 min-w-0">
                                    <div className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-1">
                                        {field.label}
                                        {hasValue
                                            ? <span className="mr-2 text-green-400">{rawText('● موجود')}</span>
                                            : <span className="mr-2 text-white/20">{rawText('○ فارغ - لن يظهر')}</span>
                                        }
                                    </div>
                                    <input type="text" value={currentVal} dir="ltr"
                                        onChange={e => onLinkChange({ ...socialLinks, [field.key]: e.target.value })}
                                        placeholder={field.placeholder}
                                        className="w-full bg-transparent text-sm text-white placeholder:text-white/20 outline-none border-b border-white/10 pb-1 focus:border-cinematic-neon-red/40 transition-colors" />
                                </div>
                                {/* أزرار الحفظ والحذف */}
                                <div className="flex items-center gap-2 shrink-0">
                                    {hasValue && (
                                        <button type="button" title="حفظ"
                                            onClick={async () => {
                                                try {
                                                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                                    await api.settings.updateSocialLinks({ socialLinks: socialLinks as any });
                                                    setMessage({ type: 'success', text: isRTL ? `✅ تم حفظ ${field.label}` : `✅ ${field.label} saved` });
                                                    setTimeout(() => setMessage({ type: EMPTY_STRING, text: EMPTY_STRING }), 2000);
                                                } catch { setMessage({ type: 'error', text: isRTL ? 'فشل الحفظ' : 'Save failed' }); }
                                            }}
                                            className="px-3 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 hover:bg-emerald-500/20 transition-all">
                                            {isRTL ? rawText('حفظ') : rawText('Save')}
                                        </button>
                                    )}
                                    <button type="button" title="حذف"
                                        onClick={async () => {
                                            const updated = { ...socialLinks, [field.key]: EMPTY_STRING };
                                            onLinkChange(updated as SocialLinks);
                                            try {
                                                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                                await api.settings.updateSocialLinks({ socialLinks: updated as any });
                                                setMessage({ type: 'success', text: isRTL ? `🗑️ تم حذف ${field.label}` : `🗑️ ${field.label} removed` });
                                                setTimeout(() => setMessage({ type: EMPTY_STRING, text: EMPTY_STRING }), 2000);
                                            } catch { setMessage({ type: 'error', text: isRTL ? 'فشل الحذف' : 'Delete failed' }); }
                                        }}
                                        className="px-3 py-2 text-[10px] font-black uppercase tracking-wider rounded-lg bg-red-500/10 border border-red-500/30 text-red-400 hover:bg-red-500/20 transition-all">
                                        {isRTL ? rawText('حذف') : rawText('Del')}
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
            <SaveButton loading={loading} isRTL={isRTL} label={isRTL ? 'حفظ جميع الروابط' : 'Save All Links'} onClick={onSave} />
        </motion.div>
    );
}

