export function FeaturesTab({ features, loading, isRTL, onSave, onFeaturesChange }: {
    features: Feature[]; loading: boolean; isRTL: boolean;
    onSave: () => void;
    onFeaturesChange: (features: Feature[]) => void;
}) {
    // تحديث حقل واحد في ميزة محددة
    const updateFeature = (idx: number, field: string, value: string) => {
        const updated = [...features];
        updated[idx][field] = value;
        onFeaturesChange(updated);
    };

    return (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="space-y-6">
            <div className="p-8 bg-white/2 border border-white/5 rounded-3xl">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-lg font-black uppercase tracking-wider flex items-center gap-3">
                        <Shield className="w-5 h-5 text-cinematic-neon-red" />
                        {isRTL ? rawText('لماذا تختارنا') : rawText('Why Choose Us')}
                    </h2>
                    {/* زر إضافة ميزة جديدة */}
                    <button onClick={() => onFeaturesChange([...features, { icon: 'Star', title: '', desc: '' }])}
                        className="px-4 py-2 bg-white/10 hover:bg-white/20 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all">
                        {isRTL ? rawText('+ إضافة ميزة') : rawText('+ ADD FEATURE')}
                    </button>
                </div>
                <div className="grid grid-cols-1 gap-6">
                    {features.map((feature, idx) => (
                        <div key={idx} className="p-6 bg-white/5 border border-white/10 rounded-2xl relative group">
                            {/* زر حذف الميزة */}
                            <button onClick={() => onFeaturesChange(features.filter((_, i) => i !== idx))}
                                className="absolute top-4 right-4 text-white/20 hover:text-cinematic-neon-red transition-colors">
                                {rawText('✕')}
                            </button>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                {/* اسم الأيقونة */}
                                <div>
                                    <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest mb-1 block">{rawText('Icon Name (Lucide)')}</label>
                                    <input type="text" value={feature.icon}
                                        onChange={e => updateFeature(idx, 'icon', e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg py-3 px-4 text-xs text-white"
                                        placeholder="e.g. Shield, Star, Zap" />
                                </div>
                                {/* العنوان */}
                                <div>
                                    <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest mb-1 block">{rawText('Title')}</label>
                                    <input type="text" value={feature.title}
                                        onChange={e => updateFeature(idx, 'title', e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg py-3 px-4 text-xs text-white"
                                        placeholder="Feature Title" />
                                </div>
                                {/* الوصف */}
                                <div>
                                    <label className="text-[9px] font-bold text-white/30 uppercase tracking-widest mb-1 block">{rawText('Description')}</label>
                                    <input type="text" value={feature.desc}
                                        onChange={e => updateFeature(idx, 'desc', e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg py-3 px-4 text-xs text-white"
                                        placeholder="Feature Description" />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
            <SaveButton loading={loading} isRTL={isRTL} label={isRTL ? 'حفظ المميزات' : 'Save Features'} onClick={onSave} />
        </motion.div>
    );
}

// ─────────────────────────────────
// مكوّن زر الحفظ المشترك (لإزالة التكرار)
// ─────────────────────────────────
function SaveButton({ loading, isRTL, label, onClick, white = false }: {
    loading: boolean; isRTL: boolean; label: string; onClick: () => void; white?: boolean;
}) {
    return (
        <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
            onClick={onClick} disabled={loading}
            className={`w-full py-5 font-black uppercase tracking-wider rounded-xl flex items-center justify-center gap-3 transition-all ${white
                ? 'bg-white text-black shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:shadow-[0_0_40px_rgba(255,255,255,0.4)]'
                : 'bg-cinematic-neon-red text-white shadow-[0_0_30px_rgba(255,0,60,0.3)] hover:shadow-[0_0_50px_rgba(255,0,60,0.5)]'
                }`}>
            <Save className="w-5 h-5" />
            {loading ? (isRTL ? rawText('جاري الحفظ...') : rawText('Saving...')) : label}
        </motion.button>
    );
}

'use client';

/**
 * صفحة الإعدادات - لوحة تحكم HM CAR
 * ──────────────────────────────────────
 * هذه الصفحة مقسمة إلى 8 تبويبات:
 * 1. profile   - الملف الشخصي وكلمة المرور
 * 2. site      - هوية الموقع (الشعار والوصف)
 * 3. home      - محتوى الصفحة الرئيسية (Hero)
 * 4. social    - روابط التواصل الاجتماعي
 * 5. contact   - معلومات الاتصال
 * 6. currency  - إعدادات أسعار الصرف
 * 7. features  - قسم "لماذا تختارنا"
 *
 * المكونات المستخدمة (مجلد _components/):
 * - ProfileTab : تبويب الملف الشخصي
 * - SettingsTabs: باقي التبويبات (Social, Contact, Currency, Site, Home, Features)
 */

import { motion } from 'framer-motion';
import { Suspense, useState, useEffect } from 'react';
import { useSearchParams } from 'next/navigation';
import { ArrowLeft, User, Globe, Phone, DollarSign, Camera, LayoutDashboard, Shield } from 'lucide-react';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { useLanguage } from '@/lib/LanguageContext';
import { useAuth } from '@/lib/AuthContext';
import { api } from '@/lib/api';
import AdminPageShell from '@/components/AdminPageShell';

// ── المكونات المقسمة ──
import ProfileTab from './_components/ProfileTab';
import { SocialTab, ContactTab, CurrencyTab, SiteTab, HomeTab, FeaturesTab } from './_components/SettingsTabs';

// ── أنواع التبويبات ──
type TabID = 'profile' | 'security' | 'social' | 'contact' | 'currency' | 'site' | 'home' | 'features';

// ── أنواع البيانات ──
interface SocialLinks { whatsapp: string; instagram: string; twitter: string; facebook: string; youtube: string; tiktok: string; snapchat: string; telegram: string; linkedin: string; }
interface ContactInfo { phone: string; email: string; address: string; workingHours: string; }
interface CurrencySettings { usdToSar: number; usdToKrw: number; activeCurrency: string; partsMultiplier: number; auctionMultiplier: number; }
interface SiteInfo { siteName: string; siteDescription: string; logoUrl: string; faviconUrl: string; }
interface HomeContent { heroTitle: string; heroSubtitle: string; heroVideoUrl: string; }
interface Feature { icon: string; title: string; desc: string;[key: string]: string; }

export default function AdminSettings() {
    return (
        <Suspense fallback={<div className="min-h-screen bg-black text-white flex items-center justify-center font-black uppercase tracking-[0.5em] italic animate-pulse">Synchronizing Matrix...</div>}>
            <AdminSettingsContent />
        </Suspense>
    );
}

function AdminSettingsContent() {
    const { isRTL } = useLanguage();
    const { user, refreshUser } = useAuth();
    const searchParams = useSearchParams();
    const tabParam = searchParams.get('tab') as TabID;
    const [activeTab, setActiveTab] = useState<TabID>('profile');

    useEffect(() => {
        if (tabParam && ['profile', 'security', 'social', 'contact', 'currency', 'site', 'home', 'features'].includes(tabParam)) {
            setActiveTab(tabParam);
        }
    }, [tabParam]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });

    // ── بيانات الملف الشخصي ──
    const [profileData, setProfileData] = useState({
        name: '', username: '', email: '', phone: '',
        currentPassword: '', newPassword: '', confirmPassword: ''
    });

    // ── بيانات التبويبات الأخرى ──
    const [socialLinks, setSocialLinks] = useState<SocialLinks>({ whatsapp: '', instagram: '', twitter: '', facebook: '', youtube: '', tiktok: '', snapchat: '', telegram: '', linkedin: '' });
    const [contactInfo, setContactInfo] = useState<ContactInfo>({ phone: '', email: '', address: '', workingHours: '' });
    const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({ usdToSar: 3.75, usdToKrw: 1300, activeCurrency: 'SAR', partsMultiplier: 1.15, auctionMultiplier: 1.1 });
    const [siteInfo, setSiteInfo] = useState<SiteInfo>({ siteName: 'HM CAR', siteDescription: '', logoUrl: '', faviconUrl: '' });
    const [homeContent, setHomeContent] = useState<HomeContent>({ heroTitle: '', heroSubtitle: '', heroVideoUrl: '' });
    const [features, setFeatures] = useState<Feature[]>([]);

    // ── تحميل البيانات عند الفتح ──
    useEffect(() => {
        loadSettings();
        if (user) {
            setProfileData(prev => ({ ...prev, name: user.name || '', username: user.username || '', email: user.email || '', phone: user.phone || '' }));
        }
    }, [user]);

    // ── جلب إعدادات النظام من الـ API ──
    const loadSettings = async () => {
        try {
            const response = await api.settings.getAll();
            if (response.success) {
                setSocialLinks(response.data.socialLinks || {});
                setContactInfo(response.data.contactInfo || {});
                if (response.data.currencySettings) setCurrencySettings(response.data.currencySettings);
                if (response.data.siteInfo) setSiteInfo(response.data.siteInfo);
                if (response.data.homeContent) setHomeContent(response.data.homeContent);
                if (response.data.features) setFeatures(response.data.features);
            }
        } catch (error) { console.error('فشل تحميل الإعدادات:', error); }
    };

    // ── دوال الحفظ لكل قسم ──

    const handleSaveProfile = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            const response = await api.users.updateProfile({ name: profileData.name, username: profileData.username, email: profileData.email, phone: profileData.phone });
            if (response.success && response.data) {
                const currentUserStr = localStorage.getItem('hm_user');
                if (currentUserStr) {
                    localStorage.setItem('hm_user', JSON.stringify({ ...JSON.parse(currentUserStr), ...response.data }));
                    refreshUser();
                }
            }
            // تغيير كلمة المرور إن وُجدت
            if (profileData.newPassword) {
                if (profileData.newPassword !== profileData.confirmPassword) {
                    setMessage({ type: 'error', text: isRTL ? 'كلمات المرور غير متطابقة' : 'Passwords do not match' });
                    setLoading(false); return;
                }
                if (!profileData.currentPassword) {
                    if (!silent) setMessage({ type: 'error', text: isRTL ? 'يجب إدخال كلمة المرور الحالية' : 'Current password required' });
                    setLoading(false); return;
                }
                await api.auth.changePassword({ currentPassword: profileData.currentPassword, newPassword: profileData.newPassword });
                setProfileData(prev => ({ ...prev, currentPassword: '', newPassword: '', confirmPassword: '' }));
            }
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ البيانات بنجاح' : 'Profile saved successfully' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving profile' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveSocialLinks = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await api.settings.updateSocialLinks({ socialLinks: socialLinks as any });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ روابط التواصل' : 'Social links saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveContactInfo = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await api.settings.updateContactInfo({ contactInfo: contactInfo as any });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ معلومات الاتصال' : 'Contact info saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveCurrencySettings = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await api.settings.updateCurrencySettings({ currencySettings: currencySettings as any });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ إعدادات العملة' : 'Currency settings saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveSiteInfo = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await api.settings.updateSiteInfo({ siteInfo: siteInfo as any });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ معلومات الموقع' : 'Site info saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveHomeContent = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            await api.settings.updateHomeContent({ homeContent: homeContent as any });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ محتوى الصفحة الرئيسية' : 'Home content saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    const handleSaveFeatures = async (silent = false) => {
        if (!silent) { setLoading(true); setMessage({ type: '', text: '' }); }
        try {
            await api.settings.updateFeatures({ features });
            if (!silent) setMessage({ type: 'success', text: isRTL ? 'تم حفظ مميزات الموقع' : 'Features saved' });
        } catch (error) {
            if (!silent) setMessage({ type: 'error', text: (error as Error).message || 'Error saving' });
        } finally { if (!silent) setLoading(false); }
    };

    // ── رفع الشعار ──
    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setLoading(true);
        try {
            const formData = new FormData();
            formData.append('image', file);
            const res = await api.upload.image(formData);
            if (res.success) {
                setSiteInfo(prev => ({ ...prev, logoUrl: res.url }));
                setMessage({ type: 'success', text: isRTL ? 'تم رفع الشعار بنجاح' : 'Logo uploaded successfully' });
            }
        } catch (error) {
            setMessage({ type: 'error', text: (error as Error).message || 'Upload failed' });
        } finally { setLoading(false); }
    };

    // ── قائمة التبويبات ──
    const tabs = [
        { id: 'profile', label: isRTL ? 'الملف الشخصي' : 'Profile', icon: User },
        { id: 'site', label: isRTL ? 'هوية الموقع' : 'Site Identity', icon: Camera },
        { id: 'home', label: isRTL ? 'الصفحة الرئيسية' : 'Home Content', icon: LayoutDashboard },
        { id: 'social', label: isRTL ? 'التواصل الاجتماعي' : 'Social Links', icon: Globe },
        { id: 'contact', label: isRTL ? 'معلومات الاتصال' : 'Contact Info', icon: Phone },
        { id: 'currency', label: isRTL ? 'إعدادات العملة' : 'Currency', icon: DollarSign },
        { id: 'features', label: isRTL ? 'لماذا تختارنا' : 'Features', icon: Shield },
    ];
    return (
        <AdminPageShell
                title={isRTL ? 'الإعدادات' : 'SETTINGS'}
                titleEn="SYSTEM CONFIG"
                backHref="/admin/dashboard"
                isRTL={isRTL}
            >
                {/* رسالة النجاح / الخطأ */}
                {message.text && (
                    <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }}
                        className={cn('mb-8 p-4 rounded-xl border text-center',
                            message.type === 'success'
                                ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'
                                : 'bg-cinematic-neon-red/10 border-cinematic-neon-red/30 text-cinematic-neon-red')}>
                        <span className="text-sm font-bold">{message.text}</span>
                    </motion.div>
                )}

                {/* ─── شريط التبويبات ─── */}
                <div className="flex flex-wrap gap-2 mb-8 p-2 bg-white/5 rounded-2xl border border-white/5">
                        {tabs.map(tab => {
                            const Icon = tab.icon;
                            return (
                                <button key={tab.id}
                                    onClick={() => setActiveTab(tab.id as TabID)}
                                    className={cn(
                                        'flex-1 min-w-[80px] flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-xs uppercase tracking-wider transition-all',
                                        activeTab === tab.id
                                            ? 'bg-cinematic-neon-red text-white shadow-lg'
                                            : 'text-white/40 hover:text-white hover:bg-white/5'
                                    )}>
                                    <Icon className="w-3.5 h-3.5" />
                                    <span className="hidden sm:inline">{tab.label}</span>
                                </button>
                            );
                        })}
                    </div>

                    {/* ─── محتوى التبويب المحدد ─── */}

                    {activeTab === 'profile' && (
                        <ProfileTab
                            profileData={profileData}
                            loading={loading}
                            isRTL={isRTL}
                            onProfileChange={setProfileData}
                            onSave={handleSaveProfile}
                            onSilentSave={() => handleSaveProfile(true)}
                        />
                    )}

                    {activeTab === 'social' && (
                        <SocialTab
                            socialLinks={socialLinks}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveSocialLinks}
                            onLinkChange={setSocialLinks}
                            setMessage={setMessage}
                        />
                    )}

                    {activeTab === 'contact' && (
                        <ContactTab
                            contactInfo={contactInfo}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveContactInfo}
                            onSilentSave={() => handleSaveContactInfo(true)}
                            onContactChange={setContactInfo}
                        />
                    )}

                    {activeTab === 'currency' && (
                        <CurrencyTab
                            currencySettings={currencySettings}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveCurrencySettings}
                            onSilentSave={() => handleSaveCurrencySettings(true)}
                            onCurrencyChange={setCurrencySettings}
                        />
                    )}

                    {activeTab === 'site' && (
                        <SiteTab
                            siteInfo={siteInfo}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveSiteInfo}
                            onSilentSave={() => handleSaveSiteInfo(true)}
                            onSiteChange={setSiteInfo}
                            onLogoUpload={handleLogoUpload}
                        />
                    )}

                    {activeTab === 'home' && (
                        <HomeTab
                            homeContent={homeContent}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveHomeContent}
                            onSilentSave={() => handleSaveHomeContent(true)}
                            onHomeChange={setHomeContent}
                        />
                    )}

                    {activeTab === 'features' && (
                        <FeaturesTab
                            features={features}
                            loading={loading}
                            isRTL={isRTL}
                            onSave={handleSaveFeatures}
                            onFeaturesChange={setFeatures}
                        />
                    )}

            </AdminPageShell>
        );
    }

'use client';

import { useEffect, useState } from "react";
import { MessageCircle, Save, Trash2, CheckCircle2, SquarePen, ArrowLeft } from "lucide-react";
import { motion } from "framer-motion";
import Link from "next/link";
import { useLanguage } from "@/lib/LanguageContext";
import { cn } from "@/lib/utils";
import { getSocialIcon } from "@/lib/socialIcons";
import { api } from "@/lib/api";

// Social config uses simple runtime-shape

function AdminSocialSettings() {
  const { t, isRTL } = useLanguage();
  const [config, setConfig] = useState({ whatsapp: "", links: [] as Array<{ platform: string; url: string }> });
  const [saved, setSaved] = useState(false);
  const platforms = [
    { key: 'whatsapp', label: 'WhatsApp' },
    { key: 'instagram', label: 'Instagram' },
    { key: 'twitter', label: 'X' },
    { key: 'facebook', label: 'Facebook' },
    { key: 'youtube', label: 'YouTube' },
    { key: 'tiktok', label: 'TikTok' },
    { key: 'snapchat', label: 'Snapchat' },
    { key: 'telegram', label: 'Telegram' },
    { key: 'linkedin', label: 'LinkedIn' },
  ];

  useEffect(() => {
    const fetchLinks = async () => {
      try {
        const response = await api.settings.getAll();
        if (response.success && response.data.socialLinks) {
          const sl = response.data.socialLinks;
          const linksArray = Object.entries(sl)
            .filter(([k, v]) => k !== 'whatsapp' && v)
            .map(([k, v]) => ({ platform: k, url: v as string }));

          setConfig({
            whatsapp: sl.whatsapp || "",
            links: linksArray
          });
        }
      } catch (err) {
        console.error("Failed to fetch social links", err);
      }
    };
    fetchLinks();
  }, []);

  const handleSave = async () => {
    try {
      // Convert links array back to object for schema
      const socialLinks: Record<string, string> = { whatsapp: config.whatsapp };
      config.links.forEach(l => {
        if (l.platform && l.url) {
          socialLinks[l.platform.toLowerCase()] = l.url;
        }
      });

      const response = await api.settings.updateSocialLinks({ socialLinks });
      if (response.success) {
        setSaved(true);
        setTimeout(() => setSaved(false), 2000);
      }
    } catch (err) {
      console.error("Failed to save social links", err);
    }
  };

  const addLink = () => {
    setConfig(prev => ({ ...prev, links: [...prev.links, { platform: "", url: "" }] }));
  };

  const setPlatformUrl = (platformKey: string, url: string) => {
    const key = platformKey.toLowerCase();
    setConfig(prev => {
      const next = [...prev.links];
      const idx = next.findIndex(l => (l.platform || '').toLowerCase() === key);
      if (idx >= 0) next[idx] = { ...next[idx], platform: key, url };
      else next.push({ platform: key, url });
      return { ...prev, links: next };
    });
  };

  const removePlatformUrl = (platformKey: string) => {
    const key = platformKey.toLowerCase();
    setConfig(prev => ({ ...prev, links: prev.links.filter(l => (l.platform || '').toLowerCase() !== key) }));
  };

  const removeLink = (idx: number) => {
    setConfig(prev => ({ ...prev, links: prev.links.filter((_, i) => i !== idx) }));
  };

  return (
    <div className={cn("min-h-screen bg-black text-white px-6 sm:px-12 lg:px-20 py-24")}>
      <div className="max-w-4xl mx-auto space-y-10">

        {/* Navigation HUD */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
            <div className="flex items-center gap-8">
                <Link href="/admin/dashboard">
                    <motion.button
                        whileHover={{ scale: 1.1, x: isRTL ? 5 : -5 }}
                        whileTap={{ scale: 0.9 }}
                        className="p-5 rounded-2xl bg-white/5 border border-white/10 hover:border-cinematic-neon-blue/40 hover:bg-cinematic-neon-blue/10 transition-all group shadow-2xl"
                    >
                        <ArrowLeft className={cn(
                            "w-7 h-7 text-white/40 group-hover:text-cinematic-neon-blue transition-colors",
                            isRTL && "rotate-180"
                        )} />
                    </motion.button>
                </Link>

                <div>
                    <div className="flex items-center gap-4 mb-2">
                        <div className="h-[2px] w-12 bg-cinematic-neon-blue shadow-[0_0_15px_rgba(0,150,255,1)]" />
                        <span className="text-[10px] font-black uppercase tracking-[0.5em] text-cinematic-neon-blue italic">HQ Control Settings</span>
                    </div>
                    <h1 className="text-3xl md:text-5xl font-black uppercase tracking-[0.4em]">
                        {t('socialSettings')}
                    </h1>
                </div>
            </div>
        </div>

        <div className="glass-card p-8 bg-white/[0.02] border border-white/10 rounded-2xl space-y-6">
          <label className="block text-[10px] font-black uppercase tracking-[0.4em] text-white/60 mb-2">
            {t('whatsappNumber')}
          </label>
          <input
            type="tel"
            placeholder={isRTL ? "مثال: +9665xxxxxxxx" : "+9665xxxxxxxx"}
            value={config.whatsapp || ""}
            onChange={(e) => setConfig(prev => ({ ...prev, whatsapp: e.target.value }))}
            className={cn("w-full bg-white/[0.04] border border-white/10 rounded-xl px-5 py-4 text-sm text-white focus:outline-none focus:border-cinematic-neon-blue/40", isRTL ? "text-right" : "text-left")}
          />
        </div>

        <div className="glass-card p-8 bg-white/[0.02] border border-white/10 rounded-2xl">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-[11px] font-black uppercase tracking-[0.6em]">{t('socialLinks')}</h2>
            <button
              onClick={addLink}
              className="px-4 py-2 rounded-xl bg-cinematic-neon-blue/20 text-cinematic-neon-blue border border-cinematic-neon-blue/30 text-[10px] font-black uppercase tracking-[0.3em]"
            >
              {t('addLink')}
            </button>
          </div>

          <div className="space-y-4">
            {platforms.map((p) => {
              const Icon = getSocialIcon(p.key) as React.ComponentType<{ className?: string }>;
              const val = (config.links.find(l => (l.platform || '').toLowerCase() === p.key) || {}).url || "";
              return (
                <div key={p.key} className="flex items-center gap-4 bg-white/[0.02] border border-white/10 rounded-xl p-4">
                  <div className="w-12 h-12 rounded-full bg-black/40 border border-white/10 flex items-center justify-center">
                    {Icon ? <Icon className="w-6 h-6 text-white/80" /> : <MessageCircle className="w-6 h-6 text-white/60" />}
                  </div>
                  <div className="flex-1">
                    <div className="text-sm font-black">{p.label}</div>
                    <input
                      type="url"
                      placeholder={isRTL ? "https://..." : "https://..."}
                      value={val}
                      onChange={(e) => setPlatformUrl(p.key, e.target.value)}
                      className={cn("mt-2 w-full bg-white/[0.04] border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-cinematic-neon-blue/40", isRTL ? "text-right" : "text-left")}
                    />
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      className="px-3 py-2 rounded-lg bg-white/5 border border-white/10 text-white/60 hover:text-white hover:bg-white/10 transition-all flex items-center gap-1 text-[9px] font-black uppercase"
                    >
                      <SquarePen className="w-3 h-3" />
                      {isRTL ? 'تعديل' : 'EDIT'}
                    </button>
                    <button
                      onClick={() => removePlatformUrl(p.key)}
                      className="px-3 py-2 rounded-lg bg-cinematic-neon-red/10 text-cinematic-neon-red border border-cinematic-neon-red/20 hover:bg-cinematic-neon-red hover:text-white transition-all flex items-center gap-1 text-[9px] font-black uppercase"
                    >
                      <Trash2 className="w-3 h-3" />
                      {isRTL ? 'حذف' : 'REMOVE'}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button
            onClick={handleSave}
            className="flex items-center gap-3 px-6 py-3 rounded-xl bg-white text-black font-black uppercase tracking-[0.3em] hover:bg-cinematic-neon-blue hover:text-white transition-all"
          >
            <Save className="w-5 h-5" /> {t('saveChanges')}
          </button>
          {saved && (
            <div className="flex items-center gap-2 text-cinematic-neon-blue">
              <CheckCircle2 className="w-5 h-5" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em]">OK</span>
            </div>
          )}
        </div>

        <div className="text-white/40 text-sm">
          <Link href="/social" className="underline hover:text-white">
            {t('publicSocialPage')}
          </Link>
        </div>
      </div>
    </div>
  )
}

export default AdminSocialSettings;

'use client';

/**
 * نوافذ إدارة المستخدمين - UserModals
 * ────────────────────────────────────
 * يحتوي على نافذتين منبثقتين:
 * 1. AddUserModal   - إضافة مسؤول/مدير/عميل جديد
 * 2. UserDetailModal - عرض وتعديل تفاصيل مستخدم موجود
 *
 * ✅ تم إصلاح:
 * - معالجة _id من الـ backend بشكل صحيح
 * - عرض رسائل الخطأ التفصيلية
 * - التحقق من صحة البيانات قبل الإرسال
 * - دعم تغيير كلمة المرور عند التعديل
 */

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
    Plus, X, Eye, EyeOff, ChevronDown, Shield,
    Trash2, Save, AlertCircle, CheckCircle2, User, Mail, Phone
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { api } from '@/lib/api';
import PermissionsGrid from './PermissionsGrid';

// ─────────────────────────────────
// أنواع البيانات
// ─────────────────────────────────
interface Device {
    deviceId: string; browser: string; os: string;
    ip: string; lastUsedAt: string; isActive: boolean;
}

export interface User {
    id: string; name: string; email?: string; username?: string; phone?: string;
    role: string; isActive: boolean; createdAt: string;
    boundDevices?: Device[]; isDeviceLocked?: boolean; permissions?: string[];
}

// ─────────────────────────────────
// مكوّن مساعد: حقل إدخال مع أيقونة
// ─────────────────────────────────
function InputField({ label, type = 'text', value, onChange, placeholder, icon: Icon, required = false, hint }: {
    label: string; type?: string; value: string; onChange: (v: string) => void;
    placeholder?: string; icon?: React.ComponentType<{ className?: string }>; required?: boolean; hint?: string;
}) {
    return (
        <div>
            <label className="text-[9px] font-black text-white/40 uppercase tracking-widest block mb-1.5">
                {label} {required && <span className="text-red-400">*</span>}
            </label>
            <div className="relative">
                {Icon && <Icon className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-white/20" />}
                <input
                    type={type} value={value} onChange={e => onChange(e.target.value)}
                    placeholder={placeholder}
                    className={cn(
                        'w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white text-sm',
                        'placeholder:text-white/20 focus:border-blue-500/50 outline-none transition-all',
                        Icon && 'pr-9'
                    )}
                />
            </div>
            {hint && <p className="text-[9px] text-white/25 mt-1">{hint}</p>}
        </div>
    );
}

// ═══════════════════════════════════════════════════════
// نافذة إضافة مستخدم جديد (مسؤول / مدير / عميل)
// ═══════════════════════════════════════════════════════
export function AddUserModal({ onClose, onAdd, isRTL }: {
    onClose: () => void;
    onAdd: (u: User) => void;
    isRTL: boolean;
}) {
    // ── بيانات النموذج ──
    const [formData, setFormData] = useState({
        name: '', email: '', username: '', phone: '',
        password: '', confirmPassword: '',
        role: 'admin', permissions: [] as string[]
    });
    const [showPass, setShowPass] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    const update = (field: string, value: string) =>
        setFormData(prev => ({ ...prev, [field]: value }));

    const isAdminRole = ['admin', 'manager', 'super_admin'].includes(formData.role);

    // ── التحقق من صحة البيانات ──
    const validate = (): string => {
        if (!formData.name.trim()) return 'الاسم الكامل مطلوب';
        if (formData.name.trim().length < 3) return 'الاسم يجب أن يكون 3 أحرف على الأقل';
        if (!formData.password) return 'كلمة المرور مطلوبة';
        if (formData.password.length < 6) return 'كلمة المرور يجب أن تكون 6 أحرف على الأقل';
        if (formData.password !== formData.confirmPassword) return 'كلمات المرور غير متطابقة';

        // للمسؤولين: البريد إلزامي لتسجيل الدخول لاحقاً
        if (isAdminRole && !formData.email.trim()) {
            return 'البريد الإلكتروني إلزامي لحسابات المسؤولين (يُستخدم لتسجيل الدخول)';
        }

        // للعملاء: يجب وجود طريقة تعريف واحدة على الأقل
        if (!isAdminRole && !formData.email.trim() && !formData.phone.trim() && !formData.username.trim()) {
            return 'يجب إدخال البريد الإلكتروني أو رقم الهاتف أو اسم المستخدم';
        }

        if (isAdminRole && formData.permissions.length === 0) {
            return 'يجب تحديد صلاحية واحدة على الأقل للمسؤولين';
        }

        return '';
    };

    // ── إرسال النموذج ──
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        const validationError = validate();
        if (validationError) { setError(validationError); return; }

        try {
            setLoading(true);

            // بناء payload - فقط الحقول غير الفارغة
            const payload: Record<string, unknown> = {
                name: formData.name.trim(),
                password: formData.password,
                role: formData.role,
                status: 'active',
                createdVia: 'admin-created',
                // الصلاحيات فقط للمسؤولين
                permissions: isAdminRole ? formData.permissions : [],
            };

            if (formData.email.trim()) payload.email = formData.email.trim().toLowerCase();
            if (formData.phone.trim()) payload.phone = formData.phone.trim();
            if (formData.username.trim()) payload.username = formData.username.trim();

            const res = await api.users.create(payload);

            if (res.success) {
                setSuccess(`✅ تم إنشاء حساب "${formData.name}" بنجاح`);
                // تحويل البيانات المُرجعة للنوع User الصحيح
                const newUser: User = {
                    id: res.data._id || res.data.id || '',
                    name: res.data.name,
                    email: res.data.email,
                    username: res.data.username,
                    phone: res.data.phone,
                    role: res.data.role,
                    isActive: res.data.status === 'active',
                    createdAt: res.data.createdAt || new Date().toISOString(),
                    permissions: res.data.permissions || [],
                };
                setTimeout(() => onAdd(newUser), 800);
            } else {
                setError(res.message || 'فشل إنشاء الحساب - تحقق من البيانات');
            }
        } catch (err: unknown) {
            const msg = err instanceof Error ? err.message : 'فشل الاتصال بالخادم';
            setError(msg);
        } finally { setLoading(false); }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-3 sm:p-4 bg-black/90 backdrop-blur-md"
            dir={isRTL ? 'rtl' : 'ltr'}>
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                className="bg-[#080808] border border-white/10 rounded-3xl w-full max-w-xl max-h-[92vh] flex flex-col overflow-hidden shadow-2xl">

                {/* ── رأس النافذة ── */}
                <div className="flex items-center justify-between p-5 border-b border-white/8 flex-shrink-0">
                    <h2 className="text-base font-black uppercase text-white flex items-center gap-2">
                        <Plus className="w-4 h-4 text-blue-400" />
                        إضافة مستخدم جديد
                    </h2>
                    <button onClick={onClose} title="إغلاق"
                        className="w-8 h-8 bg-white/5 border border-white/10 rounded-xl flex items-center justify-center hover:bg-white/10 transition-all">
                        <X className="w-4 h-4 text-white/50" />
                    </button>
                </div>

                {/* ── محتوى النموذج ── */}
                <div className="overflow-y-auto flex-1 p-5">
                    <form onSubmit={handleSubmit} className="space-y-4">

                        {/* رسالة خطأ */}
                        {error && (
                            <div className="flex items-start gap-2 p-3.5 bg-red-500/10 border border-red-500/30 rounded-xl text-red-400 text-xs font-bold">
                                <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
                                <span>{error}</span>
                            </div>
                        )}
                        {/* رسالة نجاح */}
                        {success && (
                            <div className="flex items-center gap-2 p-3.5 bg-green-500/10 border border-green-500/30 rounded-xl text-green-400 text-xs font-bold">
                                <CheckCircle2 className="w-4 h-4 shrink-0" />
                                <span>{success}</span>
                            </div>
                        )}

                        {/* ── المعلومات الأساسية ── */}
                        <div>
                            <h3 className="text-[9px] font-black uppercase tracking-widest text-white/30 border-b border-white/5 pb-2 mb-3">
                                المعلومات الأساسية
                            </h3>
                            <div className="space-y-3">
                                <InputField label="الاسم الكامل" value={formData.name} icon={User}
                                    onChange={v => update('name', v)} placeholder="مثال: محمد العمري" required />

                                <InputField label="البريد الإلكتروني" type="email" value={formData.email} icon={Mail}
                                    onChange={v => update('email', v)} placeholder="admin@example.com"
                                    required={isAdminRole}
                                    hint={isAdminRole ? '⚠️ إلزامي للمسؤولين - يُستخدم لتسجيل الدخول' : 'اختياري للعملاء'} />

                                {!isAdminRole && (
                                    <>
                                        <InputField label="رقم الهاتف" type="tel" value={formData.phone} icon={Phone}
                                            onChange={v => update('phone', v)} placeholder="+966XXXXXXXXX"
                                            hint="بديل للبريد الإلكتروني" />
                                        <InputField label="اسم المستخدم" value={formData.username} icon={User}
                                            onChange={v => update('username', v)} placeholder="username123"
                                            hint="بديل للبريد الإلكتروني" />
                                    </>
                                )}
                            </div>
                        </div>

                        {/* ── كلمة المرور ── */}
                        <div>
                            <h3 className="text-[9px] font-black uppercase tracking-widest text-white/30 border-b border-white/5 pb-2 mb-3">
                                كلمة المرور
                            </h3>
                            <div className="space-y-3">
                                <div>
                                    <label className="text-[9px] font-black text-white/40 uppercase tracking-widest block mb-1.5">
                                        كلمة المرور <span className="text-red-400">*</span>
                                    </label>
                                    <div className="relative">
                                        <input required type={showPass ? 'text' : 'password'}
                                            placeholder="6 أحرف على الأقل" minLength={6}
                                            className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white placeholder:text-white/20 focus:border-blue-500/50 outline-none transition-all pr-10"
                                            value={formData.password}
                                            onChange={e => update('password', e.target.value)} />
                                        <button type="button" onClick={() => setShowPass(!showPass)}
                                            className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40 hover:text-white transition-colors">
                                            {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                        </button>
                                    </div>
                                </div>
                                <div>
                                    <label className="text-[9px] font-black text-white/40 uppercase tracking-widest block mb-1.5">
                                        تأكيد كلمة المرور <span className="text-red-400">*</span>
                                    </label>
                                    <input type={showPass ? 'text' : 'password'}
                                        placeholder="أعد كتابة كلمة المرور"
                                        className={cn(
                                            'w-full bg-white/5 border p-3 rounded-xl text-white placeholder:text-white/20 focus:border-blue-500/50 outline-none transition-all',
                                            formData.confirmPassword && formData.password !== formData.confirmPassword
                                                ? 'border-red-500/50' : 'border-white/10'
                                        )}
                                        value={formData.confirmPassword}
                                        onChange={e => update('confirmPassword', e.target.value)} />
                                    {formData.confirmPassword && formData.password !== formData.confirmPassword && (
                                        <p className="text-[9px] text-red-400 mt-1">⚠️ كلمات المرور غير متطابقة</p>
                                    )}
                                </div>
                            </div>
                        </div>

                        {/* ── نوع الحساب ── */}
                        <div>
                            <label className="text-[9px] font-black text-white/40 uppercase tracking-widest block mb-1.5">
                                نوع الحساب
                            </label>
                            <div className="relative">
                                <select value={formData.role} title="نوع الحساب"
                                    onChange={e => update('role', e.target.value)}
                                    className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white focus:border-blue-500/50 outline-none transition-all appearance-none cursor-pointer">
                                    <option value="admin" className="bg-zinc-900">🛡️ مسؤول - Admin (صلاحيات كاملة)</option>
                                    <option value="manager" className="bg-zinc-900">👔 مدير - Manager (صلاحيات محددة)</option>
                                    <option value="buyer" className="bg-zinc-900">👤 عميل - Buyer</option>
                                </select>
                                <ChevronDown className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40 pointer-events-none" />
                            </div>
                            {isAdminRole && (
                                <p className="text-[9px] text-blue-400/70 mt-1.5">
                                    💡 الأدمن يدخل بالبريد الإلكتروني وكلمة المرور عبر صفحة تسجيل دخول الأدمن
                                </p>
                            )}
                        </div>

                        {/* ── الصلاحيات (للمسؤولين والمدراء فقط) ── */}
                        {isAdminRole && (
                            <div className="space-y-3 border-t border-white/8 pt-4">
                                <div className="flex items-center gap-2">
                                    <Shield className="w-4 h-4 text-blue-400" />
                                    <h3 className="text-[9px] font-black uppercase tracking-widest text-blue-400">
                                        صلاحيات النظام {formData.permissions.length > 0 && `(${formData.permissions.length} محددة)`}
                                    </h3>
                                </div>
                                <PermissionsGrid
                                    permissions={formData.permissions}
                                    onChange={p => setFormData(prev => ({ ...prev, permissions: p }))}
                                />
                            </div>
                        )}

                        {/* ── أزرار الإجراءات ── */}
                        <div className="flex gap-3 pt-2">
                            <button type="submit" disabled={loading || !!success}
                                className="flex-1 py-3.5 bg-blue-500 text-white font-black uppercase tracking-wider rounded-xl hover:bg-blue-400 transition-all disabled:opacity-50 text-sm shadow-[0_0_20px_rgba(59,130,246,0.3)] flex items-center justify-center gap-2">
                                {loading ? (
                                    <><span className="animate-spin inline-block w-4 h-4 border-2 border-white/30 border-t-white rounded-full" /> جاري الإنشاء...</>
                                ) : '✅ إنشاء الحساب'}
                            </button>
                            <button type="button" onClick={onClose}
                                className="flex-1 py-3.5 border border-white/10 text-white/50 font-black uppercase tracking-wider rounded-xl hover:bg-white/5 transition-all text-sm">
                                إلغاء
                            </button>
                        </div>
                    </form>
                </div>
            </motion.div>
        </div>
    );
}

// ═══════════════════════════════════════════════════════
// نافذة تفاصيل وتعديل المستخدم
// ═══════════════════════════════════════════════════════
export function UserDetailModal({ user, onClose, onUpdate, onDelete, isRTL }: {
    user: User;
    onClose: () => void;
    onUpdate: (u: User) => void;
    onDelete: (id: string) => void;
    isRTL: boolean;
}) {
    // بيانات التعديل - نبدأ ببيانات المستخدم الحالية
    const [editData, setEditData] = useState({
        name: user.name,
        email: user.email || '',
        username: user.username || '',
        phone: user.phone || '',
        password: '',
        role: user.role,
        isActive: user.isActive,
        isBanned: (user as any).isBanned ?? false
    });
    const [permissions, setPermissions] = useState<string[]>(user.permissions || []);
    const [devices, setDevices] = useState<Device[]>(user.boundDevices || []);
    const [isDeviceLocked, setIsDeviceLocked] = useState(user.isDeviceLocked ?? true);
    const [loading, setLoading] = useState(false);
    const [showPass, setShowPass] = useState(false);
    const [saveError, setSaveError] = useState('');
    const [saveSuccess, setSaveSuccess] = useState('');
    const [activeTab, setActiveTab] = useState<'info' | 'perms' | 'devices'>('info');

    const isAdminRole = ['admin', 'manager', 'super_admin'].includes(editData.role);

    // ── حفظ التغييرات ──
    const handleSave = async () => {
        try {
            setLoading(true);
            setSaveError('');
            setSaveSuccess('');

            if (!editData.name.trim()) { setSaveError('الاسم مطلوب'); setLoading(false); return; }

            // بناء payload - نُرسل فقط الحقول المطلوبة
            const payload: Record<string, unknown> = {
                name: editData.name.trim(),
                role: editData.role,
                status: editData.isActive ? 'active' : 'suspended',
                // الصلاحيات فقط للمسؤولين والمدراء
                permissions: isAdminRole ? permissions : [],
                boundDevices: devices,
                isDeviceLocked,
            };

            // أضف الحقول فقط إذا لم تكن فارغة (لتجنب تعارض Unique indexes)
            if (editData.email.trim()) payload.email = editData.email.trim().toLowerCase();
            if (editData.username.trim()) payload.username = editData.username.trim();
            if (editData.phone.trim()) payload.phone = editData.phone.trim();
            // كلمة المرور الجديدة - اختيارية
            if (editData.password.trim() && editData.password.length >= 6) {
                payload.password = editData.password;
            } else if (editData.password.trim() && editData.password.length < 6) {
                setSaveError('كلمة المرور الجديدة يجب أن تكون 6 أحرف على الأقل');
                setLoading(false);
                return;
            }

            const res = await api.users.update(user.id, payload);

            // Handle banning separately if it changed
            if (editData.isBanned !== (user as any).isBanned) {
                await api.users.ban(user.id, editData.isBanned).catch(err => {
                    console.error("Ban update failed", err);
                });
            }

            if (res.success) {
                setSaveSuccess('✅ تم حفظ التغييرات بنجاح');
                // دمج البيانات المحدثة مع بيانات المستخدم الأصلية
                const updatedUser: User = {
                    ...user,
                    name: editData.name,
                    email: editData.email || user.email,
                    username: editData.username || user.username,
                    phone: editData.phone || user.phone,
                    role: editData.role,
                    isActive: editData.isActive,
                    isBanned: editData.isBanned,
                    permissions: isAdminRole ? permissions : [],
                    boundDevices: devices,
                    isDeviceLocked,
                } as User;
                setTimeout(() => onUpdate(updatedUser), 800);
            } else {
                setSaveError(res.message || 'فشل تحديث البيانات');
            }
        } catch (err: unknown) {
            setSaveError(err instanceof Error ? err.message : 'فشل الاتصال بالخادم');
        } finally { setLoading(false); }
    };

    // ── حذف المستخدم ──
    const handleDelete = async () => {
        const confirmed = window.confirm(
            `⚠️ تأكيد الحذف\n\nهل تريد حذف حساب "${user.name}"؟\nلا يمكن التراجع عن هذا الإجراء.`
        );
        if (!confirmed) return;

        try {
            setLoading(true);
            await api.users.delete(user.id);
            onDelete(user.id);
        } catch (err: unknown) {
            const msg = err instanceof Error ? err.message : 'فشل حذف المستخدم';
            setSaveError(msg);
            setLoading(false);
        }
    };

    // قائمة التبويبات حسب دور المستخدم
    const tabs = [
        { id: 'info', label: 'المعلومات' },
        ...(isAdminRole ? [{ id: 'perms', label: `الصلاحيات (${permissions.length})` }] : []),
        ...(editData.role === 'buyer' ? [{ id: 'devices', label: `الأجهزة (${devices.length})` }] : []),
    ];

    return (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/90 backdrop-blur-md"
            dir={isRTL ? 'rtl' : 'ltr'}>
            <motion.div initial={{ y: 60, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
                className="bg-[#080808] border border-white/10 rounded-t-3xl sm:rounded-3xl w-full sm:max-w-2xl max-h-[95vh] flex flex-col overflow-hidden shadow-2xl">

                {/* ── رأس النافذة ── */}
                <div className="flex items-center justify-between p-5 border-b border-white/8 flex-shrink-0">
                    <div>
                        <div className="text-base font-black text-white flex items-center gap-2">
                            <span>{user.name}</span>
                            <span className={cn('text-[9px] px-2 py-0.5 rounded-full border font-black uppercase',
                                isAdminRole
                                    ? 'bg-red-500/10 border-red-500/30 text-red-400'
                                    : 'bg-blue-500/10 border-blue-500/30 text-blue-400'
                            )}>
                                {editData.role}
                            </span>
                        </div>
                        <div className="text-[10px] text-white/30 mt-0.5">
                            {user.email || user.username || user.phone || 'لا يوجد معرّف'}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        {/* زر حذف المستخدم */}
                        <button onClick={handleDelete} disabled={loading} title="حذف المستخدم"
                            className="w-8 h-8 bg-red-500/10 border border-red-500/20 text-red-400 rounded-xl flex items-center justify-center hover:bg-red-500/20 transition-all disabled:opacity-40">
                            <Trash2 className="w-3.5 h-3.5" />
                        </button>
                        {/* زر إغلاق النافذة */}
                        <button onClick={onClose} title="إغلاق"
                            className="w-8 h-8 bg-white/5 border border-white/10 rounded-xl flex items-center justify-center hover:bg-white/10 transition-all">
                            <X className="w-4 h-4 text-white/50" />
                        </button>
                    </div>
                </div>

                {/* ── شريط التبويبات ── */}
                <div className="flex border-b border-white/8 flex-shrink-0">
                    {tabs.map(tab => (
                        <button key={tab.id} onClick={() => setActiveTab(tab.id as typeof activeTab)}
                            className={cn('flex-1 py-3 text-[10px] font-black uppercase tracking-wider transition-all',
                                activeTab === tab.id
                                    ? 'text-blue-400 border-b-2 border-blue-500'
                                    : 'text-white/30 hover:text-white/60')}>
                            {tab.label}
                        </button>
                    ))}
                </div>

                {/* ── محتوى التبويبات ── */}
                <div className="overflow-y-auto flex-1 p-5">

                    {/* ─ تبويب: المعلومات الأساسية ─ */}
                    {activeTab === 'info' && (
                        <div className="space-y-4">
                            {/* حقول البيانات */}
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <InputField label="الاسم الكامل" value={editData.name}
                                    onChange={v => setEditData(p => ({ ...p, name: v }))}
                                    placeholder="الاسم الكامل" icon={User} required />

                                <InputField label="البريد الإلكتروني" type="email" value={editData.email}
                                    onChange={v => setEditData(p => ({ ...p, email: v }))}
                                    placeholder="email@..." icon={Mail}
                                    hint={isAdminRole ? 'يُستخدم لتسجيل الدخول' : ''} />

                                <InputField label="اسم المستخدم" value={editData.username}
                                    onChange={v => setEditData(p => ({ ...p, username: v }))}
                                    placeholder="username" icon={User} />

                                <InputField label="رقم الهاتف" type="tel" value={editData.phone}
                                    onChange={v => setEditData(p => ({ ...p, phone: v }))}
                                    placeholder="+966..." icon={Phone} />
                            </div>

                            {/* الدور */}
                            <div>
                                <label className="text-[9px] font-black text-white/40 uppercase tracking-widest block mb-1.5">الدور</label>
                                <div className="relative">
                                    <select value={editData.role} title="الدور"
                                        onChange={e => setEditData(p => ({ ...p, role: e.target.value }))}
                                        className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white focus:border-blue-500/40 outline-none transition-all appearance-none cursor-pointer">
                                        <option value="super_admin" className="bg-zinc-900">👑 مسؤول عام - Super Admin</option>
                                        <option value="admin" className="bg-zinc-900">🛡️ مسؤول - Admin</option>
                                        <option value="manager" className="bg-zinc-900">👔 مدير - Manager</option>
                                        <option value="buyer" className="bg-zinc-900">👤 عميل - Buyer</option>
                                        <option value="seller" className="bg-zinc-900">💼 بائع - Seller</option>
                                    </select>
                                    <ChevronDown className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40 pointer-events-none" />
                                </div>
                            </div>

                            {/* كلمة مرور جديدة (اختياري) */}
                            <div>
                                <label className="text-[9px] font-black text-white/30 uppercase tracking-widest block mb-1.5">
                                    كلمة مرور جديدة <span className="text-white/20 normal-case">(اتركها فارغة للإبقاء على الحالية)</span>
                                </label>
                                <div className="relative">
                                    <input type={showPass ? 'text' : 'password'} placeholder="••••••"
                                        className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white placeholder:text-white/20 focus:border-blue-500/40 outline-none transition-all pr-10"
                                        value={editData.password}
                                        onChange={e => setEditData(p => ({ ...p, password: e.target.value }))} />
                                    <button type="button" onClick={() => setShowPass(!showPass)}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 hover:text-white transition-colors">
                                        {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                    </button>
                                </div>
                                {editData.password && editData.password.length < 6 && (
                                    <p className="text-[9px] text-red-400 mt-1">⚠️ كلمة المرور يجب أن تكون 6 أحرف على الأقل</p>
                                )}
                            </div>

                            {/* مفتاح تشغيل/إيقاف الحساب */}
                            <div className="flex items-center justify-between bg-white/[0.02] border border-white/8 p-4 rounded-xl">
                                <div>
                                    <div className="text-sm font-bold text-white">حالة الحساب</div>
                                    <div className={cn('text-[10px] mt-0.5', editData.isActive ? 'text-green-400' : 'text-red-400')}>
                                        {editData.isActive ? '● نشط ومفعّل' : '● معطّل / موقوف'}
                                    </div>
                                </div>
                                <div onClick={() => setEditData(p => ({ ...p, isActive: !p.isActive }))}
                                    className={cn('w-12 h-6 rounded-full relative cursor-pointer transition-all duration-300',
                                        editData.isActive ? 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.4)]' : 'bg-white/10')}>
                                    <div className={cn('absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow',
                                        editData.isActive ? 'right-1' : 'right-7')} />
                                </div>
                            </div>

                            {/* Ban Status */}
                            <div className="flex items-center justify-between bg-white/[0.02] border border-red-500/20 p-4 rounded-xl">
                                <div>
                                    <div className="text-sm font-bold text-red-400">{isRTL ? "حظر شامل للحساب" : "Global Account Ban"}</div>
                                    <div className="text-[10px] text-white/30 mt-0.5">
                                        {editData.isBanned ? (isRTL ? "🚫 المستخدم محظور تماماً من النظام" : "🚫 User is completely banned from system") : (isRTL ? "✅ المستخدم غير محظور" : "✅ User is not banned")}
                                    </div>
                                </div>
                                <div onClick={() => setEditData(p => ({ ...p, isBanned: !p.isBanned }))}
                                    className={cn('w-12 h-6 rounded-full relative cursor-pointer transition-all duration-300',
                                        editData.isBanned ? 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]' : 'bg-white/10')}>
                                    <div className={cn('absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow',
                                        editData.isBanned ? 'right-1' : 'right-7')} />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* ─ تبويب: الصلاحيات ─ */}
                    {activeTab === 'perms' && (
                        <div>
                            <p className="text-[9px] text-white/30 mb-4">
                                صلاحيات هذا المستخدم في النظام. تنطبق فقط على المسؤولين والمدراء.
                            </p>
                            <PermissionsGrid permissions={permissions} onChange={setPermissions} />
                        </div>
                    )}

                    {/* ─ تبويب: الأجهزة المرتبطة ─ */}
                    {activeTab === 'devices' && (
                        <div className="space-y-4">
                            {/* مفتاح قفل الأجهزة */}
                            <div className="flex items-center justify-between bg-white/[0.02] border border-white/8 p-4 rounded-xl">
                                <div>
                                    <div className="text-sm font-bold text-white">قفل الحساب على الأجهزة المرتبطة</div>
                                    <div className="text-[10px] text-white/30 mt-0.5">
                                        {isDeviceLocked ? 'مُفعّل - لا يمكن الدخول من جهاز جديد' : 'معطّل - يمكن الدخول من أي جهاز'}
                                    </div>
                                </div>
                                <div onClick={() => setIsDeviceLocked(!isDeviceLocked)}
                                    className={cn('w-12 h-6 rounded-full relative cursor-pointer transition-all duration-300',
                                        isDeviceLocked ? 'bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.4)]' : 'bg-white/10')}>
                                    <div className={cn('absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow',
                                        isDeviceLocked ? 'right-1' : 'right-7')} />
                                </div>
                            </div>

                            <button
                                onClick={() => {
                                    setDevices([]);
                                    setIsDeviceLocked(false);
                                    setSaveSuccess(isRTL ? "✅ تم تصفير الأجهزة وفتح المتصفح" : "✅ Devices reset & lock disabled");
                                }}
                                className="w-full py-3 bg-red-500/10 border border-red-500/20 text-red-400 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-red-500/20 transition-all mb-4"
                            >
                                {isRTL ? "تصفير ارتباط الأجهزة وفتح القفل" : "RESET DEVICE BINDING & UNLOCK"}
                            </button>

                            {/* قائمة الأجهزة */}
                            <div className="space-y-2">
                                {devices.length === 0 ? (
                                    <p className="text-center text-white/20 text-sm py-8">لا توجد أجهزة مربوطة بهذا الحساب</p>
                                ) : devices.map(dev => (
                                    <div key={dev.deviceId}
                                        className="flex items-center justify-between gap-3 bg-white/[0.02] border border-white/8 p-4 rounded-xl">
                                        <div>
                                            <div className="text-sm font-bold text-white">{dev.browser} على {dev.os}</div>
                                            <div className="text-[10px] text-white/30 font-mono">IP: {dev.ip}</div>
                                            <div className={cn('text-[9px] mt-0.5', dev.isActive ? 'text-green-400' : 'text-red-400')}>
                                                {dev.isActive ? '● نشط' : '● محظور'}
                                            </div>
                                        </div>
                                        <button
                                            onClick={() => setDevices(d => d.map(x =>
                                                x.deviceId === dev.deviceId ? { ...x, isActive: !x.isActive } : x
                                            ))}
                                            className={cn('px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all',
                                                dev.isActive
                                                    ? 'bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20'
                                                    : 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20')}>
                                            {dev.isActive ? 'حظر' : 'رفع الحظر'}
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* ── تذييل النافذة: رسائل + زر الحفظ ── */}
                <div className="p-5 border-t border-white/8 flex-shrink-0 space-y-3">
                    {saveError && (
                        <div className="flex items-center gap-2 p-3 bg-red-500/10 border border-red-500/30 rounded-xl text-red-400 text-xs font-bold">
                            <AlertCircle className="w-4 h-4 shrink-0" />
                            <span>{saveError}</span>
                        </div>
                    )}
                    {saveSuccess && (
                        <div className="flex items-center gap-2 p-3 bg-green-500/10 border border-green-500/30 rounded-xl text-green-400 text-xs font-bold">
                            <CheckCircle2 className="w-4 h-4 shrink-0" />
                            <span>{saveSuccess}</span>
                        </div>
                    )}
                    <div className="flex gap-3">
                        <button onClick={handleSave} disabled={loading || !!saveSuccess}
                            className="flex-1 py-3.5 bg-blue-500 text-white font-black uppercase tracking-wider rounded-xl hover:bg-blue-400 transition-all disabled:opacity-50 text-sm shadow-[0_0_20px_rgba(59,130,246,0.3)] flex items-center justify-center gap-2">
                            {loading ? (
                                <><span className="animate-spin inline-block w-4 h-4 border-2 border-white/30 border-t-white rounded-full" /> جاري الحفظ...</>
                            ) : (
                                <><Save className="w-4 h-4" /> حفظ التغييرات</>
                            )}
                        </button>
                        <button onClick={onClose}
                            className="px-6 py-3.5 border border-white/10 text-white/50 font-black uppercase tracking-wider rounded-xl hover:bg-white/5 transition-all text-sm">
                            إغلاق
                        </button>
                    </div>
                </div>
            </motion.div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { motion } from 'framer-motion';
import {
    Gavel, Clock, Users, TrendingUp,
    ChevronLeft, ChevronRight, AlertCircle, CheckCircle
} from 'lucide-react';
import { api } from '@/lib/api';
import { useLocale } from '@/hooks/useLocale';
import ClientPageHeader from '@/components/ClientPageHeader';
import { useSettings } from '@/lib/SettingsContext';

interface AuctionDetails {
    _id: string;
    title?: string;
    car: {
        _id: string;
        title: string;
        make: string;
        model: string;
        year: number;
        images: string[];
        mileage?: number;
        fuelType?: string;
        transmission?: string;
    };
    startingPrice: number;
    currentPrice: number;
    minBidIncrement?: number;
    startTime: string;
    endTime: string;
    status: string;
    totalBids?: number;
}

interface Bid {
    id: string;
    amount: number;
    bidder: { id: string; name: string };
    createdAt: string;
}

export default function AuctionDetailsPage() {
    const params = useParams();
    const { isRTL, locale } = useLocale();
    const { formatPrice: formatGlobalPrice } = useSettings();
    const [auction, setAuction] = useState<AuctionDetails | null>(null);
    const [bids, setBids] = useState<Bid[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [bidAmount, setBidAmount] = useState('');
    const [bidding, setBidding] = useState(false);
    const [bidMessage, setBidMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [timeLeft, setTimeLeft] = useState('');
    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const [imageErrors, setImageErrors] = useState<Record<number, boolean>>({});

    useEffect(() => {
        if (params.id) {
            fetchAuctionDetails();
            fetchBids();
        }
    }, [params.id]);

    useEffect(() => {
        if (auction) {
            const timer = setInterval(() => {
                setTimeLeft(calculateTimeLeft());
            }, 1000);
            return () => clearInterval(timer);
        }
    }, [auction]);

    const fetchAuctionDetails = async () => {
        try {
            setLoading(true);
            const response = await api.auctions.getById(params.id as string);
            if (response.success) {
                setAuction(response.data);
                setBidAmount(String((response.data.currentPrice || response.data.startingPrice) + (response.data.minBidIncrement || 100)));
            } else {
                setError(isRTL ? 'المزاد غير موجود' : 'Auction not found');
            }
        } catch (err: any) {
            setError(err.message || (isRTL ? 'حدث خطأ' : 'An error occurred'));
        } finally {
            setLoading(false);
        }
    };

    const fetchBids = async () => {
        try {
            const response = await api.bids.auctionBids(params.id as string, 10);
            if (response.success) {
                setBids(response.data);
            }
        } catch (err) {
            console.error('Failed to fetch bids:', err);
        }
    };

    const calculateTimeLeft = () => {
        if (!auction) return '';
        const end = new Date(auction.endTime).getTime();
        const now = Date.now();
        const diff = end - now;

        if (diff <= 0) return isRTL ? 'انتهى المزاد' : 'Auction Ended';

        const days = Math.floor(diff / (1000 * 60 * 60 * 24));
        const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((diff % (1000 * 60)) / 1000);

        if (days > 0) {
            return `${days}${isRTL ? 'ي' : 'd'} ${hours}${isRTL ? 'س' : 'h'} ${minutes}${isRTL ? 'د' : 'm'}`;
        }
        return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
    };

    const placeBid = async () => {
        const amount = parseInt(bidAmount);
        if (!amount || amount <= (auction?.currentPrice || 0)) {
            setBidMessage({
                type: 'error',
                text: isRTL ? 'المبلغ يجب أن يكون أعلى من السعر الحالي' : 'Amount must be higher than current price'
            });
            return;
        }

        try {
            setBidding(true);
            setBidMessage(null);
            const response = await api.bids.place(params.id as string, amount);
            if (response.success) {
                setBidMessage({ type: 'success', text: isRTL ? 'تم تقديم المزايدة بنجاح!' : 'Bid placed successfully!' });
                fetchAuctionDetails();
                fetchBids();
            }
        } catch (err: any) {
            setBidMessage({ type: 'error', text: err.message || (isRTL ? 'فشل في تقديم المزايدة' : 'Failed to place bid') });
        } finally {
            setBidding(false);
        }
    };

    const formatPrice = (price: number) => formatGlobalPrice(Number(price || 0));

    const formatTime = (dateStr: string) => {
        return new Date(dateStr).toLocaleString(locale === 'AR' ? 'ar-SA' : 'en-US');
    };

    const isActive = auction?.status === 'active' || auction?.status === 'running';

    if (loading) {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
                <div className="w-16 h-16 border-4 border-[#c5a059] border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    if (error || !auction) {
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center text-white">
                <AlertCircle className="w-20 h-20 text-red-500 mb-4" />
                <h1 className="text-2xl font-bold mb-4">{error || (isRTL ? 'المزاد غير موجود' : 'Auction not found')}</h1>
                <Link href="/auctions" className="text-[#c5a059] hover:underline">
                    {isRTL ? 'العودة للمزادات' : 'Back to Auctions'}
                </Link>
            </div>
        );
    }

    const car = auction.car;

    return (
        <div className={`min-h-screen bg-black text-white ${isRTL ? 'rtl' : 'ltr'}`} dir={isRTL ? 'rtl' : 'ltr'}>
            <div className="max-w-7xl mx-auto px-4 pt-24 pb-4">
                <ClientPageHeader title={isRTL ? 'تفاصيل المزاد' : 'Auction Details'} icon={Gavel} />
            </div>

            <main className="max-w-7xl mx-auto px-4 pb-20">
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">

                    {/* Main Content - 2 columns */}
                    <div className="lg:col-span-2 space-y-8">
                        {/* Image Gallery */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="relative aspect-video rounded-3xl overflow-hidden bg-white/5 border border-white/10"
                        >
                            {car.images && car.images.length > 0 ? (
                                (() => {
                                    const imageSrc = car.images[currentImageIndex] || '';
                                    const showFallback = !imageSrc || imageErrors[currentImageIndex];
                                    return showFallback ? (
                                        <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-white/5 via-black/40 to-black/80">
                                            <Gavel className="w-24 h-24 text-white/20" />
                                        </div>
                                    ) : (
                                        <img
                                            src={imageSrc}
                                            alt={car.title}
                                            className="w-full h-full object-cover"
                                            onError={() => setImageErrors(prev => ({ ...prev, [currentImageIndex]: true }))}
                                        />
                                    );
                                })()
                            ) : (
                                <div className="w-full h-full flex items-center justify-center">
                                    <Gavel className="w-32 h-32 text-white/20" />
                                </div>
                            )}

                            {car.images && car.images.length > 1 && (
                                <>
                                    <button
                                        onClick={() => setCurrentImageIndex((prev) => (prev - 1 + car.images.length) % car.images.length)}
                                        className="absolute left-4 top-1/2 -translate-y-1/2 w-12 h-12 bg-black/50 backdrop-blur-xl rounded-full flex items-center justify-center hover:bg-[#c5a059] transition-colors"
                                    >
                                        <ChevronLeft className="w-6 h-6" />
                                    </button>
                                    <button
                                        onClick={() => setCurrentImageIndex((prev) => (prev + 1) % car.images.length)}
                                        className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 bg-black/50 backdrop-blur-xl rounded-full flex items-center justify-center hover:bg-[#c5a059] transition-colors"
                                    >
                                        <ChevronRight className="w-6 h-6" />
                                    </button>
                                </>
                            )}

                            {/* Status Badge */}
                            <div className={`absolute top-4 left-4 px-4 py-2 rounded-full font-bold ${isActive ? 'bg-green-500' : 'bg-red-500'
                                }`}>
                                {isActive ? (isRTL ? 'مزاد نشط' : 'LIVE') : (isRTL ? 'انتهى' : 'ENDED')}
                            </div>
                        </motion.div>

                        {/* Car Info */}
                        <div className="space-y-4">
                            <div className="flex items-center gap-3 text-[#c5a059] text-sm font-bold uppercase tracking-wider">
                                <span>{car.make}</span>
                                <span>•</span>
                                <span>{car.year}</span>
                            </div>
                            <h1 className="text-4xl font-black">{auction.title || `${car.make} ${car.model}`}</h1>

                            <div className="flex flex-wrap gap-4 text-white/60">
                                {car.mileage && <span>{car.mileage.toLocaleString()} {isRTL ? 'كم' : 'km'}</span>}
                                {car.fuelType && <span>• {car.fuelType}</span>}
                                {car.transmission && <span>• {car.transmission}</span>}
                            </div>
                        </div>

                        {/* Bid History */}
                        <div className="bg-white/5 rounded-3xl border border-white/10 p-6">
                            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                                <TrendingUp className="w-5 h-5 text-[#c5a059]" />
                                {isRTL ? 'سجل المزايدات' : 'Bid History'}
                            </h3>

                            {bids.length > 0 ? (
                                <div className="space-y-3">
                                    {bids.map((bid, index) => (
                                        <div
                                            key={bid.id}
                                            className={`flex items-center justify-between py-3 border-b border-white/10 last:border-0 ${index === 0 ? 'text-[#c5a059]' : 'text-white/70'
                                                }`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full bg-white/10 flex items-center justify-center font-bold">
                                                    {bid.bidder.name}
                                                </div>
                                                <span>{index === 0 ? (isRTL ? 'أعلى مزايدة' : 'Highest Bid') : ''}</span>
                                            </div>
                                            <div className="text-right">
                                                <div className="font-bold">{formatPrice(bid.amount)}</div>
                                                <div className="text-xs text-white/40">{formatTime(bid.createdAt)}</div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-white/50 text-center py-8">
                                    {isRTL ? 'لا توجد مزايدات بعد' : 'No bids yet'}
                                </p>
                            )}
                        </div>
                    </div>

                    {/* Sidebar - Bidding Panel */}
                    <div className="space-y-6">
                        {/* Timer */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="bg-gradient-to-br from-[#c5a059]/20 to-[#c5a059]/5 rounded-3xl border border-[#c5a059]/30 p-6 text-center"
                        >
                            <Clock className="w-8 h-8 text-[#c5a059] mx-auto mb-3" />
                            <div className="text-white/60 text-sm mb-2">{isRTL ? 'الوقت المتبقي' : 'Time Remaining'}</div>
                            <div className="text-3xl font-black font-mono">{timeLeft}</div>
                        </motion.div>

                        {/* Current Price */}
                        <div className="bg-white/5 rounded-3xl border border-white/10 p-6">
                            <div className="text-white/60 text-sm mb-2">{isRTL ? 'السعر الحالي' : 'Current Price'}</div>
                            <div className="text-4xl font-black text-[#c5a059]">
                                {formatPrice(auction.currentPrice || auction.startingPrice)}
                            </div>
                            <div className="text-white/40 text-sm mt-2">
                                {isRTL ? 'سعر البداية:' : 'Starting:'} {formatPrice(auction.startingPrice)}
                            </div>
                        </div>

                        {/* Bidding Form */}
                        {isActive && (
                            <div className="bg-white/5 rounded-3xl border border-white/10 p-6 space-y-4">
                                <h3 className="font-bold text-lg">{isRTL ? 'قدم مزايدتك' : 'Place Your Bid'}</h3>

                                <div>
                                    <label className="text-white/60 text-sm block mb-2">
                                        {isRTL ? 'قيمة المزايدة' : 'Bid Amount'}
                                    </label>
                                    <input
                                        type="number"
                                        value={bidAmount}
                                        onChange={(e) => setBidAmount(e.target.value)}
                                        min={(auction.currentPrice || auction.startingPrice) + (auction.minBidIncrement || 100)}
                                        step={auction.minBidIncrement || 100}
                                        className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-lg font-bold focus:outline-none focus:border-[#c5a059]"
                                    />
                                    <div className="text-white/40 text-xs mt-1">
                                        {isRTL ? 'الحد الأدنى للزيادة:' : 'Min Increment:'} {formatPrice(auction.minBidIncrement || 100)}
                                    </div>
                                </div>

                                {bidMessage && (
                                    <div className={`flex items-center gap-2 p-3 rounded-xl ${bidMessage.type === 'success' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'
                                        }`}>
                                        {bidMessage.type === 'success' ? <CheckCircle className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
                                        <span>{bidMessage.text}</span>
                                    </div>
                                )}

                                <button
                                    onClick={placeBid}
                                    disabled={bidding}
                                    className="w-full py-4 bg-[#c5a059] text-black font-bold rounded-xl hover:bg-[#d4af68] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                >
                                    <Gavel className="w-5 h-5" />
                                    {bidding ? (isRTL ? 'جاري التقديم...' : 'Placing...') : (isRTL ? 'قدم المزايدة' : 'Place Bid')}
                                </button>
                            </div>
                        )}

                        {/* Stats */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-white/5 rounded-2xl p-4 text-center border border-white/10">
                                <Users className="w-6 h-6 text-[#c5a059] mx-auto mb-2" />
                                <div className="text-2xl font-bold">{bids.length}</div>
                                <div className="text-white/50 text-sm">{isRTL ? 'مزايدة' : 'Bids'}</div>
                            </div>
                            <div className="bg-white/5 rounded-2xl p-4 text-center border border-white/10">
                                <TrendingUp className="w-6 h-6 text-[#c5a059] mx-auto mb-2" />
                                <div className="text-2xl font-bold">
                                    {auction.currentPrice && auction.startingPrice
                                        ? Math.round(((auction.currentPrice - auction.startingPrice) / auction.startingPrice) * 100)
                                        : 0}%
                                </div>
                                <div className="text-white/50 text-sm">{isRTL ? 'زيادة' : 'Increase'}</div>
                            </div>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
}

'use client';

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import { MessageCircle, X, ExternalLink, ChevronLeft, ShieldCheck, Info, Tag, AlertTriangle } from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { api } from "@/lib/api";

export default function LiveAuctionDetails() {
    const { isRTL } = useLanguage();
    const { id } = useParams();
    const router = useRouter();
    const [session, setSession] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [selectedCar, setSelectedCar] = useState<any>(null);

    const [globalWhatsapp, setGlobalWhatsapp] = useState('+967781007805');

    useEffect(() => {
        api.settings.getPublic().then((res: any) => {
            if (res?.success && res.data.socialLinks?.whatsapp) {
                setGlobalWhatsapp(res.data.socialLinks.whatsapp);
            }
        }).catch(() => { });
    }, []);

    useEffect(() => {
        const loadSession = async () => {
            try {
                const res = await api.liveAuctions.getById(id as string);
                if (res.success) setSession(res.data);
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        loadSession();
    }, [id]);

    const handleBuyRequest = (car: any) => {
        const phone = session.whatsappNumber || globalWhatsapp; // استخدم رقم المزاد أو الرقم العام الافتراضي
        const text = encodeURIComponent(
            isRTL
                ? `السلام عليكم، أريد الاستفسار عن شراء سيارة من المزاد المباشر:\nالسيارة: ${car.title}\nالمزاد: ${session.title}\nرقم اللوت: ${car.lotNumber || 'N/A'}`
                : `Hello, I'm interested in buying this car from the Live Auction:\nCar: ${car.title}\nAuction: ${session.title}\nLot #: ${car.lotNumber || 'N/A'}`
        );
        window.open(`https://wa.me/${phone}?text=${text}`, '_blank');
    };

    if (loading) return <div className="min-h-screen bg-black flex items-center justify-center text-white/20 uppercase tracking-[0.5em] animate-pulse">Initializing HUD Feed...</div>;
    if (!session) return <div className="min-h-screen bg-black flex items-center justify-center text-white">Session not found</div>;

    return (
        <div className={`min-h-screen bg-[#050505] text-white ${isRTL ? 'font-arabic' : ''}`} dir={isRTL ? 'rtl' : 'ltr'}>
            <Navbar />

            {/* Top HUD Bar */}
            <div className="fixed top-20 left-0 right-0 z-40 bg-black/60 backdrop-blur-3xl border-b border-white/5 p-4 mx-6 rounded-b-2xl shadow-2xl">
                <div className="max-w-[1500px] mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-6">
                        <button onClick={() => router.back()} className="p-3 bg-white/5 rounded-xl border border-white/10 hover:bg-white/10 transition-all">
                            <ChevronLeft className={cn("w-5 h-5", isRTL && "rotate-180")} />
                        </button>
                        <div>
                            <span className="text-[10px] font-black text-cinematic-neon-red uppercase tracking-widest flex items-center gap-2">
                                <div className="w-2 h-2 rounded-full bg-cinematic-neon-red animate-pulse" />
                                {session.status === 'live' ? (isRTL ? 'بث مباشر الآن' : 'LIVE TRANSMISSION') : (isRTL ? 'جلسة منتهية' : 'SESSION ENDED')}
                            </span>
                            <h1 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter">{session.title}</h1>
                        </div>
                    </div>

                    {session.externalUrl && (
                        <a href={session.externalUrl} target="_blank" className="hidden md:flex items-center gap-3 px-6 py-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-all">
                            <ExternalLink className="w-4 h-4 text-white/40" />
                            <span className="text-[10px] font-black uppercase tracking-widest">{isRTL ? 'عرض الموقع الرسمي' : 'OFFICIAL AUCTION SITE'}</span>
                        </a>
                    )}
                </div>
            </div>

            <main className="pt-52 pb-20 px-6 max-w-[1500px] mx-auto grid grid-cols-1 lg:grid-cols-12 gap-10">

                {/* Left Side: Feed or External Link */}
                <div className="lg:col-span-8 space-y-8">
                    {session.externalUrl ? (
                        <div className="relative aspect-video w-full bg-zinc-900 rounded-3xl overflow-hidden border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)]">
                            <iframe
                                src={session.externalUrl}
                                className="w-full h-full border-0"
                                title="Auction Feed"
                                allowFullScreen
                            />
                            {/* Protection overlay if needed, but here we want interaction */}
                        </div>
                    ) : (
                        <div className="bg-white/[0.02] border border-white/5 rounded-3xl p-12 text-center space-y-4">
                            <AlertTriangle className="w-16 h-16 text-white/5 mx-auto" />
                            <h3 className="text-2xl font-black uppercase italic text-white/20 tracking-tighter">No Live Video Feed</h3>
                            <p className="text-white/40 text-[11px] uppercase tracking-widest">Please refer to the manual car list below</p>
                        </div>
                    )}

                    {/* Manual Car List */}
                    <div className="space-y-6 pt-10">
                        <div className="flex items-center gap-4 mb-8">
                            <div className="h-[2px] w-12 bg-cinematic-neon-blue" />
                            <h2 className="text-2xl font-black uppercase italic tracking-tighter">{isRTL ? 'السيارات المتوفرة للمزايدة' : 'AVAILABLE FOR PURCHASE'}</h2>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {session.cars?.map((car: any, idx: number) => (
                                <motion.div
                                    key={idx}
                                    whileHover={{ y: -10 }}
                                    className="glass-card bg-white/[0.01] border-white/5 p-6 space-y-6 cursor-pointer group"
                                    onClick={() => setSelectedCar(car)}
                                >
                                    <div className="relative aspect-video rounded-2xl overflow-hidden border border-white/5">
                                        <img src={car.images?.[0] || 'https://images.unsplash.com/photo-1552519507-da3b142c6e3d'} className="w-full h-full object-cover grayscale-[0.5] group-hover:grayscale-0 transition-all duration-700" alt={car.title} />
                                        <div className="absolute top-4 right-4 flex gap-2">
                                            <div className="px-3 py-1 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 text-[8px] font-black uppercase tracking-widest">{car.condition}</div>
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <h3 className="text-xl font-black uppercase italic truncate">{car.title}</h3>
                                        <div className="flex justify-between items-end border-t border-white/5 pt-4">
                                            <div>
                                                <span className="text-[9px] font-bold text-white/20 uppercase tracking-widest">{isRTL ? 'تقدير السعر' : 'ESTIMATE'}</span>
                                                <div className="text-lg font-black text-cinematic-neon-blue tracking-tighter">{car.priceEstimate || 'Contact Us'}</div>
                                            </div>
                                            <button
                                                onClick={(e) => { e.stopPropagation(); handleBuyRequest(car); }}
                                                className="px-6 py-3 bg-white/5 border border-white/10 rounded-xl hover:bg-cinematic-neon-blue/20 hover:text-cinematic-neon-blue transition-all text-[9px] font-black uppercase tracking-[0.2em]"
                                            >
                                                {isRTL ? 'شراء عبر واتساب' : 'BUY VIA WHATSAPP'}
                                            </button>
                                        </div>
                                    </div>
                                </motion.div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Right Side: Info & HUD */}
                <div className="lg:col-span-4 space-y-8">
                    <div className="glass-card p-8 bg-white/[0.02] border-white/5 space-y-8">
                        <div>
                            <span className="text-[9px] font-black text-white/20 uppercase tracking-[0.4em] mb-4 block">Process Info</span>
                            <div className="space-y-6">
                                <div className="flex gap-4">
                                    <div className="w-10 h-10 shrink-0 rounded-xl bg-cinematic-neon-blue/10 border border-cinematic-neon-blue/20 flex items-center justify-center">
                                        <ShieldCheck className="w-5 h-5 text-cinematic-neon-blue" />
                                    </div>
                                    <div>
                                        <h4 className="text-[11px] font-black uppercase tracking-widest mb-1">{isRTL ? 'وساطة آمنة' : 'SECURE BROKERAGE'}</h4>
                                        <p className="text-[10px] text-white/40 leading-relaxed">{isRTL ? 'نحن نقوم بالمزايدة نيابة عنك في المزاد الخارجي لضمان أفضل سعر.' : 'We bid on your behalf at the external auction to ensure the best price.'}</p>
                                    </div>
                                </div>
                                <div className="flex gap-4">
                                    <div className="w-10 h-10 shrink-0 rounded-xl bg-cinematic-neon-red/10 border border-cinematic-neon-red/20 flex items-center justify-center">
                                        <MessageCircle className="w-5 h-5 text-cinematic-neon-red" />
                                    </div>
                                    <div>
                                        <h4 className="text-[11px] font-black uppercase tracking-widest mb-1">{isRTL ? 'اتفاق الواتساب' : 'WHATSAPP AGREEMENT'}</h4>
                                        <p className="text-[10px] text-white/40 leading-relaxed">{isRTL ? 'بعد الضغط على شراء، سنتفق على الحد الأقصى للمزايدة والشروط.' : 'After clicking buy, we will agree on the maximum bid limit and terms.'}</p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="pt-8 border-t border-white/5">
                            <span className="text-[9px] font-black text-white/20 uppercase tracking-[0.4em] mb-6 block">Support</span>
                            <a href={`https://wa.me/${(session.whatsappNumber || globalWhatsapp).replace(/[^0-9]/g, '')}`} className="w-full py-4 bg-green-500/10 border border-green-500/20 rounded-2xl flex items-center justify-center gap-3 text-green-500 hover:bg-green-500/20 transition-all">
                                <MessageCircle className="w-5 h-5" />
                                <span className="text-[10px] font-black uppercase tracking-widest">{isRTL ? 'تحدث مع المستشار' : 'TALK TO EXPERT'}</span>
                            </a>
                        </div>
                    </div>
                </div>
            </main>

            {/* Car Details Modal */}
            <AnimatePresence>
                {selectedCar && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/95 backdrop-blur-3xl overflow-y-auto">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }}
                            className="bg-zinc-950 border border-white/10 rounded-3xl w-full max-w-5xl overflow-hidden relative"
                        >
                            <button onClick={() => setSelectedCar(null)} className="absolute top-6 right-6 text-white/40 hover:text-white z-20 transition-all hover:rotate-90"><X className="w-8 h-8" /></button>

                            <div className="grid grid-cols-1 lg:grid-cols-2">
                                <div className="p-8 space-y-6">
                                    <div className="aspect-video rounded-2xl overflow-hidden border border-white/10">
                                        <img src={selectedCar.images?.[0]} className="w-full h-full object-cover" alt="" />
                                    </div>
                                    <div className="grid grid-cols-4 gap-4">
                                        {selectedCar.images?.slice(1, 5).map((img: string, i: number) => (
                                            <div key={i} className="aspect-square rounded-xl overflow-hidden border border-white/10">
                                                <img src={img} className="w-full h-full object-cover" alt="" />
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                <div className="p-12 space-y-10 flex flex-col justify-center">
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-3">
                                            <Tag className="w-4 h-4 text-cinematic-neon-blue" />
                                            <span className="text-[11px] font-black text-cinematic-neon-blue uppercase tracking-widest">{selectedCar.condition}</span>
                                        </div>
                                        <h2 className="text-4xl lg:text-5xl font-black italic uppercase tracking-tighter leading-none">{selectedCar.title}</h2>
                                        <p className="text-white/40 text-[13px] leading-relaxed max-w-md">{selectedCar.description || (isRTL ? 'لا توجد تفاصيل إضافية متوفرة حالياً لهذه السيارة.' : 'No additional details currently available for this vehicle.')}</p>
                                    </div>

                                    <div className="flex items-center gap-10">
                                        <div>
                                            <span className="text-[10px] font-black text-white/20 uppercase tracking-widest block mb-1">MSRP Estimate</span>
                                            <div className="text-3xl font-black text-white">{selectedCar.priceEstimate || 'TBD'}</div>
                                        </div>
                                        {selectedCar.lotNumber && (
                                            <div>
                                                <span className="text-[10px] font-black text-white/20 uppercase tracking-widest block mb-1">Lot Number</span>
                                                <div className="text-3xl font-black text-white/40">{selectedCar.lotNumber}</div>
                                            </div>
                                        )}
                                    </div>

                                    <div className="flex flex-col sm:flex-row gap-4 pt-10">
                                        <button
                                            onClick={() => handleBuyRequest(selectedCar)}
                                            className="flex-1 py-5 bg-cinematic-neon-blue text-black font-black uppercase text-xs tracking-[0.4em] rounded-2xl shadow-[0_0_40px_rgba(0,240,255,0.3)] hover:scale-105 transition-all"
                                        >
                                            {isRTL ? 'شراء السيارة الآن' : 'SECURE THIS CAR'}
                                        </button>
                                        <button onClick={() => setSelectedCar(null)} className="px-10 py-5 bg-white/5 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white/10 transition-all">
                                            {isRTL ? 'العودة' : 'CANCEL'}
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

        </div>
    );
}

'use client';

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect } from "react";
import {
    Gavel, Trophy, Clock, XCircle, TrendingUp,
    ChevronLeft, ChevronRight,
    Flame
} from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { useSettings } from "@/lib/SettingsContext";
import { api } from "@/lib/api";
import Link from "next/link";

type BidStatus = 'won' | 'lost' | 'active' | 'outbid';

interface MyBid {
    id: string;
    auction: {
        id: string;
        title: string;
        image: string;
        endDate: string;
        basePrice: number;
    };
    myAmount: number;
    currentHighest: number;
    status: BidStatus;
    bidTime: string;
    totalBids: number;
}

export default function MyBidsPage() {
    const { isRTL } = useLanguage();
    const { formatPrice } = useSettings();
    const [bids, setBids] = useState<MyBid[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState<'all' | BidStatus>('all');

    useEffect(() => {
        loadBids();
    }, []);

    const loadBids = async () => {
        try {
            const res = await api.bids?.myBids?.();
            if (res?.success) {
                setBids(res.data);
            } else throw new Error();
        } catch {
            // Mock data
            setBids([
                {
                    id: '1',
                    auction: {
                        id: 'a1',
                        title: 'FERRARI F8 TRIBUTO 2023',
                        image: 'https://images.unsplash.com/photo-1586464831261-c3b7f68ea2b1?q=80&w=1200',
                        endDate: new Date(Date.now() - 3600000).toISOString(),
                        basePrice: 850000,
                    },
                    myAmount: 920000,
                    currentHighest: 920000,
                    status: 'won',
                    bidTime: new Date(Date.now() - 7200000).toISOString(),
                    totalBids: 34,
                },
                {
                    id: '2',
                    auction: {
                        id: 'a2',
                        title: 'LAMBORGHINI URUS 2024',
                        image: 'https://images.unsplash.com/photo-1544636331-e26879cd4d9b?q=80&w=1200',
                        endDate: new Date(Date.now() + 86400000 * 2).toISOString(),
                        basePrice: 1200000,
                    },
                    myAmount: 1250000,
                    currentHighest: 1350000,
                    status: 'outbid',
                    bidTime: new Date(Date.now() - 1800000).toISOString(),
                    totalBids: 61,
                },
                {
                    id: '3',
                    auction: {
                        id: 'a3',
                        title: 'PORSCHE 911 TURBO S 2024',
                        image: 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?q=80&w=1200',
                        endDate: new Date(Date.now() + 3600000 * 5).toISOString(),
                        basePrice: 700000,
                    },
                    myAmount: 750000,
                    currentHighest: 750000,
                    status: 'active',
                    bidTime: new Date(Date.now() - 600000).toISOString(),
                    totalBids: 22,
                },
                {
                    id: '4',
                    auction: {
                        id: 'a4',
                        title: 'BMW M8 COMPETITION 2023',
                        image: 'https://images.unsplash.com/photo-1555215695-3004980ad54e?q=80&w=1200',
                        endDate: new Date(Date.now() - 86400000 * 5).toISOString(),
                        basePrice: 480000,
                    },
                    myAmount: 500000,
                    currentHighest: 520000,
                    status: 'lost',
                    bidTime: new Date(Date.now() - 86400000 * 5).toISOString(),
                    totalBids: 45,
                },
            ]);
        } finally {
            setLoading(false);
        }
    };

    const filtered = filter === 'all' ? bids : bids.filter(b => b.status === filter);

    const stats = {
        total: bids.length,
        won: bids.filter(b => b.status === 'won').length,
        active: bids.filter(b => b.status === 'active').length,
        outbid: bids.filter(b => b.status === 'outbid').length,
        lost: bids.filter(b => b.status === 'lost').length,
    };

    const getStatusMeta = (status: BidStatus) => ({
        won: { label: isRTL ? 'فزت' : 'WON', color: 'text-green-400', bg: 'bg-green-400/10 border-green-400/30', icon: Trophy },
        active: { label: isRTL ? 'مشارك' : 'ACTIVE', color: 'text-cinematic-neon-blue', bg: 'bg-cinematic-neon-blue/10 border-cinematic-neon-blue/30', icon: Flame },
        outbid: { label: isRTL ? 'تم تجاوزك' : 'OUTBID', color: 'text-cinematic-neon-yellow', bg: 'bg-cinematic-neon-yellow/10 border-cinematic-neon-yellow/30', icon: TrendingUp },
        lost: { label: isRTL ? 'خسرت' : 'LOST', color: 'text-cinematic-neon-red', bg: 'bg-cinematic-neon-red/10 border-cinematic-neon-red/30', icon: XCircle },
    }[status]);

    const formatCountdown = (dateStr: string) => {
        const diff = new Date(dateStr).getTime() - Date.now();
        if (diff <= 0) return isRTL ? 'انتهى' : 'Ended';
        const h = Math.floor(diff / 3600000);
        const m = Math.floor((diff % 3600000) / 60000);
        return `${h}h ${m}m`;
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
                <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
                    className="w-14 h-14 border-4 border-cinematic-neon-red border-t-transparent rounded-full" />
            </div>
        );
    }

    return (
        <div className="relative min-h-screen bg-black text-white font-sans overflow-hidden">
            <Navbar />

            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,_rgba(255,0,60,0.05),_transparent_55%)]" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,0,60,0.01)_1px,transparent_1px),linear-gradient(90deg,rgba(255,0,60,0.01)_1px,transparent_1px)] bg-[size:80px_80px]" />
            </div>

            <main className="relative z-10 pt-32 pb-24 px-6 max-w-6xl mx-auto">

                {/* Back */}
                <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="mb-10">
                    <Link href="/auctions" className="inline-flex items-center gap-3 text-white/40 hover:text-white transition-colors group">
                        {isRTL ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />}
                        <span className="text-[11px] font-black uppercase tracking-[0.3em]">
                            {isRTL ? 'المزادات' : 'AUCTIONS'}
                        </span>
                    </Link>
                </motion.div>

                {/* Header */}
                <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="mb-12">
                    <div className="flex items-center gap-5">
                        <div className="p-4 rounded-2xl bg-cinematic-neon-red/10 border border-cinematic-neon-red/20">
                            <Gavel className="w-8 h-8 text-cinematic-neon-red" />
                        </div>
                        <div>
                            <h1 className="text-4xl md:text-5xl font-black uppercase tracking-tighter">
                                {isRTL ? 'مزايداتي' : 'MY BIDS'}
                            </h1>
                            <p className="text-white/40 text-[11px] uppercase tracking-[0.3em] mt-1 font-bold">
                                {isRTL ? 'سجل مشاركاتك في المزادات' : 'YOUR AUCTION PARTICIPATION HISTORY'}
                            </p>
                        </div>
                    </div>
                </motion.div>

                {/* Stats Row */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-10">
                    {[
                        { key: 'all', label: isRTL ? 'الكل' : 'ALL', value: stats.total, color: 'text-white' },
                        { key: 'won', label: isRTL ? 'فزت' : 'WON', value: stats.won, color: 'text-green-400' },
                        { key: 'active', label: isRTL ? 'مشارك' : 'ACTIVE', value: stats.active, color: 'text-cinematic-neon-blue' },
                        { key: 'outbid', label: isRTL ? 'تجاوزوك' : 'OUTBID', value: stats.outbid, color: 'text-cinematic-neon-yellow' },
                        { key: 'lost', label: isRTL ? 'خسرت' : 'LOST', value: stats.lost, color: 'text-cinematic-neon-red' },
                    ].map((s) => (
                        <motion.button
                            key={s.key}
                            onClick={() => setFilter(s.key as any)}
                            whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                            className={cn(
                                "glass-card p-6 bg-white/[0.01] border-white/5 text-center transition-all",
                                filter === s.key && "border-cinematic-neon-red/30 bg-cinematic-neon-red/5"
                            )}
                        >
                            <div className={cn("text-3xl font-black tracking-tighter mb-2", s.color)}>{s.value}</div>
                            <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/50">{s.label}</div>
                        </motion.button>
                    ))}
                </div>

                {/* Bids List */}
                <AnimatePresence mode="popLayout">
                    {filtered.length === 0 ? (
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-32">
                            <Gavel className="w-24 h-24 text-white/10 mx-auto mb-8" />
                            <h3 className="text-2xl font-black uppercase tracking-tight text-white/40">
                                {isRTL ? 'لا توجد مزايدات' : 'NO BIDS FOUND'}
                            </h3>
                        </motion.div>
                    ) : (
                        <div className="space-y-6">
                            {filtered.map((bid, i) => {
                                const meta = getStatusMeta(bid.status);
                                const StatusIcon = meta.icon;
                                const isLeading = bid.myAmount >= bid.currentHighest && bid.status === 'active';
                                return (
                                    <motion.div
                                        key={bid.id}
                                        layout
                                        initial={{ opacity: 0, y: 30 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: -20 }}
                                        transition={{ delay: i * 0.08 }}
                                        className={cn(
                                            "glass-card bg-white/[0.01] border-white/5 overflow-hidden hover:border-white/10 transition-all",
                                            bid.status === 'won' && "border-green-400/20 shadow-[0_0_30px_rgba(74,222,128,0.08)]",
                                            bid.status === 'outbid' && "border-cinematic-neon-yellow/10",
                                        )}
                                    >
                                        <div className="grid grid-cols-1 lg:grid-cols-12 gap-0">

                                            {/* Image */}
                                            <div className="lg:col-span-3 relative overflow-hidden h-52 lg:h-auto">
                                                <img
                                                    src={bid.auction.image}
                                                    alt={bid.auction.title}
                                                    className="w-full h-full object-cover grayscale-[20%] hover:grayscale-0 transition-all duration-700"
                                                />
                                                <div className="absolute inset-0 bg-gradient-to-t lg:bg-gradient-to-r from-black/60 to-transparent" />
                                                {bid.status === 'won' && (
                                                    <div className="absolute top-4 left-4 bg-green-400 text-black px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest flex items-center gap-2">
                                                        <Trophy className="w-3 h-3" />
                                                        {isRTL ? 'فائز!' : 'WINNER!'}
                                                    </div>
                                                )}
                                                {bid.status === 'outbid' && (
                                                    <div className="absolute top-4 left-4 bg-cinematic-neon-yellow text-black px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest">
                                                        {isRTL ? 'تجاوزوك!' : 'OUTBID!'}
                                                    </div>
                                                )}
                                            </div>

                                            {/* Info */}
                                            <div className="lg:col-span-9 p-8 flex flex-col justify-between gap-6">
                                                <div className="flex flex-wrap items-start justify-between gap-4">
                                                    <div>
                                                        <h3 className="text-xl md:text-2xl font-black uppercase italic tracking-tighter mb-2">
                                                            {bid.auction.title}
                                                        </h3>
                                                        <div className="flex items-center gap-3 flex-wrap">
                                                            <span className="text-[10px] font-black text-white/30 uppercase tracking-widest">
                                                                <Clock className="w-3 h-3 inline mr-1" />
                                                                {formatCountdown(bid.auction.endDate)}
                                                            </span>
                                                            <span className="text-white/20">·</span>
                                                            <span className="text-[10px] font-black text-white/30 uppercase tracking-widest">
                                                                {bid.totalBids} {isRTL ? 'مزايدة' : 'bids'}
                                                            </span>
                                                        </div>
                                                    </div>
                                                    <div className={cn(
                                                        "px-4 py-2 rounded-xl border flex items-center gap-2 text-[11px] font-black uppercase tracking-wider",
                                                        meta.bg, meta.color
                                                    )}>
                                                        <StatusIcon className="w-4 h-4" />
                                                        {meta.label}
                                                    </div>
                                                </div>

                                                {/* Bid amounts */}
                                                <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                                                    <div>
                                                        <div className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] mb-1">
                                                            {isRTL ? 'مزايدتي' : 'MY BID'}
                                                        </div>
                                                        <div className={cn(
                                                            "text-2xl font-black italic",
                                                            isLeading ? "text-green-400" : "text-white"
                                                        )}>
                                                            {formatPrice ? formatPrice(Number(bid.myAmount)) : `${Number(bid.myAmount).toLocaleString()} SAR`}
                                                        </div>
                                                    </div>
                                                    <div>
                                                        <div className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] mb-1">
                                                            {isRTL ? 'أعلى مزايدة' : 'HIGHEST BID'}
                                                        </div>
                                                        <div className="text-2xl font-black italic text-cinematic-neon-blue">
                                                            {formatPrice ? formatPrice(Number(bid.currentHighest)) : `${Number(bid.currentHighest).toLocaleString()} SAR`}
                                                        </div>
                                                    </div>
                                                    <div>
                                                        <div className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] mb-1">
                                                            {isRTL ? 'وقت المزايدة' : 'BID TIME'}
                                                        </div>
                                                        <div className="text-sm font-bold text-white/60">
                                                            {new Date(bid.bidTime).toLocaleString(isRTL ? 'ar-SA' : 'en-US', {
                                                                month: 'short', day: 'numeric',
                                                                hour: '2-digit', minute: '2-digit'
                                                            })}
                                                        </div>
                                                    </div>
                                                </div>

                                                {/* Difference bar (outbid) */}
                                                {bid.status === 'outbid' && (
                                                    <div className="space-y-2">
                                                        <div className="flex justify-between text-[9px] font-black text-white/30 uppercase tracking-widest">
                                                            <span>{isRTL ? 'أنت متأخر بـ:' : 'You are behind by:'}</span>
                                                            <span className="text-cinematic-neon-yellow">
                                                                {formatPrice ? formatPrice(Number(bid.currentHighest - bid.myAmount)) : `${(bid.currentHighest - bid.myAmount).toLocaleString()} SAR`}
                                                            </span>
                                                        </div>
                                                        <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                                                            <div
                                                                className="h-full bg-cinematic-neon-yellow rounded-full transition-all duration-700"
                                                                data-width={Math.min((bid.myAmount / bid.currentHighest) * 100, 100)}
                                                            />
                                                        </div>
                                                    </div>
                                                )}

                                                {/* CTA */}
                                                <div className="flex gap-4 flex-wrap">
                                                    {bid.status === 'outbid' && (
                                                        <Link href={`/auctions/${bid.auction.id}`}>
                                                            <motion.button
                                                                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                                                                className="px-6 py-3 bg-cinematic-neon-red/10 border border-cinematic-neon-red/30 text-cinematic-neon-red rounded-xl text-[11px] font-black uppercase tracking-wide hover:bg-cinematic-neon-red/20 transition-all"
                                                            >
                                                                {isRTL ? '⚡ زايد مجدداً' : '⚡ BID AGAIN'}
                                                            </motion.button>
                                                        </Link>
                                                    )}
                                                    {bid.status === 'active' && (
                                                        <Link href={`/auctions/${bid.auction.id}`}>
                                                            <motion.button
                                                                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                                                                className="px-6 py-3 bg-cinematic-neon-blue/10 border border-cinematic-neon-blue/30 text-cinematic-neon-blue rounded-xl text-[11px] font-black uppercase tracking-wide hover:bg-cinematic-neon-blue/20 transition-all"
                                                            >
                                                                {isRTL ? 'متابعة المزاد' : 'VIEW AUCTION'}
                                                            </motion.button>
                                                        </Link>
                                                    )}
                                                    {bid.status === 'won' && (
                                                        <Link href="/orders">
                                                            <motion.button
                                                                whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
                                                                className="px-6 py-3 bg-green-400/10 border border-green-400/30 text-green-400 rounded-xl text-[11px] font-black uppercase tracking-wide hover:bg-green-400/20 transition-all"
                                                            >
                                                                {isRTL ? '📦 عرض الطلب' : '📦 VIEW ORDER'}
                                                            </motion.button>
                                                        </Link>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </motion.div>
                                );
                            })}
                        </div>
                    )}
                </AnimatePresence>

            </main>
        </div>
    );
}

'use client';

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect } from "react";
import { Gavel, AlertCircle, Radio, Car } from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { api } from "@/lib/api";
import { useSettings } from "@/lib/SettingsContext";
import Link from "next/link";
import ClientPageHeader from "@/components/ClientPageHeader";

export default function Auctions() {
    const { isRTL } = useLanguage();
    const { formatPrice } = useSettings();
    const [activeTab, setActiveTab] = useState('LIVE');
    const [auctions, setAuctions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [imageErrors, setImageErrors] = useState<Record<string, boolean>>({});

    const normalizeImage = (src?: string) => (typeof src === 'string' ? src.trim() : '');

    useEffect(() => {
        const loadData = async () => {
            setLoading(true);
            try {
                if (activeTab === 'SHOWROOM') {
                    // [[ARABIC_COMMENT]] جلب المزادات المباشرة اليدوية من قاعدة البيانات
                    const data = await api.liveAuctions.list();
                    if (data.success) setAuctions(data.data || []);
                } else {
                    // [[ARABIC_COMMENT]] الحالات الصحيحة: 'live' للمباشر و 'upcoming' للقادم
                    const status = activeTab === 'LIVE' ? 'live' : 'upcoming';
                    const data = await api.auctions.list({ status });
                    if (data.success) setAuctions(data.data || []);
                }

            } catch (err) {
                console.error("Failed to load data", err);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, [activeTab]);

    return (
        <div className={`relative min-h-screen bg-black text-white overflow-x-hidden ${isRTL ? 'font-arabic' : ''}`} dir={isRTL ? 'rtl' : 'ltr'}>
            <Navbar />

            <div className="pt-24 px-6 max-w-[1500px] mx-auto">
                <ClientPageHeader
                    title={isRTL ? "المزادات" : "AUCTIONS"}
                    subtitle={activeTab === 'SHOWROOM' ? (isRTL ? "المعرض المباشر" : "LIVE SHOWROOM") : (isRTL ? "بث مباشر" : "LIVE FEED")}
                    icon={Gavel}
                />
            </div>

            {/* ── VIDEO HERO ── */}
            <div className="relative h-[85vh] md:h-[60vh] overflow-hidden mt-8 mx-6 rounded-3xl border border-white/5">
                <video
                    autoPlay loop muted playsInline
                    className="absolute inset-0 w-full h-full object-cover"
                    style={{ filter: 'brightness(0.45) contrast(1.25) saturate(1.1)' }}
                >
                    <source src="/videos/video_2026-02-07_22-24-50.mp4" type="video/mp4" />
                </video>
                <div className="absolute inset-0 bg-gradient-to-b from-black/30 via-transparent to-black/70" />

                {/* Hero Content */}
                <div className="absolute inset-0 flex items-end z-10">
                    <div className="max-w-[1500px] mx-auto w-full px-6 pb-16">
                        <motion.div
                            initial={{ opacity: 0, y: 30 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8 }}
                            className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-8"
                        >
                            <div>
                                <span className="text-[9px] font-bold uppercase tracking-[0.5em] text-accent-red/80 block mb-3">
                                    {isRTL ? "بث مباشر" : "LIVE FEED"}
                                </span>
                                <h1 className="text-4xl md:text-5xl font-black tracking-[-0.04em] uppercase italic">
                                    {activeTab === 'SHOWROOM' ? (isRTL ? "المعرض المباشر" : "SHOW SHOWROOM") : (isRTL ? "المزادات" : "AUCTIONS")}
                                </h1>
                            </div>

                            {/* Tabs */}
                            <div className="flex bg-white/[0.04] p-1.5 rounded-xl border border-white/5 backdrop-blur-xl">
                                <button
                                    onClick={() => setActiveTab('LIVE')}
                                    className={cn(
                                        "px-8 py-3.5 rounded-lg text-[10px] font-bold uppercase tracking-[0.15em] transition-all duration-400 flex items-center gap-3",
                                        activeTab === 'LIVE'
                                            ? "bg-accent-red text-white shadow-[0_8px_25px_rgba(232,54,78,0.25)]"
                                            : "text-white/30 hover:text-white/50"
                                    )}
                                >
                                    <Radio className={cn("w-3.5 h-3.5", activeTab === 'LIVE' && "animate-pulse")} />
                                    {isRTL ? "مباشر" : "LIVE"}
                                </button>
                                <button
                                    onClick={() => setActiveTab('SHOWROOM')}
                                    className={cn(
                                        "px-8 py-3.5 rounded-lg text-[10px] font-bold uppercase tracking-[0.15em] transition-all duration-400 flex items-center gap-3",
                                        activeTab === 'SHOWROOM'
                                            ? "bg-cinematic-neon-blue text-black shadow-lg"
                                            : "text-white/30 hover:text-white/50"
                                    )}
                                >
                                    <Gavel className="w-3.5 h-3.5" />
                                    {isRTL ? "المعرض" : "SHOWROOM"}
                                </button>
                                <button
                                    onClick={() => setActiveTab('UPCOMING')}
                                    className={cn(
                                        "px-8 py-3.5 rounded-lg text-[10px] font-bold uppercase tracking-[0.15em] transition-all duration-400",
                                        activeTab === 'UPCOMING'
                                            ? "bg-white text-black shadow-lg"
                                            : "text-white/30 hover:text-white/50"
                                    )}
                                >
                                    {isRTL ? "قادمة" : "UPCOMING"}
                                </button>
                            </div>
                        </motion.div>
                    </div>
                </div>
            </div>

            <main className="relative z-10 pt-16 pb-32 px-6 max-w-[1500px] mx-auto">
                <div className="grid grid-cols-1 gap-8">
                    <AnimatePresence mode="popLayout">
                        {auctions.map((item, i) => (
                            <motion.div key={item._id || item.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
                                className="group obsidian-card overflow-hidden flex flex-col lg:flex-row"
                            >
                                {activeTab === 'SHOWROOM' ? (
                                    <>
                                        <div className="lg:w-[40%] h-64 lg:h-auto overflow-hidden relative">
                                            {(() => {
                                                const imageKey = `${item._id || item.id}-live`;
                                                const imageSrc = normalizeImage((item.cars && item.cars[0]?.images?.[0]) || '');
                                                const showFallback = !imageSrc || imageErrors[imageKey];
                                                return showFallback ? (
                                                    <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-white/5 via-black/40 to-black/80">
                                                        <div className="text-center">
                                                            <Car className="w-10 h-10 text-white/15 mx-auto mb-2" />
                                                            <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/30">No Image</div>
                                                        </div>
                                                    </div>
                                                ) : (
                                                    <img
                                                        src={imageSrc}
                                                        className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700"
                                                        alt=""
                                                        onError={() => setImageErrors(prev => ({ ...prev, [imageKey]: true }))}
                                                    />
                                                );
                                            })()}
                                            {item.status === 'live' && (
                                                <div className="absolute top-6 left-6 px-4 py-2 bg-cinematic-neon-red/20 border border-cinematic-neon-red/40 rounded-lg backdrop-blur-md">
                                                    <span className="text-[10px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                                                        <div className="w-2 h-2 rounded-full bg-cinematic-neon-red animate-pulse" /> {isRTL ? 'بث مباشر' : 'LIVE'}
                                                    </span>
                                                </div>
                                            )}
                                        </div>
                                        <div className="flex-1 p-10 space-y-8 flex flex-col justify-center">
                                            <div>
                                                <h2 className="text-4xl font-black italic uppercase tracking-tighter">{item.title}</h2>
                                                <p className="text-white/40 text-[10px] font-bold uppercase tracking-widest mt-2">{item.externalUrl ? 'Linked to Official Platform' : 'Internal Selection'}</p>
                                            </div>
                                            <div className="flex items-center gap-10">
                                                <div>
