    const filterItems = [
        { key: 'all', label: 'الكل', labelEn: 'All', icon: Sparkles, count: notifications.length },
        { key: 'unread', label: 'غير مقروء', labelEn: 'Unread', icon: Eye, count: unreadCount },
        ...Object.entries(NOTIFICATION_TYPES).map(([key, val]) => ({
            key, label: val.label, labelEn: val.labelEn, icon: val.icon,
            count: notifications.filter(n => n.type === key).length,
        })),
    ];

    return (
        <div className={cn("min-h-screen bg-black text-white font-sans overflow-x-hidden", isRTL && "rtl")}>
            <Navbar />

            {/* Cinematic Background */}
            <div className="fixed inset-0 z-0 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-cinematic-neon-blue/8 via-black to-black" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(0,240,255,0.015)_1px,transparent_1px),linear-gradient(90deg,rgba(0,240,255,0.015)_1px,transparent_1px)] bg-[size:60px_60px]" />
                <motion.div animate={{ y: [0, -20, 0], opacity: [0.15, 0.3, 0.15] }} transition={{ duration: 8, repeat: Infinity }} className="absolute top-1/3 right-1/4 w-80 h-80 bg-cinematic-neon-blue/10 rounded-full blur-[100px]" />
                <motion.div animate={{ y: [0, 25, 0], opacity: [0.1, 0.2, 0.1] }} transition={{ duration: 11, repeat: Infinity, delay: 3 }} className="absolute bottom-1/4 left-1/4 w-64 h-64 bg-purple-500/10 rounded-full blur-[90px]" />
            </div>

            <div className="relative z-10 flex h-screen pt-20">

                {/* ── LEFT SIDEBAR (Filters + Stats) ─────── */}
                <aside className={cn(
                    "hidden lg:flex flex-col w-72 shrink-0 h-[calc(100vh-5rem)] sticky top-20",
                    "bg-white/[0.02] backdrop-blur-2xl border-white/5 overflow-y-auto",
                    isRTL ? "border-l" : "border-r"
                )}>
                    <div className="p-6 flex flex-col h-full gap-6">

                        {/* Header */}
                        <div>
                            <button
                                onClick={() => router.back()}
                                title={isRTL ? 'رجوع' : 'Back'}
                                aria-label={isRTL ? 'رجوع' : 'Back'}
                                className={cn(
                                    "inline-flex items-center justify-center w-11 h-11 rounded-xl bg-white/5 border border-white/10 text-white/60 hover:text-white hover:bg-white/10 transition-all mb-5"
                                )}
                            >
                                {isRTL ? <ArrowRight className="w-4 h-4" /> : <ArrowLeft className="w-4 h-4" />}
                            </button>

                            {/* Bell Icon + Count */}
                            <div className="flex items-center gap-3 mb-2">
                                <div className="relative">
                                    <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-cinematic-neon-blue to-purple-600 flex items-center justify-center shadow-[0_0_30px_rgba(0,240,255,0.3)]">
                                        <Bell className="w-6 h-6 text-white" />
                                    </div>
                                    {unreadCount > 0 && (
                                        <motion.span
                                            initial={{ scale: 0 }} animate={{ scale: 1 }}
                                            className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-cinematic-neon-red rounded-full text-[9px] font-black flex items-center justify-center shadow-[0_0_12px_rgba(255,0,60,0.6)]"
                                        >
                                            {unreadCount}
                                        </motion.span>
                                    )}
                                </div>
                                <div>
                                    <h1 className="text-xl font-black uppercase italic tracking-tight">
                                        {isRTL ? 'الإشعارات' : 'Notifications'}
                                    </h1>
                                    <p className="text-[10px] text-white/30 uppercase tracking-widest">
                                        {isRTL ? `${unreadCount} غير مقروءة` : `${unreadCount} unread`}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Filter List */}
                        <div className="flex-1 space-y-1">
                            <p className={cn("text-[9px] font-black uppercase tracking-[0.3em] text-white/20 mb-3 flex items-center gap-2", isRTL && "flex-row-reverse")}>
                                <Filter className="w-3 h-3" /> {isRTL ? 'تصفية' : 'Filter by'}
                            </p>
                            {filterItems.map(item => (
                                <button
                                    key={item.key}
                                    onClick={() => setFilter(item.key)}
                                    className={cn(
                                        "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all text-[11px] font-black uppercase tracking-wider",
                                        isRTL && "flex-row-reverse text-right",
                                        filter === item.key
                                            ? "bg-white text-black shadow-lg"
                                            : item.key === 'unread' && item.count > 0
                                                ? "bg-cinematic-neon-blue/10 text-cinematic-neon-blue border border-cinematic-neon-blue/20 hover:bg-cinematic-neon-blue/20"
                                                : "text-white/50 hover:text-white hover:bg-white/5"
                                    )}
                                >
                                    <item.icon className="w-4 h-4 shrink-0" />
                                    <span className="flex-1">{isRTL ? item.label : item.labelEn}</span>
                                    {item.count > 0 && (
                                        <span className={cn(
                                            "px-2 py-0.5 rounded-md text-[9px] shrink-0",
                                            filter === item.key ? "bg-black/10" : "bg-white/10"
                                        )}>
                                            {item.count}
                                        </span>
                                    )}
                                </button>
                            ))}
                        </div>

                        {/* Bottom Actions */}
                        <div className="space-y-2 pt-4 border-t border-white/5">
                            {/* Sound Toggle */}
                            <button
                                onClick={() => setSoundEnabled(!soundEnabled)}
                                className={cn(
                                    "w-full flex items-center gap-3 px-4 py-3 rounded-xl border transition-all text-[11px] font-black uppercase tracking-wider",
                                    isRTL && "flex-row-reverse",
                                    soundEnabled
                                        ? "bg-cinematic-neon-blue/10 border-cinematic-neon-blue/20 text-cinematic-neon-blue"
                                        : "bg-white/5 border-white/10 text-white/40"
                                )}
                            >
                                {soundEnabled ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
                                <span>{isRTL ? (soundEnabled ? 'صوت مفعّل' : 'صوت مكتوم') : (soundEnabled ? 'Sound On' : 'Sound Off')}</span>
                            </button>

                            {/* Mark All Read */}
                            <button
                                onClick={markAllRead}
                                disabled={unreadCount === 0}
                                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-[11px] font-black uppercase tracking-wider text-white/60 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed"
                                style={{ flexDirection: isRTL ? 'row-reverse' : 'row' }}
                            >
                                <CheckCheck className="w-4 h-4 shrink-0" />
                                <span>{isRTL ? 'قراءة الكل' : 'Mark All Read'}</span>
                            </button>

                            {/* Clear All */}
                            <button
                                onClick={clearAll}
                                disabled={notifications.length === 0}
                                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl bg-cinematic-neon-red/10 border border-cinematic-neon-red/20 text-cinematic-neon-red hover:bg-cinematic-neon-red/20 transition-all text-[11px] font-black uppercase tracking-wider disabled:opacity-30 disabled:cursor-not-allowed"
                                style={{ flexDirection: isRTL ? 'row-reverse' : 'row' }}
                            >
                                <Trash2 className="w-4 h-4 shrink-0" />
                                <span>{isRTL ? 'مسح الكل' : 'Clear All'}</span>
                            </button>
                        </div>
                    </div>
                </aside>

                {/* ── MAIN CONTENT ───────────────────────── */}
                <main className="flex-1 h-[calc(100vh-5rem)] overflow-y-auto">
                    <div className="max-w-3xl mx-auto px-4 md:px-8 py-8">

                        {/* Mobile Header */}
                        <div className="lg:hidden mb-6">
                            <div className="flex items-center justify-between mb-4">
                                <button onClick={() => router.back()} className="p-2 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                                    {isRTL ? <ArrowRight className="w-5 h-5" /> : <ArrowLeft className="w-5 h-5" />}
                                </button>
                                <h1 className="text-2xl font-black uppercase italic">
                                    {isRTL ? 'الإشعارات' : 'Notifications'}
                                </h1>
                                <div className="flex items-center gap-2">
                                    <button onClick={() => setSoundEnabled(!soundEnabled)} className="p-2 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                                        {soundEnabled ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
                                    </button>
                                </div>
                            </div>
                            {/* Mobile Filter Scroll */}
                            <div className="flex gap-2 overflow-x-auto scrollbar-hide pb-2">
                                {filterItems.map(item => (
                                    <button
                                        key={item.key}
                                        onClick={() => setFilter(item.key)}
                                        className={cn(
                                            "flex items-center gap-1.5 px-3 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider whitespace-nowrap shrink-0 transition-all",
                                            filter === item.key ? "bg-white text-black" : "bg-white/5 text-white/40 hover:text-white hover:bg-white/10"
                                        )}
                                    >
                                        <item.icon className="w-3.5 h-3.5" />
                                        {isRTL ? item.label : item.labelEn}
                                        {item.count > 0 && <span className="ml-1 opacity-60">{item.count}</span>}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Section Title */}
                        <div className={cn("flex items-center justify-between mb-6", isRTL && "flex-row-reverse")}>
                            <div className={cn("flex items-center gap-3", isRTL && "flex-row-reverse")}>
                                <div className="h-[2px] w-8 bg-cinematic-neon-blue shadow-[0_0_10px_rgba(0,240,255,1)]" />
                                <span className="text-[10px] font-black uppercase tracking-[0.4em] text-cinematic-neon-blue">
                                    {filter === 'all' ? (isRTL ? 'جميع الإشعارات' : 'All Notifications')
                                        : filter === 'unread' ? (isRTL ? 'غير المقروءة' : 'Unread')
                                            : isRTL ? NOTIFICATION_TYPES[filter as keyof typeof NOTIFICATION_TYPES]?.label : NOTIFICATION_TYPES[filter as keyof typeof NOTIFICATION_TYPES]?.labelEn}
                                </span>
                            </div>
                            <span className="text-[10px] text-white/20 font-black uppercase tracking-wider">
                                {filtered.length} {isRTL ? 'إشعار' : 'items'}
                            </span>
                        </div>

                        {/* Notifications List */}
                        <div className="space-y-3">
                            <AnimatePresence mode="popLayout">
                                {filtered.length === 0 ? (
                                    <motion.div
                                        key="empty"
                                        initial={{ opacity: 0, scale: 0.95 }}
                                        animate={{ opacity: 1, scale: 1 }}
                                        className="py-24 text-center"
                                    >
                                        <div className="w-20 h-20 mx-auto mb-5 rounded-full bg-white/[0.03] border border-white/5 flex items-center justify-center">
                                            <Bell className="w-9 h-9 text-white/10" />
                                        </div>
                                        <h3 className="text-xl font-black uppercase italic text-white/20 mb-2">
                                            {isRTL ? 'لا توجد إشعارات' : 'No Notifications'}
                                        </h3>
                                        <p className="text-[11px] text-white/10 uppercase tracking-[0.3em]">
                                            {isRTL ? 'أنت على اطلاع بكل شيء!' : "You're all caught up!"}
                                        </p>
                                    </motion.div>
                                ) : (
                                    filtered.map((notification, idx) => (
                                        <NotifCard
                                            key={notification.id}
                                            n={notification}
                                            idx={idx}
                                            isRTL={isRTL}
                                            onRead={() => markRead(notification.id)}
                                            onDelete={() => remove(notification.id)}
                                            onSelect={() => { markRead(notification.id); setSelected(notification); }}
                                        />
                                    ))
                                )}
                            </AnimatePresence>
                        </div>

                    </div>
                </main>

                {/* ── DETAIL PANEL (right side on wide screens) ── */}
                <AnimatePresence>
                    {selected && (
                        <>
                            {/* Overlay for small screens */}
                            <motion.div
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="fixed inset-0 z-40 bg-black/70 backdrop-blur-sm lg:hidden"
                                onClick={() => setSelected(null)}
                            />

                            {/* Panel */}
                            <motion.div
                                initial={{ x: isRTL ? '-100%' : '100%' }}
                                animate={{ x: 0 }}
                                exit={{ x: isRTL ? '-100%' : '100%' }}
                                transition={{ type: 'spring', damping: 28, stiffness: 300 }}
                                className={cn(
                                    "fixed top-20 bottom-0 z-50 w-full max-w-sm",
                                    "bg-zinc-950/95 backdrop-blur-2xl border-white/10",
                                    "flex flex-col shadow-[-20px_0_60px_rgba(0,0,0,0.6)]",
                                    isRTL ? "left-72 border-r" : "right-72 border-l",
                                    "lg:sticky lg:top-20 lg:h-[calc(100vh-5rem)] lg:w-80 lg:shrink-0 lg:flex"
                                )}
                            >
                                <DetailPanel
                                    n={selected}
                                    isRTL={isRTL}
                                    onClose={() => setSelected(null)}
                                    onDelete={() => { remove(selected.id); setSelected(null); }}
                                />
                            </motion.div>
                        </>
                    )}
                </AnimatePresence>

            </div>
        </div>
    );
}

// ─── Notification Card ─────────────────────────────────────────────────────────
function NotifCard({ n, idx, isRTL, onRead, onDelete, onSelect }: any) {
    const typeInfo = NOTIFICATION_TYPES[n.type as keyof typeof NOTIFICATION_TYPES];
    const TypeIcon = typeInfo?.icon || Bell;

    return (
        <motion.div
            layout
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, x: isRTL ? -60 : 60, scale: 0.95 }}
            transition={{ delay: idx * 0.04, duration: 0.3 }}
            onClick={onSelect}
            className={cn(
                "group relative flex items-start gap-4 p-5 rounded-2xl border cursor-pointer transition-all duration-300",
                n.read
                    ? "bg-white/[0.015] border-white/5 hover:bg-white/[0.03] hover:border-white/10"
                    : "bg-white/[0.04] border-white/10 hover:bg-white/[0.06] shadow-[0_4px_24px_rgba(0,0,0,0.3)]",
                isRTL && "flex-row-reverse"
            )}
        >
            {/* Priority Stripe */}
            {n.priority === 'high' && !n.read && (
                <div className={cn(
                    "absolute top-0 bottom-0 w-[3px] rounded-full bg-gradient-to-b from-cinematic-neon-red via-orange-500 to-cinematic-neon-red",
                    isRTL ? "right-0 rounded-r-2xl" : "left-0 rounded-l-2xl"
                )} />
            )}

            {/* Icon */}
            <div className={cn(
                "w-12 h-12 rounded-xl bg-gradient-to-br flex items-center justify-center shrink-0 shadow-lg",
                typeInfo?.color || 'from-gray-500 to-slate-600'
            )}>
                <TypeIcon className="w-5 h-5 text-white" />
            </div>

            {/* Content */}
            <div className="flex-1 min-w-0">
                <div className={cn("flex items-start justify-between gap-3 mb-1", isRTL && "flex-row-reverse")}>
                    <h3 className={cn("font-bold text-[14px] leading-snug", n.read ? "text-white/60" : "text-white")}>
                        {isRTL ? n.title : n.titleEn}
                    </h3>
                    <span className={cn("text-[10px] text-white/25 uppercase tracking-wider flex items-center gap-1 shrink-0", isRTL && "flex-row-reverse")}>
                        <Clock className="w-3 h-3" />
                        {isRTL ? n.time : n.timeEn}
                    </span>
                </div>
                <p className={cn("text-[12px] leading-relaxed line-clamp-2", n.read ? "text-white/30" : "text-white/50")}>
                    {isRTL ? n.message : n.messageEn}
                </p>
            </div>

            {/* Unread Dot */}
            {!n.read && (
                <div className="w-2 h-2 rounded-full bg-cinematic-neon-blue mt-1 shrink-0 shadow-[0_0_8px_rgba(0,240,255,0.8)]" />
            )}

            {/* Hover Actions */}
            <div className={cn(
                "absolute top-4 flex items-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity",
                isRTL ? "left-4" : "right-4"
            )}>
                {!n.read && (
                    <button onClick={e => { e.stopPropagation(); onRead(); }}
                        className="p-1.5 rounded-lg bg-white/5 hover:bg-cinematic-neon-blue/20 text-white/30 hover:text-cinematic-neon-blue transition-all">
                        <Check className="w-3.5 h-3.5" />
                    </button>
                )}
                <button onClick={e => { e.stopPropagation(); onDelete(); }}
                    className="p-1.5 rounded-lg bg-white/5 hover:bg-cinematic-neon-red/20 text-white/30 hover:text-cinematic-neon-red transition-all">
                    <Trash2 className="w-3.5 h-3.5" />
                </button>
            </div>
        </motion.div>
    );
}

// ─── Detail Panel ──────────────────────────────────────────────────────────────
function DetailPanel({ n, isRTL, onClose, onDelete }: any) {
    const typeInfo = NOTIFICATION_TYPES[n.type as keyof typeof NOTIFICATION_TYPES];
    const TypeIcon = typeInfo?.icon || Bell;

    return (
        <div className="flex flex-col h-full">
            {/* Panel Header */}
            <div className={cn("flex items-center justify-between p-5 border-b border-white/5", isRTL && "flex-row-reverse")}>
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30">
                    {isRTL ? 'تفاصيل الإشعار' : 'Notification Detail'}
                </span>
                <button onClick={onClose} className="p-1.5 rounded-lg bg-white/5 hover:bg-white/10 transition-all text-white/40 hover:text-white">
                    <X className="w-4 h-4" />
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-6">
                {/* Icon & Badge */}
                <div className="flex flex-col items-center text-center mb-8">
                    <div className={cn(
                        "w-20 h-20 rounded-3xl bg-gradient-to-br flex items-center justify-center mb-4 shadow-2xl",
                        typeInfo?.color || 'from-gray-500 to-slate-600'
                    )}>
                        <TypeIcon className="w-10 h-10 text-white" />
                    </div>

                    {/* Type Badge */}
                    <span className={cn(
                        "px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border",
                        typeInfo?.bg, typeInfo?.border,
                        "text-white/70"
                    )}>
                        {isRTL ? typeInfo?.label : typeInfo?.labelEn}
                    </span>
                </div>

                {/* Title */}
                <h2 className="text-2xl font-black uppercase italic mb-3 text-center leading-tight">
                    {isRTL ? n.title : n.titleEn}
                </h2>

                {/* Message */}
                <p className="text-white/60 leading-relaxed text-sm text-center mb-6">
                    {isRTL ? n.message : n.messageEn}
                </p>

                {/* Time */}
                <div className={cn("flex items-center justify-center gap-2 text-white/25 text-[11px] uppercase tracking-wider mb-8")}>
                    <Clock className="w-4 h-4" />
                    {isRTL ? n.time : n.timeEn}
                </div>

                {/* Priority Tag */}
                {n.priority === 'high' && (
                    <div className="flex items-center justify-center gap-2 mb-6 px-4 py-2 bg-cinematic-neon-red/10 border border-cinematic-neon-red/20 rounded-xl">
                        <AlertTriangle className="w-4 h-4 text-cinematic-neon-red" />
                        <span className="text-[10px] font-black uppercase tracking-wider text-cinematic-neon-red">
                            {isRTL ? 'أولوية عالية' : 'High Priority'}
                        </span>
                    </div>
                )}

                {/* Divider */}
                <div className="border-t border-white/5 mb-6" />

                {/* Actions */}
                <div className="space-y-3">
                    <button className="w-full py-4 bg-white text-black font-black uppercase tracking-[0.2em] text-xs rounded-xl hover:bg-cinematic-neon-blue hover:text-white transition-all shadow-lg">
                        {isRTL ? 'عرض التفاصيل' : 'View Details'}
                    </button>
                    <button
                        onClick={onDelete}
                        className="w-full py-3 bg-cinematic-neon-red/10 border border-cinematic-neon-red/20 text-cinematic-neon-red font-black uppercase tracking-[0.2em] text-xs rounded-xl hover:bg-cinematic-neon-red/20 transition-all flex items-center justify-center gap-2"
                    >
                        <Trash2 className="w-4 h-4" />
                        {isRTL ? 'حذف الإشعار' : 'Delete'}
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

/**
 * صفحة الفاتورة - تُفتح عند الضغط على زر "فاتورة" في الطلبات
 * تعرض فاتورة احترافية قابلة للطباعة أو الحفظ كـ PDF
 */

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Printer, Download, ArrowLeft, CheckCircle, Car, Calendar, Hash, User, Phone, MapPin } from 'lucide-react';
import { api } from '@/lib/api';
import { useLanguage } from '@/lib/LanguageContext';
import { useSettings } from '@/lib/SettingsContext';
import { motion } from 'framer-motion';
import { formatAmountWithSnapshot, getOrderGrandTotalSar } from '@/lib/orderCurrency';

export default function InvoicePage() {
    const { id } = useParams();
    const router = useRouter();
    const { isRTL } = useLanguage();
    const { displayCurrency, currency } = useSettings();
    const [order, setOrder] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const loadOrder = async () => {
            try {
                setLoading(true);
                const res = await api.orders.getById(id as string);
                if (res?.success && res.data) {
                    setOrder(res.data);
                } else {
                    setError(isRTL ? 'لم يتم العثور على الطلب' : 'Order not found');
                }
            } catch (err) {
                console.error('Failed to load order:', err);
                setError(isRTL ? 'حدث خطأ في تحميل الطلب' : 'Failed to load order');
            } finally {
                setLoading(false);
            }
        };
        if (id) loadOrder();
    }, [id, isRTL]);

    const handlePrint = () => {
        window.print();
    };

    const invoiceDate = order ? new Date(order.createdAt).toLocaleDateString('ar-SA', {
        year: 'numeric', month: 'long', day: 'numeric'
    }) : '';

    const statusLabel = (s: string) => {
        const map: Record<string, string> = {
            pending: isRTL ? 'قيد الانتظار' : 'Pending',
            confirmed: isRTL ? 'مؤكد' : 'Confirmed',
            completed: isRTL ? 'مكتمل' : 'Completed',
            cancelled: isRTL ? 'ملغي' : 'Cancelled',
        };
        return map[s] || s;
    };

    if (loading) return (
        <div className="min-h-screen bg-black flex items-center justify-center">
            <motion.div
                animate={{ rotate: 360 }}
                transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
                className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full"
            />
        </div>
    );

    if (error) return (
        <div className="min-h-screen bg-black flex items-center justify-center text-white text-center">
            <div>
                <p className="text-2xl font-bold mb-4">{error}</p>
                <button onClick={() => router.back()} className="px-6 py-3 bg-white/10 rounded-xl text-sm">
                    {isRTL ? 'العودة' : 'Go Back'}
                </button>
            </div>
        </div>
    );

    return (
        <>
            {/* ── أزرار التحكم - لا تُطبع ── */}
            <div className="no-print fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-6 py-4 flex items-center justify-between">
                <button
                    onClick={() => router.back()}
                    className="flex items-center gap-2 text-white/60 hover:text-white transition-colors text-sm font-bold"
                >
                    <ArrowLeft className="w-4 h-4" />
                    {isRTL ? 'العودة للطلبات' : 'Back to Orders'}
                </button>
                <div className="flex gap-3">
                    <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        onClick={handlePrint}
                        className="flex items-center gap-2 px-5 py-2.5 bg-white text-black font-black text-xs uppercase tracking-wider rounded-xl hover:bg-white/90 transition-all"
                    >
                        <Printer className="w-4 h-4" />
                        {isRTL ? 'طباعة / PDF' : 'Print / PDF'}
                    </motion.button>
                </div>
            </div>

            {/* ── محتوى الفاتورة ── */}
            <div className="min-h-screen bg-white pt-20 pb-16 px-8 print:pt-0 print:px-0" dir={isRTL ? 'rtl' : 'ltr'}>
                <div className="max-w-3xl mx-auto">

                    {/* رأس الفاتورة */}
                    <div className="flex justify-between items-start mb-12 pb-8 border-b-2 border-black/10 print:border-black/20">
                        <div>
                            <div className="text-4xl font-black tracking-tighter mb-1">
                                CAR<span className="text-red-600">HM</span>
                            </div>
                            <div className="text-xs text-gray-500 font-semibold uppercase tracking-widest">
                                {isRTL ? 'منصة مزادات السيارات الفاخرة' : 'Premium Car Auction Platform'}
                            </div>
                            <div className="text-xs text-gray-400 mt-1">info@hmcar.com</div>
                        </div>
                        <div className="text-right">
                            <div className="text-2xl font-black uppercase tracking-widest text-gray-800">
                                {isRTL ? 'فاتورة' : 'INVOICE'}
                            </div>
                            <div className="text-xs text-gray-500 mt-1 font-mono">
                                #{order?.orderNumber || id?.toString().slice(-8).toUpperCase()}
                            </div>
                            <div className="text-xs text-gray-400 mt-1">{invoiceDate}</div>
                        </div>
                    </div>

                    {/* بيانات الطلب والعميل */}
                    <div className="grid grid-cols-2 gap-8 mb-10">
                        <div>
                            <div className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-3 flex items-center gap-1">
                                <User className="w-3 h-3" />
                                {isRTL ? 'بيانات المشتري' : 'BUYER DETAILS'}
                            </div>
                            <div className="text-sm font-bold text-gray-800">{order?.buyer?.name || order?.buyerName || (isRTL ? 'العميل' : 'Customer')}</div>
                            {order?.buyer?.phone && (
                                <div className="text-xs text-gray-500 mt-1 flex items-center gap-1">
                                    <Phone className="w-3 h-3" />
                                    {order.buyer.phone}
                                </div>
                            )}
                            {order?.buyer?.email && (
                                <div className="text-xs text-gray-500 mt-1">{order.buyer.email}</div>
                            )}
                        </div>
                        <div>
                            <div className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-3 flex items-center gap-1">
                                <Hash className="w-3 h-3" />
                                {isRTL ? 'تفاصيل الطلب' : 'ORDER DETAILS'}
                            </div>
                            <div className="space-y-1 text-xs text-gray-600">
                                <div className="flex justify-between">
                                    <span className="text-gray-400">{isRTL ? 'رقم الطلب:' : 'Order No:'}</span>
                                    <span className="font-mono font-bold">{order?.orderNumber || id?.toString().slice(-8).toUpperCase()}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-400">{isRTL ? 'التاريخ:' : 'Date:'}</span>
                                    <span className="font-bold">{invoiceDate}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-400">{isRTL ? 'الحالة:' : 'Status:'}</span>
                                    <span className={`font-black uppercase text-[10px] ${order?.status === 'completed' ? 'text-green-600' : order?.status === 'pending' ? 'text-yellow-600' : 'text-gray-600'}`}>
                                        {statusLabel(order?.status)}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* جدول السيارة */}
                    <table className="w-full mb-8">
                        <thead>
                            <tr className="border-b-2 border-black">
                                <th className="text-left text-[10px] font-black uppercase tracking-widest text-gray-500 pb-3">
                                    {isRTL ? 'البند' : 'ITEM'}
                                </th>
                                <th className="text-center text-[10px] font-black uppercase tracking-widest text-gray-500 pb-3">
                                    {isRTL ? 'الكمية' : 'QTY'}
                                </th>
                                <th className="text-right text-[10px] font-black uppercase tracking-widest text-gray-500 pb-3">
                                    {isRTL ? 'المبلغ' : 'AMOUNT'}
                                </th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr className="border-b border-gray-100">
                                <td className="py-6">
                                    <div className="flex items-start gap-4">
                                        {order?.car?.image && (
                                            <img
                                                src={order.car.image}
                                                alt={order?.car?.title}
                                                className="w-20 h-14 object-cover rounded-lg border border-gray-200 flex-shrink-0"
                                            />
                                        )}
                                        <div>
                                            <div className="font-black text-gray-900 text-base">{order?.car?.title || (isRTL ? 'السيارة' : 'Vehicle')}</div>
                                            {order?.car?.make && (
                                                <div className="text-xs text-gray-400 mt-1 flex items-center gap-1">
                                                    <Car className="w-3 h-3" />
                                                    {order.car.make}
                                                </div>
                                            )}
                                            {order?.car?.year && (
                                                <div className="text-xs text-gray-400 mt-0.5 flex items-center gap-1">
                                                    <Calendar className="w-3 h-3" />
                                                    {isRTL ? 'موديل ' : 'Year '} {order.car.year}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </td>
                                <td className="py-6 text-center text-sm font-bold text-gray-600">1</td>
                                <td className="py-6 text-right">
                                    <div className="text-xl font-black text-gray-900">
                                        {formatAmountWithSnapshot(
                                            getOrderGrandTotalSar(order),
                                            displayCurrency,
                                            order,
                                            currency
                                        )}
                                    </div>
                                </td>
                            </tr>
                        </tbody>
                    </table>

                    {/* الإجمالي */}
                    <div className="flex justify-end mb-10">
                        <div className="w-72 space-y-3">
                            <div className="flex justify-between text-sm text-gray-500">
                                <span>{isRTL ? 'المجموع الجزئي' : 'Subtotal'}</span>
                                <span className="font-bold">{formatAmountWithSnapshot(getOrderGrandTotalSar(order), displayCurrency, order, currency)}</span>
                            </div>
                            <div className="flex justify-between text-sm text-gray-500">
                                <span>{isRTL ? 'الضريبة' : 'Tax'}</span>
                                <span className="font-bold">—</span>
                            </div>
                            <div className="border-t-2 border-black pt-3 flex justify-between text-lg font-black text-black">
                                <span>{isRTL ? 'الإجمالي' : 'TOTAL'}</span>
                                <span>{formatAmountWithSnapshot(getOrderGrandTotalSar(order), displayCurrency, order, currency)}</span>
                            </div>
                        </div>
                    </div>

                    {/* ملاحظة وتوقيع */}
                    {order?.status === 'completed' && (
                        <div className="flex items-center gap-3 p-4 bg-green-50 border border-green-200 rounded-xl mb-8 print:border-green-300">
                            <CheckCircle className="w-5 h-5 text-green-600 flex-shrink-0" />
                            <span className="text-sm font-bold text-green-700">
                                {isRTL ? 'تم إتمام هذه المعاملة بنجاح' : 'This transaction has been completed successfully'}
                            </span>
                        </div>
                    )}

                    {/* تذييل الفاتورة */}
                    <div className="pt-8 border-t border-gray-200 text-center">
                        <p className="text-xs text-gray-400 font-semibold">
                            {isRTL
                                ? 'شكراً لثقتكم بـ HM CAR — هذه الفاتورة تم إنشاؤها تلقائياً'
                                : 'Thank you for choosing HM CAR — This invoice was generated automatically'}
                        </p>
                        <p className="text-[10px] text-gray-300 mt-1">
                            car-auction-sand.vercel.app · info@hmcar.com
                        </p>
                    </div>
                </div>
            </div>

            {/* CSS للطباعة */}
            <style>{`
                @media print {
                    .no-print { display: none !important; }
                    body { background: white !important; }
                    @page { margin: 1.5cm; }
                }
            `}</style>
        </>
    );
}

'use client';

import { motion } from "framer-motion";
import { useState, useEffect } from "react";
import {
    Package, Clock, CheckCircle, Truck,
    CreditCard,
    Phone, Mail, AlertCircle, ChevronLeft, ChevronRight
} from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { useSettings } from "@/lib/SettingsContext";
import { api } from "@/lib/api";
import Link from "next/link";
import { useParams } from "next/navigation";
import { formatAmountWithSnapshot, getOrderGrandTotalSar } from "@/lib/orderCurrency";

const STATUS_STEPS = [
    { key: 'pending', labelAr: 'قيد الانتظار', labelEn: 'Pending', icon: Clock },
    { key: 'confirmed', labelAr: 'مؤكد', labelEn: 'Confirmed', icon: CheckCircle },
    { key: 'processing', labelAr: 'قيد المعالجة', labelEn: 'Processing', icon: Package },
    { key: 'shipped', labelAr: 'تم الشحن', labelEn: 'Shipped', icon: Truck },
    { key: 'completed', labelAr: 'مكتمل', labelEn: 'Completed', icon: CheckCircle },
];

export default function OrderDetailPage() {
    const { isRTL } = useLanguage();
    const { socialLinks, displayCurrency, currency } = useSettings(); // [[ARABIC_COMMENT]] جلب رقم واتساب الحقيقي
    const params = useParams();
    const orderId = params?.id as string;

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const [order, setOrder] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (orderId) loadOrder();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [orderId]);

    const loadOrder = async () => {
        try {
            setLoading(true);
            const res = await api.orders.getById(orderId);
            if (res.success) {
                setOrder(res.data);
            } else {
                throw new Error(res.error || 'Not found');
            }
        } catch {
            // [[ARABIC_COMMENT]] الطلب غير موجود - لا نعرض بيانات وهمية
            setOrder(null);
        } finally {
            setLoading(false);
        }
    };

    const getCurrentStepIndex = (status: string) => {
        const idx = STATUS_STEPS.findIndex(s => s.key === status);
        return idx === -1 ? 0 : idx;
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'pending': return 'text-cinematic-neon-yellow';
            case 'confirmed': return 'text-cinematic-neon-blue';
            case 'processing': return 'text-purple-400';
            case 'shipped': return 'text-amber-400';
            case 'completed': return 'text-green-400';
            case 'cancelled': return 'text-cinematic-neon-red';
            default: return 'text-white/60';
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
                <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
                    className="w-14 h-14 border-4 border-cinematic-neon-blue border-t-transparent rounded-full"
                />
            </div>
        );
    }

    if (!order) {
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6">
                <AlertCircle className="w-20 h-20 text-cinematic-neon-red" />
                <h2 className="text-2xl font-black text-white uppercase">{isRTL ? 'الطلب غير موجود' : 'Order Not Found'}</h2>
                <Link href="/orders" className="text-cinematic-neon-blue underline text-sm font-bold">
                    {isRTL ? 'العودة للطلبات' : 'Back to Orders'}
                </Link>
            </div>
        );
    }

    const currentStep = getCurrentStepIndex(order.status);

    return (
        <div className="relative min-h-screen bg-black text-white font-sans overflow-hidden">
            <Navbar />

            {/* Background */}
            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_left,_rgba(0,240,255,0.05),_transparent_60%)]" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(0,240,255,0.015)_1px,transparent_1px),linear-gradient(90deg,rgba(0,240,255,0.015)_1px,transparent_1px)] bg-[size:80px_80px]" />
            </div>

            <main className="relative z-10 pt-32 pb-24 px-6 max-w-6xl mx-auto">

                {/* Back Button */}
                <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="mb-10">
                    <Link href="/orders" className="inline-flex items-center gap-3 text-white/40 hover:text-white transition-colors group">
                        {isRTL ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />}
                        <span className="text-[11px] font-black uppercase tracking-[0.3em]">
                            {isRTL ? 'الطلبات' : 'MY ORDERS'}
                        </span>
                    </Link>
                </motion.div>

                {/* Header */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                    className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 mb-12"
                >
                    <div>
                        <div className="text-[10px] font-black text-cinematic-neon-blue/70 uppercase tracking-[0.4em] mb-2">
                            {order.orderNumber}
                        </div>
                        <h1 className="text-4xl md:text-5xl font-black uppercase tracking-tighter text-white">
                            {isRTL ? 'تفاصيل الطلب' : 'ORDER DETAILS'}
                        </h1>
                        <p className="text-white/40 text-sm mt-2 font-bold">
                            {new Date(order.createdAt).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US', {
                                year: 'numeric', month: 'long', day: 'numeric'
                            })}
                        </p>
                    </div>
                    <div className={cn(
                        "px-6 py-3 rounded-2xl border font-black text-sm uppercase tracking-widest",
                        order.status === 'completed' ? "bg-green-400/10 border-green-400/30 text-green-400" :
                            order.status === 'cancelled' ? "bg-cinematic-neon-red/10 border-cinematic-neon-red/30 text-cinematic-neon-red" :
                                "bg-cinematic-neon-blue/10 border-cinematic-neon-blue/30 text-cinematic-neon-blue"
                    )}>
                        {isRTL
                            ? STATUS_STEPS.find(s => s.key === order.status)?.labelAr || order.status
                            : STATUS_STEPS.find(s => s.key === order.status)?.labelEn || order.status
                        }
                    </div>
                </motion.div>

                {/* Progress Tracker */}
                {order.status !== 'cancelled' && (
                    <motion.div
                        initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}
                        className="glass-card p-8 md:p-12 bg-white/[0.01] border-white/5 mb-8 overflow-hidden"
                    >
                        <h2 className="text-[11px] font-black uppercase tracking-[0.5em] text-white/60 mb-10 flex items-center gap-3">
                            <Truck className="w-5 h-5 text-cinematic-neon-blue" />
                            {isRTL ? 'تتبع الطلب' : 'ORDER TRACKING'}
                        </h2>
                        <div className="relative flex items-center justify-between">
                            {/* Progress Line */}
                            <div className="absolute top-7 left-7 right-7 h-[2px] bg-white/5 z-0" />
                            <motion.div
                                className="absolute top-7 left-7 h-[2px] bg-cinematic-neon-blue z-0 shadow-[0_0_10px_rgba(0,240,255,0.8)]"
                                initial={{ width: 0 }}
                                animate={{ width: `${(currentStep / (STATUS_STEPS.length - 1)) * (100 - (100 / STATUS_STEPS.length))}%` }}
                                transition={{ duration: 1.5, delay: 0.3, ease: 'easeOut' }}
                            />
                            {STATUS_STEPS.map((step, i) => {
                                const StepIcon = step.icon;
                                const done = i <= currentStep;
                                const active = i === currentStep;
                                return (
                                    <div key={step.key} className="relative z-10 flex flex-col items-center gap-3">
                                        <motion.div
                                            initial={{ scale: 0 }} animate={{ scale: 1 }}
                                            transition={{ delay: i * 0.15 + 0.3 }}
                                            className={cn(
                                                "w-14 h-14 rounded-2xl border-2 flex items-center justify-center transition-all",
                                                done
                                                    ? "bg-cinematic-neon-blue border-cinematic-neon-blue shadow-[0_0_20px_rgba(0,240,255,0.5)]"
                                                    : "bg-white/[0.03] border-white/10"
                                            )}
                                        >
                                            <StepIcon className={cn("w-6 h-6", done ? "text-black" : "text-white/20")} />
                                        </motion.div>
                                        <div className={cn(
                                            "text-[9px] font-black uppercase tracking-[0.2em] text-center hidden md:block",
                                            done ? "text-cinematic-neon-blue" : "text-white/20"
                                        )}>
                                            {isRTL ? step.labelAr : step.labelEn}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </motion.div>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                    {/* Car Info */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}
                        className="lg:col-span-2 glass-card bg-white/[0.01] border-white/5 overflow-hidden"
                    >
                        <div className="relative h-56 overflow-hidden">
                            <img
                                src={order.car.image}
                                alt={order.car.title}
                                className="w-full h-full object-cover"
                            />
                            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent" />
                            <div className="absolute bottom-6 left-6 right-6">
                                <div className="text-[9px] font-black text-cinematic-neon-blue/80 uppercase tracking-[0.4em] mb-1">
                                    {isRTL ? 'السيارة المطلوبة' : 'ORDERED VEHICLE'}
                                </div>
                                <h3 className="text-2xl font-black uppercase italic tracking-tighter">{order.car.title}</h3>
                            </div>
                        </div>
                        <div className="p-8 grid grid-cols-2 md:grid-cols-3 gap-6">
                            {[
                                { label: isRTL ? 'الموديل' : 'Model', value: `${order.car.year}` },
                                { label: isRTL ? 'اللون' : 'Color', value: order.car.color },
                                { label: isRTL ? 'رقم الهيكل' : 'VIN', value: order.car.vin },
                            ].map((item, i) => (
                                <div key={i}>
                                    <div className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] mb-1">{item.label}</div>
                                    <div className="text-sm font-black text-white truncate">{item.value || '—'}</div>
                                </div>
                            ))}
                        </div>
                    </motion.div>

                    {/* Summary */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}
                        className="space-y-6"
                    >
                        {/* Payment */}
                        <div className="glass-card p-8 bg-white/[0.01] border-white/5">
                            <div className="flex items-center gap-3 mb-6">
                                <CreditCard className="w-5 h-5 text-green-400" />
                                <h3 className="text-[11px] font-black uppercase tracking-[0.4em] text-white">
                                    {isRTL ? 'ملخص الدفع' : 'PAYMENT'}
                                </h3>
                            </div>
                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] text-white/40 uppercase tracking-widest font-bold">
                                        {isRTL ? 'السعر' : 'Price'}
                                    </span>
                                    <span className="font-black text-white">
                                        {formatAmountWithSnapshot(
                                            Number(order.car?.price || getOrderGrandTotalSar(order)),
                                            displayCurrency,
                                            order,
                                            currency
                                        )}
                                    </span>
                                </div>
                                <div className="h-[1px] bg-white/5" />
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] text-white/40 uppercase tracking-widest font-bold">
                                        {isRTL ? 'الإجمالي' : 'Total'}
                                    </span>
                                    <span className="font-black text-xl text-cinematic-neon-blue italic">
                                        {formatAmountWithSnapshot(
                                            getOrderGrandTotalSar(order),
                                            displayCurrency,
                                            order,
                                            currency
                                        )}
                                    </span>
                                </div>
                                <div className={cn(
                                    "mt-2 px-4 py-2 rounded-xl text-center text-[10px] font-black uppercase tracking-widest",
                                    order.paymentStatus === 'paid'
                                        ? "bg-green-400/10 text-green-400 border border-green-400/20"
                                        : "bg-cinematic-neon-yellow/10 text-cinematic-neon-yellow border border-cinematic-neon-yellow/20"
                                )}>
                                    {order.paymentStatus === 'paid'
                                        ? (isRTL ? '✓ تم الدفع' : '✓ PAID')
                                        : (isRTL ? 'في انتظار الدفع' : 'PAYMENT PENDING')
                                    }
                                </div>
                            </div>
                        </div>

                        {/* Contact */}
                        {order.buyer && (
                            <div className="glass-card p-8 bg-white/[0.01] border-white/5">
                                <div className="flex items-center gap-3 mb-6">
                                    <Phone className="w-5 h-5 text-cinematic-neon-blue" />
                                    <h3 className="text-[11px] font-black uppercase tracking-[0.4em] text-white">
                                        {isRTL ? 'بيانات التواصل' : 'CONTACT'}
                                    </h3>
                                </div>
                                <div className="space-y-4 text-sm">
                                    <div className="flex items-center gap-3">
                                        <Mail className="w-4 h-4 text-white/30 shrink-0" />
                                        <span className="text-white/70 font-bold truncate">{order.buyer.email}</span>
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <Phone className="w-4 h-4 text-white/30 shrink-0" />
                                        <span className="text-white/70 font-bold">{order.buyer.phone}</span>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* [[ARABIC_COMMENT]] زر التواصل عبر واتساب - يستخدم الرقم المحفوظ في الإعدادات */}
                        <a
                            href={`https://wa.me/${(socialLinks?.whatsapp || '966500000000').replace(/\D/g, '')}?text=${encodeURIComponent(
                                `طلب رقم: ${order.orderNumber}\nالسيارة: ${order.car?.title || ''}\nالمبلغ: ${formatAmountWithSnapshot(getOrderGrandTotalSar(order), displayCurrency, order, currency)}\n\nأرجو إرسال الفاتورة.`
                            )}`}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            <motion.button
                                whileHover={{ scale: 1.03 }}
                                whileTap={{ scale: 0.97 }}
                                className="w-full py-4 bg-green-500/10 border border-green-500/30 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] text-green-400 hover:bg-green-500/20 flex items-center justify-center gap-3 transition-all"
                            >
                                💬 {isRTL ? 'طلب الفاتورة عبر واتساب' : 'REQUEST INVOICE VIA WHATSAPP'}
                            </motion.button>
                        </a>
                    </motion.div>

                </div>

                {/* Timeline */}
                {order.timeline && order.timeline.length > 0 && (
                    <motion.div
                        initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}
                        className="glass-card p-8 md:p-12 bg-white/[0.01] border-white/5 mt-8"
                    >
                        <h2 className="text-[11px] font-black uppercase tracking-[0.5em] text-white/60 mb-8 flex items-center gap-3">
                            <Clock className="w-5 h-5 text-cinematic-neon-yellow" />
                            {isRTL ? 'سجل الطلب' : 'ORDER TIMELINE'}
                        </h2>
                        <div className="space-y-6">
                            {[...order.timeline].reverse().map((event: any, i: number) => (
                                <motion.div
                                    key={i}
                                    initial={{ opacity: 0, x: isRTL ? 20 : -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: i * 0.1 }}
                                    className="flex items-start gap-5"
                                >
                                    <div className={cn(
                                        "w-3 h-3 rounded-full mt-1.5 shrink-0",
                                        i === 0 ? "bg-cinematic-neon-blue shadow-[0_0_10px_rgba(0,240,255,0.8)]" : "bg-white/20"
                                    )} />
                                    <div className="flex-1">
                                        <div className="flex items-center justify-between gap-4 flex-wrap">
                                            <span className={cn(
                                                "text-[11px] font-black uppercase tracking-widest",
                                                i === 0 ? getStatusColor(event.status) : "text-white/40"
                                            )}>
                                                {isRTL
                                                    ? STATUS_STEPS.find(s => s.key === event.status)?.labelAr || event.status
                                                    : STATUS_STEPS.find(s => s.key === event.status)?.labelEn || event.status
                                                }
                                            </span>
                                            <span className="text-[10px] text-white/30 font-bold">
                                                {new Date(event.date).toLocaleString(isRTL ? 'ar-SA' : 'en-US', {
