                                                })}
                                            </span>
                                        </div>
                                        {event.note && (
                                            <p className="text-[11px] text-white/50 mt-1">{event.note}</p>
                                        )}
                                    </div>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}

            </main>
        </div>
    );
}

'use client';

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect } from "react";
import { Package, Clock, CheckCircle, XCircle, Eye, Download } from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { api } from "@/lib/api";
import Link from "next/link";
import ClientPageHeader from "@/components/ClientPageHeader";
import { useSettings } from "@/lib/SettingsContext";
import { formatAmountWithSnapshot, getOrderGrandTotalSar } from "@/lib/orderCurrency";

export default function OrdersPage() {
    const { isRTL } = useLanguage();
    const { displayCurrency, currency } = useSettings();
    type OrderStatus = 'pending' | 'confirmed' | 'completed' | 'cancelled' | string;
    interface OrderCar {
        title?: string;
        image?: string;
        images?: string[];
    }
    interface OrderPricing {
        grandTotalSar?: number;
        exchangeSnapshot?: { usdToSar?: number; usdToKrw?: number; activeCurrency?: string };
    }
    interface Order {
        id?: string;
        _id?: string;
        orderNumber?: string;
        status?: OrderStatus;
        createdAt?: string;
        car?: OrderCar;
        pricing?: OrderPricing;
        totalAmount?: number;
    }

    const [orders, setOrders] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('all');
    const [imageErrors, setImageErrors] = useState<Record<string, boolean>>({});
    const [stats, setStats] = useState({
        total: 0,
        pending: 0,
        confirmed: 0,
        completed: 0,
        cancelled: 0
    });

    useEffect(() => {
        loadOrders();
    }, [filter]);

    const loadOrders = async () => {
        try {
            setLoading(true);
            const params = filter !== 'all' ? { status: filter } : {};
            const response = await api.orders.list(params);

            if (response.success) {
                setOrders(response.data.orders);

                // [[ARABIC_COMMENT]] حساب الإحصائيات من الطلبات الحقيقية
                const allOrders = response.data.orders as Order[];
                setStats({
                    total: allOrders.length,
                    pending: allOrders.filter((o) => o.status === 'pending').length,
                    confirmed: allOrders.filter((o) => o.status === 'confirmed').length,
                    completed: allOrders.filter((o) => o.status === 'completed').length,
                    cancelled: allOrders.filter((o) => o.status === 'cancelled').length,
                });
            }
        } catch (err) {
            // [[ARABIC_COMMENT]] عند الخطأ: لا نعرض بيانات وهمية - نترك القائمة فارغة
            console.error('Failed to load orders', err);
            setOrders([]);
            setStats({ total: 0, pending: 0, confirmed: 0, completed: 0, cancelled: 0 });
        } finally {
            setLoading(false);
        }
    };

    const resolveOrderId = (order: Order, index: number) => (
        order.id || order._id || order.orderNumber || `order-${index}`
    );

    const resolveOrderImage = (order: Order) => {
        const src = order.car?.image || order.car?.images?.[0] || '';
        return typeof src === 'string' ? src.trim() : '';
    };


    const getStatusColor = (status?: string) => {
        switch (status) {
            case 'pending': return 'text-cinematic-neon-yellow';
            case 'confirmed': return 'text-cinematic-neon-blue';
            case 'completed': return 'text-green-400';
            case 'cancelled': return 'text-cinematic-neon-red';
            default: return 'text-white/60';
        }
    };

    const getStatusBg = (status?: string) => {
        switch (status) {
            case 'pending': return 'bg-cinematic-neon-yellow/10 border-cinematic-neon-yellow/30';
            case 'confirmed': return 'bg-cinematic-neon-blue/10 border-cinematic-neon-blue/30';
            case 'completed': return 'bg-green-400/10 border-green-400/30';
            case 'cancelled': return 'bg-cinematic-neon-red/10 border-cinematic-neon-red/30';
            default: return 'bg-white/5 border-white/10';
        }
    };

    const getStatusIcon = (status?: string) => {
        switch (status) {
            case 'pending': return Clock;
            case 'confirmed': return CheckCircle;
            case 'completed': return CheckCircle;
            case 'cancelled': return XCircle;
            default: return Package;
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
                <div className="text-white text-xl animate-pulse">Loading...</div>
            </div>
        );
    }

    return (
        <div className="relative min-h-screen bg-black text-white font-sans overflow-hidden">
            <Navbar />

            {/* Background HUD */}
            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-cinematic-neon-blue/5 via-black to-black opacity-40" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(0,240,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(0,240,255,0.02)_1px,transparent_1px)] bg-[size:100px_100px] opacity-20" />
            </div>

            <main className="relative z-10 pt-32 pb-24 px-6 max-w-7xl mx-auto">



                <header className="mb-12">
                    <ClientPageHeader
                        title={isRTL ? 'طلباتي' : 'MY ORDERS'}
                        subtitle={isRTL ? 'تتبع الطلبات' : 'Order Tracking'}
                        icon={Package}
                    />
                    <p className="text-[11px] text-white/40 uppercase tracking-[0.3em] font-bold max-w-2xl leading-relaxed mt-4 ml-2">
                        {isRTL ? 'تتبع ومراقبة جميع طلباتك وحالة التسليم' : 'TRACK AND MONITOR ALL YOUR ORDERS AND DELIVERY STATUS'}
                    </p>
                </header>

                {/* Stats */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-12">
                    {[
                        { label: isRTL ? 'الكل' : 'ALL', value: stats.total, key: 'all', color: 'text-white' },
                        { label: isRTL ? 'قيد الانتظار' : 'PENDING', value: stats.pending, key: 'pending', color: 'text-cinematic-neon-yellow' },
                        { label: isRTL ? 'مؤكد' : 'CONFIRMED', value: stats.confirmed, key: 'confirmed', color: 'text-cinematic-neon-blue' },
                        { label: isRTL ? 'مكتمل' : 'COMPLETED', value: stats.completed, key: 'completed', color: 'text-green-400' },
                        { label: isRTL ? 'ملغي' : 'CANCELLED', value: stats.cancelled, key: 'cancelled', color: 'text-cinematic-neon-red' },
                    ].map((stat, i) => (
                        <motion.button
                            key={stat.key}
                            onClick={() => setFilter(stat.key)}
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                            className={cn(
                                "glass-card p-6 bg-white/[0.01] border-white/5 text-center transition-all",
                                filter === stat.key && "border-cinematic-neon-blue/30 bg-cinematic-neon-blue/5"
                            )}
                        >
                            <div className={cn("text-3xl font-black tracking-tighter mb-2", stat.color)}>{stat.value}</div>
                            <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/60">{stat.label}</div>
                        </motion.button>
                    ))}
                </div>

                {/* Orders List */}
                <AnimatePresence mode="popLayout">
                    {orders.length === 0 ? (
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="text-center py-32"
                        >
                            <Package className="w-24 h-24 text-white/10 mx-auto mb-8" />
                            <h3 className="text-2xl font-black uppercase tracking-tight mb-4 text-white/60">
                                {isRTL ? 'لا توجد طلبات' : 'NO ORDERS FOUND'}
                            </h3>
                            <p className="text-sm text-white/40">
                                {isRTL ? 'لم تقم بأي طلبات بعد' : 'You haven\'t placed any orders yet'}
                            </p>
                        </motion.div>
                    ) : (
                        <div className="space-y-6">
                            {orders.map((order, i) => {
                                const StatusIcon = getStatusIcon(order.status);
                                const orderId = resolveOrderId(order, i);
                                const imageSrc = resolveOrderImage(order);
                                const showFallback = !imageSrc || imageErrors[orderId];
                                return (
                                    <motion.div
                                        key={orderId}
                                        layout
                                        initial={{ opacity: 0, y: 20 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: -20 }}
                                        transition={{ delay: i * 0.1 }}
                                        className="glass-card bg-white/[0.01] border-white/5 overflow-hidden hover:border-cinematic-neon-blue/30 transition-all"
                                    >
                                        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 p-8">

                                            {/* Car Image */}
                                            <div className="lg:col-span-3">
                                                <div className="relative h-40 rounded-2xl overflow-hidden">
                                                    {showFallback ? (
                                                        <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-white/5 via-black/40 to-black/70 border border-white/10">
                                                            <div className="text-center">
                                                                <Package className="w-10 h-10 text-white/20 mx-auto mb-2" />
                                                                <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/30">No Image</div>
                                                            </div>
                                                        </div>
                                                    ) : (
                                                        <img
                                                            src={imageSrc}
                                                            alt={order.car?.title || 'Order car'}
                                                            className="w-full h-full object-cover grayscale-[30%] hover:grayscale-0 transition-all duration-700"
                                                            onError={() => setImageErrors(prev => ({ ...prev, [orderId]: true }))}
                                                        />
                                                    )}
                                                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                                                </div>
                                            </div>

                                            {/* Order Details */}
                                            <div className="lg:col-span-6 space-y-4">
                                                <div>
                                                    <div className="text-[9px] font-black text-cinematic-neon-blue/80 uppercase tracking-[0.3em] mb-2">
                                                        {order.orderNumber}
                                                    </div>
                                                    <h3 className="text-2xl font-black uppercase italic tracking-tighter leading-tight">
                                                        {order.car?.title || (isRTL ? 'سيارة' : 'Vehicle')}
                                                    </h3>
                                                </div>

                                                <div className="flex items-center gap-6">
                                                    <div>
                                                        <div className="text-[8px] font-black text-white/20 uppercase tracking-widest mb-1">
                                                            {isRTL ? 'المبلغ الإجمالي' : 'TOTAL AMOUNT'}
                                                        </div>
                                                        <div className="text-xl font-black text-cinematic-neon-blue italic">
                                                            {formatAmountWithSnapshot(
                                                                getOrderGrandTotalSar(order),
                                                                displayCurrency,
                                                                order,
                                                                currency
                                                            )}
                                                        </div>
                                                    </div>
                                                    <div className="h-8 w-[1px] bg-white/10" />
                                                    <div>
                                                        <div className="text-[8px] font-black text-white/20 uppercase tracking-widest mb-1">
                                                            {isRTL ? 'تاريخ الطلب' : 'ORDER DATE'}
                                                        </div>
                                                        <div className="text-sm font-bold text-white/60">
                                                            {order.createdAt ? new Date(order.createdAt).toLocaleDateString('en-US', {
                                                                month: 'short',
                                                                day: 'numeric',
                                                                year: 'numeric'
                                                            }) : 'N/A'}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Status & Actions */}
                                            <div className="lg:col-span-3 flex flex-col justify-between gap-4">
                                                <div className={cn(
                                                    "px-6 py-4 rounded-xl border flex items-center gap-3",
                                                    getStatusBg(order.status)
                                                )}>
                                                    <StatusIcon className={cn("w-5 h-5", getStatusColor(order.status))} />
                                                    <div>
                                                        <div className="text-[8px] font-black text-white/40 uppercase tracking-widest">{isRTL ? 'الحالة' : 'STATUS'}</div>
                                                        <div className={cn("text-sm font-black uppercase tracking-wide", getStatusColor(order.status))}>
                                                            {isRTL ?
                                                                (order.status === 'pending' ? 'قيد الانتظار' :
                                                                    order.status === 'confirmed' ? 'مؤكد' :
                                                                        order.status === 'completed' ? 'مكتمل' :
                                                                            order.status === 'cancelled' ? 'ملغي' : order.status)
                                                                : order.status}
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="grid grid-cols-2 gap-3">
                                                    <Link href={`/orders/${order.id}`}>
                                                        <motion.button
                                                            whileHover={{ scale: 1.05 }}
                                                            whileTap={{ scale: 0.95 }}
                                                            className="w-full py-3 bg-cinematic-neon-blue/10 border border-cinematic-neon-blue/30 text-cinematic-neon-blue rounded-xl text-[10px] font-black uppercase tracking-wide flex items-center justify-center gap-2 hover:bg-cinematic-neon-blue/20 transition-all"
                                                        >
                                                            <Eye className="w-4 h-4" />
                                                            {isRTL ? 'عرض' : 'VIEW'}
                                                        </motion.button>
                                                    </Link>
                                                    <Link href={`/orders/${order.id}/invoice`}>
                                                        <motion.button
                                                            whileHover={{ scale: 1.05 }}
                                                            whileTap={{ scale: 0.95 }}
                                                            className="w-full py-3 bg-white/5 border border-white/10 text-white/60 rounded-xl text-[10px] font-black uppercase tracking-wide flex items-center justify-center gap-2 hover:bg-yellow-500/10 hover:border-yellow-500/30 hover:text-yellow-400 transition-all"
                                                        >
                                                            <Download className="w-4 h-4" />
                                                            {isRTL ? 'فاتورة' : 'INVOICE'}
                                                        </motion.button>
                                                    </Link>
                                                </div>
                                            </div>

                                        </div>
                                    </motion.div>
                                );
                            })}
                        </div>
                    )}
                </AnimatePresence>

            </main>
        </div>
    );
}

import HomeClient, { type CarType } from "./home-client";

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:4002";

async function getLatestCars(): Promise<CarType[]> {
  try {
    // [[ARABIC_COMMENT]] بدلاً من no-store الذي قد يفشل في بعض بيئات الخوادم، نستخدم revalidate لتحديث البيانات كل 15 ثانية
    // استخدام listingType=store لجلب سيارات المعرض فقط
    const res = await fetch(`${API_BASE_URL}/api/v2/cars?limit=10&status=active&listingType=store`, {
      headers: { Accept: "application/json" },
      next: { revalidate: 15 }, // 🚨 يجدث البيانات كل 15 ثانية بدلاً من منع الكاش نهائياً
    });

    if (!res.ok) return [];

    const json = await res.json();
    // API Returns { success: true, data: { cars: [...] } }
    const carsList = json?.data?.cars || json?.cars || [];
    return Array.isArray(carsList) ? carsList : [];
  } catch (error) {
    // Silently fall back when API is unavailable
    return [];
  }
}

export default async function Page() {
  const latestCars = await getLatestCars();
  return <HomeClient latestCars={latestCars} />;
}

'use client';

import { motion } from "framer-motion";
import { useState, useEffect } from "react";
import {
    User,
    Mail,
    Phone,
    Lock,
    Save,
    Edit3,
    Shield,
    Bell,
    CreditCard,
    LogOut,
    ArrowLeft
} from "lucide-react";
import Navbar from "@/components/Navbar";
import { cn } from "@/lib/utils";
import { useLanguage } from "@/lib/LanguageContext";
import { api } from "@/lib/api";
import { useRouter } from "next/navigation";
import Link from "next/link";
import ClientPageHeader from "@/components/ClientPageHeader";

export default function ProfilePage() {
    const { t, isRTL } = useLanguage();
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [userData, setUserData] = useState({
        name: '',
        email: '',
        phone: '',
        role: 'buyer'
    });
    const [passwordData, setPasswordData] = useState({
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
    });

    useEffect(() => {
        // جلب بيانات المستخدم من localStorage
        if (typeof window !== 'undefined') {
            const user = localStorage.getItem('hm_user');
            if (user) {
                try {
                    const data = JSON.parse(user);
                    setUserData({
                        name: data.name || '',
                        email: data.email || '',
                        phone: data.phone || '',
                        role: data.role || 'buyer'
                    });
                } catch (e) {
                    console.error('Error parsing user data', e);
                }
            }
        }
    }, []);

    const handleProfileUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');

        try {
            // Update profile via API
            await api.users.updateProfile(userData);

            // Update localStorage
            const currentUser = JSON.parse(localStorage.getItem('hm_user') || '{}');
            const updatedUser = { ...currentUser, ...userData };
            localStorage.setItem('hm_user', JSON.stringify(updatedUser));

            setMessage(isRTL ? 'تم تحديث البيانات بنجاح' : 'Profile updated successfully');
        } catch (err: any) {
            setMessage(err.message || (isRTL ? 'حدث خطأ' : 'An error occurred'));
        } finally {
            setLoading(false);
        }
    };

    const handlePasswordChange = async (e: React.FormEvent) => {
        e.preventDefault();

        if (passwordData.newPassword !== passwordData.confirmPassword) {
            setMessage(isRTL ? 'كلمات المرور غير متطابقة' : 'Passwords do not match');
            return;
        }

        setLoading(true);
        setMessage('');

        try {
            // تنفيذ طلب تغيير كلمة المرور عبر الـ API
            await api.auth.changePassword({
                currentPassword: passwordData.currentPassword,
                newPassword: passwordData.newPassword
            });

            setMessage(isRTL ? 'تم تغيير كلمة المرور بنجاح' : 'Password changed successfully');
            setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
        } catch (err: any) {
            setMessage(err.message || (isRTL ? 'حدث خطأ في النظام' : 'Protocol error occurred'));
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = () => {
        localStorage.removeItem('hm_token');
        localStorage.removeItem('hm_user');
        router.push('/login');
    };

    return (
        <div className="relative min-h-screen bg-black text-white font-sans overflow-hidden">
            <Navbar />

            {/* Background HUD */}
            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-cinematic-neon-blue/5 via-black to-black opacity-40" />
                <div className="absolute inset-0 bg-[linear-gradient(rgba(0,240,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(0,240,255,0.02)_1px,transparent_1px)] bg-[size:100px_100px] opacity-20" />
            </div>

            <main className="relative z-10 pt-32 pb-24 px-6 max-w-5xl mx-auto">



                {/* Header */}
                <header className="mb-12">
                    <ClientPageHeader
                        title={isRTL ? 'الملف الشخصي' : 'PROFILE SETTINGS'}
                        subtitle={isRTL ? 'إدارة معلوماتك الشخصية وإعدادات الحساب' : 'MANAGE YOUR PERSONAL INFORMATION AND ACCOUNT SETTINGS'}
                        icon={User}
                    />
                </header>

                {/* Message */}
                {message && (
                    <motion.div
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="mb-8 p-6 bg-cinematic-neon-blue/10 border border-cinematic-neon-blue/30 rounded-2xl text-center"
                    >
                        <p className="text-sm font-bold text-cinematic-neon-blue">{message}</p>
                    </motion.div>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                    {/* Sidebar */}
                    <div className="space-y-6">
                        {/* Profile Card */}
                        <div className="glass-card p-8 bg-white/[0.01] border-white/5 text-center space-y-6 relative overflow-hidden group">
                            <div className="absolute inset-0 bg-luxury-gold/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity duration-700" />
                            <div className="w-24 h-24 mx-auto rounded-full bg-cinematic-neon-blue/10 border-2 border-cinematic-neon-blue/30 flex items-center justify-center shadow-[0_0_30px_rgba(0,240,255,0.2)]">
                                <User className="w-12 h-12 text-cinematic-neon-blue" />
                            </div>
                            <div>
                                <h3 className="text-xl font-black uppercase italic tracking-tight mb-2">{userData.name}</h3>
                                <div className="text-[10px] text-white/40 uppercase tracking-[0.3em] font-bold">{userData.role}</div>
                            </div>
                        </div>

                        {/* Quick Links (hidden for now) */}
                        <div className="hidden" />
                    </div>

                    {/* Main Content */}
                    <div className="lg:col-span-2 space-y-8">

                        {/* Personal Information */}
                        <div className="glass-card p-10 bg-white/[0.01] border-white/5">
                            <div className="flex items-center gap-4 mb-8">
                                <Edit3 className="w-6 h-6 text-cinematic-neon-blue" />
                                <h2 className="text-[11px] font-black uppercase tracking-[0.6em] text-white">
                                    {isRTL ? 'المعلومات الشخصية' : 'PERSONAL INFORMATION'}
                                </h2>
                            </div>

                            <form onSubmit={handleProfileUpdate} className="space-y-6">
                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'الاسم' : 'Full Name'}
                                    </label>
                                    <div className="relative">
                                        <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="text"
                                            value={userData.name}
                                            onChange={(e) => setUserData({ ...userData, name: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-blue/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'البريد الإلكتروني' : 'Email Address'}
                                    </label>
                                    <div className="relative">
                                        <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="email"
                                            value={userData.email}
                                            onChange={(e) => setUserData({ ...userData, email: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-blue/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'رقم الهاتف' : 'Phone Number'}
                                    </label>
                                    <div className="relative">
                                        <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="tel"
                                            value={userData.phone}
                                            onChange={(e) => setUserData({ ...userData, phone: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-blue/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <motion.button
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                    type="submit"
                                    disabled={loading}
                                    className="w-full py-5 bg-cinematic-neon-blue text-black font-black uppercase text-[11px] tracking-[0.3em] rounded-xl shadow-[0_0_30px_rgba(0,240,255,0.3)] hover:shadow-[0_0_50px_rgba(0,240,255,0.5)] transition-all disabled:opacity-50 flex items-center justify-center gap-3"
                                >
                                    <Save className="w-5 h-5" />
                                    {loading ? (isRTL ? 'جاري الحفظ...' : 'SAVING...') : (isRTL ? 'حفظ التغييرات' : 'SAVE CHANGES')}
                                </motion.button>
                            </form>
                        </div>

                        {/* Change Password */}
                        <div className="glass-card p-10 bg-white/[0.01] border-white/5">
                            <div className="flex items-center gap-4 mb-8">
                                <Shield className="w-6 h-6 text-cinematic-neon-red" />
                                <h2 className="text-[11px] font-black uppercase tracking-[0.6em] text-white">
                                    {isRTL ? 'تغيير كلمة المرور' : 'CHANGE PASSWORD'}
                                </h2>
                            </div>

                            <form onSubmit={handlePasswordChange} className="space-y-6">
                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'كلمة المرور الحالية' : 'Current Password'}
                                    </label>
                                    <div className="relative">
                                        <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="password"
                                            value={passwordData.currentPassword}
                                            onChange={(e) => setPasswordData({ ...passwordData, currentPassword: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-red/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'كلمة المرور الجديدة' : 'New Password'}
                                    </label>
                                    <div className="relative">
                                        <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="password"
                                            value={passwordData.newPassword}
                                            onChange={(e) => setPasswordData({ ...passwordData, newPassword: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-red/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-[10px] font-black uppercase tracking-[0.3em] text-white/60 mb-3">
                                        {isRTL ? 'تأكيد كلمة المرور' : 'Confirm Password'}
                                    </label>
                                    <div className="relative">
                                        <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20" />
                                        <input
                                            type="password"
                                            value={passwordData.confirmPassword}
                                            onChange={(e) => setPasswordData({ ...passwordData, confirmPassword: e.target.value })}
                                            className="w-full bg-white/[0.03] border border-white/10 rounded-xl py-4 pl-12 pr-4 text-sm font-bold text-white focus:outline-none focus:border-cinematic-neon-red/40 transition-all"
                                        />
                                    </div>
                                </div>

                                <motion.button
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                    type="submit"
                                    disabled={loading}
                                    className="w-full py-5 bg-cinematic-neon-red text-white font-black uppercase text-[11px] tracking-[0.3em] rounded-xl shadow-[0_0_30px_rgba(255,0,60,0.3)] hover:shadow-[0_0_50px_rgba(255,0,60,0.5)] transition-all disabled:opacity-50 flex items-center justify-center gap-3"
                                >
                                    <Lock className="w-5 h-5" />
                                    {loading ? (isRTL ? 'جاري التحديث...' : 'UPDATING...') : (isRTL ? 'تحديث كلمة المرور' : 'UPDATE PASSWORD')}
                                </motion.button>
                            </form>
                        </div>

                    </div>
                </div>

            </main>
        </div>
    );
}

'use client';

import { Suspense, useEffect, useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { Mail, Search, Gavel, Cog, Info, User, LogOut, Menu, X, Tag, AlertCircle, ArrowRight, ShoppingBag, Sparkles } from "lucide-react";
import Link from 'next/link';
import ClientPageHeader from '@/components/ClientPageHeader';
import Navbar from '@/components/Navbar';
import { api } from '@/lib/api';
import { cn } from '@/lib/utils';
import { useLanguage } from '@/lib/LanguageContext';
import { useSettings } from '@/lib/SettingsContext';

export default function SearchPage() {
    return (
        <Suspense fallback={<div className="min-h-screen bg-black text-white flex items-center justify-center font-black uppercase tracking-[0.5em] italic animate-pulse">Synchronizing Matrix...</div>}>
            <SearchContent />
        </Suspense>
    );
}

function SearchContent() {
    const searchParams = useSearchParams();
    const q = searchParams.get('q') || '';
    const brand = searchParams.get('brand') || '';
    const price = searchParams.get('price') || '';
    const router = useRouter();
    const { isRTL } = useLanguage();
    const { formatPrice } = useSettings();

    const [cars, setCars] = useState<any[]>([]);
    const [parts, setParts] = useState<any[]>([]);
    const [brands, setBrands] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [hasResults, setHasResults] = useState(false);

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            try {
                // Fetch brands for the filter bar
                const brandsRes = await api.brands.list().catch(() => ({ brands: [] }));
                setBrands(brandsRes?.brands || []);

                let minPrice = undefined;
                let maxPrice = undefined;
                if (price === '0-100' || price === '0-100k') { maxPrice = 100000; }
                else if (price === '100-300' || price === '100-500k') { minPrice = 100000; maxPrice = 500000; }
                else if (price === '300+' || price === '500k+') { minPrice = 500000; }

                // [[ARABIC_COMMENT]] api.cars.list يرجع { success, data: { cars, pagination } }
                const carsRes = await api.cars.list({
                    page: 1,
                    limit: 100,
                    search: q,
                    make: brand || '',
                    minPrice: minPrice?.toString() ?? '',
                    maxPrice: maxPrice?.toString() ?? ''
                }).catch(() => ({ data: { cars: [] } }));

                // [[ARABIC_COMMENT]] api.parts.list يرجع { success, data: { parts } }
                const partsRes = await api.parts.list({
                    page: 1,
                    limit: 100,
                    q: q,
                    category: brand !== '' ? brand : undefined
                }).catch(() => ({ data: { parts: [] } }));

                // [[ARABIC_COMMENT]] استخراج البيانات من المستوى الصحيح
                const fetchedCars = carsRes?.data?.cars || [];
                const fetchedParts = partsRes?.data?.parts || [];

                setCars(fetchedCars);
                setParts(fetchedParts);
                setHasResults(fetchedCars.length > 0 || fetchedParts.length > 0);

            } catch (err) {
                console.error("Search failed", err);
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [q, brand, price]);


    const handleConciergeRequest = () => {
        router.push('/concierge');
    };

    return (
        <div className="min-h-screen bg-black text-white selection:bg-luxury-gold selection:text-black font-sans perspective-1000 overflow-x-hidden">
            <Navbar />

            <div className="bg-grid-overlay opacity-20 fixed inset-0 z-0" />
            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-x-0 top-0 h-[800px] bg-gradient-to-b from-luxury-gold/5 via-transparent to-transparent opacity-60" />
            </div>

            <main className="relative z-10 pt-40 pb-32 px-6 max-w-[1800px] mx-auto">

                <ClientPageHeader
                    title={q || brand ? (
                        <span className="flex flex-col md:flex-row md:gap-3">{isRTL ? "نتائج" : "RESULT"} <span className="text-luxury-gold">{isRTL ? "البحث" : "STREAM"}</span></span>
                    ) : (
                        <span className="flex flex-col md:flex-row md:gap-3">{isRTL ? "المخزون" : "GLOBAL"} <span className="text-luxury-gold">{isRTL ? "الشامل" : "INVENTORY"}</span></span>
                    )}
                    subtitle={loading ? (isRTL ? "جاري المسح..." : "SCANNING MATRIX...") : `${cars.length + parts.length} ${isRTL ? "أصل متاح" : "IDENTIFIED ASSETS"}`}
                    icon={Search}
                />

                {/* Agencies / Brands Filter Bar */}
                {brands.length > 0 && (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="mb-16 pb-8 border-b border-white/5 scrollbar-hide overflow-x-auto flex gap-6 items-center px-2"
                    >
                        <Link
                            href="/search"
                            className={cn(
                                "shrink-0 px-6 py-3 rounded-full border text-[10px] font-black uppercase tracking-widest transition-all",
                                !brand ? "bg-luxury-gold text-black border-luxury-gold shadow-[0_0_20px_rgba(197,160,89,0.3)]" : "bg-white/5 border-white/10 text-white/40 hover:text-white"
                            )}
                        >
                            {isRTL ? "الكل" : "ALL"}
                        </Link>
                        {brands.map((b, i) => (
                            <Link
                                key={i}
                                href={`/search?brand=${b.name}${q ? `&q=${q}` : ''}`}
                                className={cn(
                                    "shrink-0 flex items-center gap-3 px-5 py-3 rounded-2xl border transition-all group",
                                    brand === b.name
                                        ? "bg-luxury-gold/10 border-luxury-gold text-luxury-gold shadow-[0_0_20px_rgba(197,160,89,0.1)]"
                                        : "bg-white/[0.02] border-white/5 text-white/30 hover:border-white/20 hover:text-white"
                                )}
                            >
                                {b.logoUrl ? (
                                    <img src={b.logoUrl} alt={b.name} className={cn("w-5 h-5 object-contain", brand === b.name ? "grayscale-0" : "grayscale")} />
                                ) : <Tag className="w-3 h-3" />}
                                <span className="text-[10px] font-black uppercase tracking-widest">{b.name}</span>
                            </Link>
                        ))}
                    </motion.div>
                )}

                {q && (
                    <div className="mb-20">
                        <span className="text-6xl md:text-8xl font-black italic text-transparent bg-clip-text bg-gradient-to-b from-white to-white/10 tracking-tighter opacity-50">&quot;{q.toUpperCase()}&quot;</span>
                    </div>
                )}

                {loading ? (
                    <div className="py-48 flex flex-col items-center justify-center space-y-12">
                        <div className="relative w-24 h-24 perspective-500">
                            <motion.div
                                animate={{ rotateX: 360, rotateY: 360 }}
                                transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                                className="absolute inset-0 border-4 border-luxury-gold/20 rounded-full border-t-luxury-gold shadow-[0_0_30px_rgba(197,160,89,0.2)]"
                            />
                        </div>
                        <span className="text-[10px] font-black uppercase tracking-[0.8em] animate-pulse text-white/40">Synchronizing Global Database...</span>
                    </div>
                ) : (
                    <div className="space-y-48">

                        {/* No Findings Module */}
                        {!hasResults && (
                            <motion.div
                                initial={{ opacity: 0, scale: 0.98 }}
                                animate={{ opacity: 1, scale: 1 }}
                                className="obsidian-card p-12 md:p-32 text-center relative overflow-hidden group border-dashed border-white/10"
                            >
                                <div className="absolute inset-0 bg-gradient-to-br from-luxury-gold/5 via-transparent to-transparent opacity-50" />
                                <div className="relative z-10 flex flex-col items-center gap-12 max-w-2xl mx-auto">
                                    <div className="w-32 h-32 rounded-full bg-white/5 border border-white/10 flex items-center justify-center group-hover:bg-luxury-gold/10 transition-all duration-700 shadow-2xl">
                                        <AlertCircle className="w-12 h-12 text-luxury-gold/40" />
                                    </div>
                                    <div className="space-y-6">
                                        <h2 className="text-4xl md:text-6xl font-black uppercase italic tracking-tighter gold-glow">
                                            {isRTL ? "لم يتم العثور على تطابق" : "ZERO MATCHES"}
                                        </h2>
                                        <p className="text-[11px] text-white/40 font-black uppercase tracking-[0.4em] leading-loose italic max-w-lg mx-auto">
                                            {isRTL
                                                ? "لم نجد طلبك في المخزون المباشر. كحل بديل، يمكن لفريقنا العالمي توفيره لك."
                                                : "The current stream yielded no results. Our acquisition specialists can manually source this from the dark network."}
                                        </p>
                                    </div>

                                    <div className="flex flex-col sm:flex-row gap-8 mt-12 w-full max-w-lg">
                                        <button
                                            onClick={handleConciergeRequest}
                                            className="btn-luxury flex-1 py-6 rounded-2xl group"
                                        >
                                            <span>{isRTL ? "خدمة الطلبات الخاصة" : "ACTIVATE CONCIERGE"}</span>
                                            <ArrowRight className={cn("w-5 h-5 transition-transform group-hover:translate-x-1", isRTL && "rotate-180")} />
                                        </button>
                                        <Link href="/" className="flex-1">
                                            <button className="w-full py-6 rounded-2xl border border-white/10 hover:bg-white/5 hover:border-white/20 transition-all text-xs font-black uppercase tracking-widest text-white/60 hover:text-white">
                                                {isRTL ? "العودة للمركز" : "EXIT TERMINAL"}
                                            </button>
                                        </Link>
                                    </div>
                                </div>
                            </motion.div>
                        )}

                        {/* Cars Matrix */}
                        {cars.length > 0 && (
                            <section className="space-y-16">
                                <div className="flex items-end justify-between border-b border-white/5 pb-8 relative">
                                    <div className="absolute bottom-0 left-0 w-32 h-[1px] bg-luxury-gold/50" />
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-2 h-2 rounded-full bg-cinematic-neon-blue animate-pulse" />
                                            <span className="text-[10px] font-black uppercase tracking-[0.5em] text-cinematic-neon-blue">Vehicle Data</span>
                                        </div>
                                        <h2 className="text-4xl md:text-6xl font-black uppercase italic tracking-tighter">IDENTIFIED <span className="text-white/20">MACHINERY</span></h2>
                                    </div>
                                    <span className="text-[10px] font-black text-white/20 uppercase tracking-widest italic">{cars.length} UNITS</span>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                                    {cars.map((car, i) => (
                                        <motion.div
                                            key={car.id}
                                            initial={{ opacity: 0, y: 50 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            transition={{ delay: i * 0.1 }}
                                            className="group obsidian-card obsidian-card-hover"
                                        >
                                            <Link href={`/cars/${car.id || car._id}`}>
                                                <div className="relative h-72 overflow-hidden rounded-t-[2.5rem] bg-black">
                                                    <img src={car.images?.[0] || 'https://images.unsplash.com/photo-1592194996308-7b43878e84a6?q=80&w=1000'} alt={car.title} className="w-full h-full object-cover grayscale transition-all duration-[1.5s] group-hover:grayscale-0 group-hover:scale-110 opacity-70 group-hover:opacity-100" />
                                                    <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90" />
                                                    <div className="absolute bottom-6 left-6 px-4 py-2 bg-black/60 backdrop-blur-xl rounded-full border border-white/10 flex items-center gap-2">
                                                        <span className="w-1.5 h-1.5 rounded-full bg-luxury-gold" />
                                                        <span className="text-[9px] font-black text-white tracking-widest">{car.year}</span>
                                                    </div>
                                                </div>
                                                <div className="p-8 space-y-8 bg-gradient-to-b from-[#0a0a0a] to-[#111]">
                                                    <div className="space-y-3">
                                                        <span className="text-[8px] font-black text-luxury-gold/50 tracking-[0.4em] uppercase italic">{typeof car.make === 'object' ? car.make?.name : car.make}</span>
                                                        <h3 className="text-2xl font-black tracking-tighter uppercase italic line-clamp-2 min-h-[4rem] group-hover:text-luxury-gold transition-colors">{car.title}</h3>
                                                    </div>
                                                    <div className="flex items-center justify-between pt-6 border-t border-white/5">
                                                        <span className="text-xl font-black italic gold-glow">{formatPrice ? formatPrice(Number(car.price || 0)) : `${Number(car.price || 0).toLocaleString()} SAR`}</span>
                                                        <div className="w-10 h-10 rounded-full border border-white/10 flex items-center justify-center group-hover:bg-luxury-gold group-hover:text-black group-hover:border-luxury-gold transition-all">
                                                            <ArrowRight className={cn("w-4 h-4 transition-transform group-hover:-rotate-45", isRTL && "rotate-180")} />
                                                        </div>
                                                    </div>
                                                </div>
                                            </Link>
                                        </motion.div>
                                    ))}
                                </div>
                            </section>
                        )}

                        {/* Parts Index */}
                        {parts.length > 0 && (
                            <section className="space-y-16">
                                <div className="flex items-end justify-between border-b border-white/5 pb-8 relative">
                                    <div className="absolute bottom-0 left-0 w-32 h-[1px] bg-cinematic-neon-yellow/50" />
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-2 h-2 rounded-full bg-cinematic-neon-yellow animate-pulse" />
                                            <span className="text-[10px] font-black uppercase tracking-[0.5em] text-cinematic-neon-yellow">Component Registry</span>
                                        </div>
                                        <h2 className="text-4xl md:text-6xl font-black uppercase italic tracking-tighter">SPARE <span className="text-white/20">LOGS</span></h2>
                                    </div>
                                    <span className="text-[10px] font-black text-white/20 uppercase tracking-widest italic">{parts.length} COMPONENTS</span>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                                    {parts.map((part, i) => (
                                        <motion.div
                                            key={part.id}
                                            initial={{ opacity: 0, y: 50 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            transition={{ delay: i * 0.1 }}
                                            className="group obsidian-card obsidian-card-hover p-6"
                                        >
                                            <Link href={`/parts/${part.id}`}>
                                                <div className="aspect-square bg-white/[0.02] rounded-[2rem] overflow-hidden mb-6 border border-white/5 relative">
                                                    <img src={part.img} alt={part.name} className="w-full h-full object-contain grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 group-hover:scale-110 transition-all duration-700 p-8" />
                                                    <div className="absolute top-4 right-4 text-[9px] font-black uppercase tracking-widest text-white/20 border border-white/10 px-3 py-1 rounded-full">{part.brand}</div>
                                                </div>
                                                <div className="space-y-4">
                                                    <span className="text-[8px] font-black uppercase text-cinematic-neon-yellow tracking-widest block">{part.condition}</span>
                                                    <h3 className="text-lg font-black uppercase italic line-clamp-1 group-hover:text-luxury-gold transition-colors">{part.name}</h3>
                                                    <div className="pt-4 border-t border-white/5 flex justify-between items-center">
                                                        <span className="text-lg font-black italic gold-glow">{formatPrice ? formatPrice(Number(part.price || 0)) : `${Number(part.price || 0).toLocaleString()} SAR`}</span>
                                                        <ShoppingBag className="w-4 h-4 text-white/20 group-hover:text-white transition-colors" />
                                                    </div>
                                                </div>
                                            </Link>
                                        </motion.div>
                                    ))}
                                </div>
                            </section>
                        )}

                        {/* Sourcing Request Matrix */}
                        {hasResults && (
                            <motion.div
                                initial={{ opacity: 0, y: 50 }}
                                whileInView={{ opacity: 1, y: 0 }}
                                viewport={{ once: true }}
                                className="obsidian-card p-12 lg:p-20 overflow-hidden relative group"
                            >
                                <div className="absolute inset-0 bg-gradient-to-br from-luxury-gold/5 via-transparent to-transparent opacity-50" />
                                <div className="relative z-10 flex flex-col lg:flex-row items-center justify-between gap-12">
                                    <div className="space-y-8 text-center lg:text-left">
                                        <div className="flex items-center gap-4 justify-center lg:justify-start">
                                            <div className="w-12 h-12 rounded-full bg-luxury-gold/10 flex items-center justify-center border border-luxury-gold/20">
                                                <Sparkles className="w-6 h-6 text-luxury-gold" />
                                            </div>
                                            <h2 className="text-4xl font-black uppercase italic tracking-tighter">BEYOND THE MATRIX</h2>
                                        </div>
                                        <p className="text-[11px] text-white/40 uppercase tracking-[0.3em] font-bold max-w-2xl leading-[2.2]">
                                            {isRTL
                                                ? "لم تجد ما تبحث عنه بدقة؟ شبكتنا العالمية من الموردين والخبراء جاهزة للانطلاق وتوفير أي مركبة أو قطعة غيار نادرة."
                                                : "Direct results limited? Our global reconnaissance units can traverse multiple networks to identify and source any obscure automotive machinery."
                                            }
                                        </p>
                                    </div>
                                    <button onClick={handleConciergeRequest} className="btn-luxury px-12 py-6 rounded-2xl group shrink-0">
                                        <span>{isRTL ? "تفعيل البحث المتقدم" : "INITIATE SOURCING"}</span>
                                        <ArrowRight className={cn("w-5 h-5 transition-transform group-hover:translate-x-1", isRTL && "rotate-180")} />
                                    </button>
                                </div>
                            </motion.div>
                        )}
                    </div>
                )}

            </main>

            {/* Matrix Data Footer */}
            <div className="fixed bottom-12 right-12 opacity-20 pointer-events-none hidden md:block">
                <div className="text-[8px] font-black uppercase tracking-[1em] italic text-right">
                    HM SCANNER SYSTEM v4.0.5 <br />
                    ENCRYPTED BROADCAST
                </div>
            </div>
        </div>
    );
}

'use client';

/**
 * صفحة تفاصيل السيارة في المعرض
 * تُعرض عند الضغط على أي سيارة في المعرض أو الصفحة الرئيسية
 * تحتوي على صور، المواصفات الكاملة، وزر طلب الشراء عبر الواتساب
 */

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import {
    ChevronLeft, MessageCircle, Fuel, Gauge, Settings2,
    Calendar, Car, Tag, CheckCircle, AlertCircle, Image as ImageIcon
} from 'lucide-react';
import Navbar from '@/components/Navbar';
import Image from 'next/image';
import { api } from '@/lib/api';
import { useLanguage } from '@/lib/LanguageContext';
import { useSettings } from '@/lib/SettingsContext';
import { cn } from '@/lib/utils';

const toFiniteNumber = (value: unknown): number | null => {
    const num = Number(value);
    return Number.isFinite(num) ? num : null;
};

export default function ShowroomCarDetail() {
    const { id } = useParams();
    const router = useRouter();
    const { isRTL } = useLanguage();
    const { formatPrice, formatPriceFromUsd, currency } = useSettings();

    // حالة البيانات
    const [car, setCar] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeImage, setActiveImage] = useState(0);
    const [whatsapp, setWhatsapp] = useState('');
    const [showInvoice, setShowInvoice] = useState(false);

    // جلب بيانات السيارة من الـ API
    useEffect(() => {
        const loadCar = async () => {
            try {
                setLoading(true);
                const res = await api.cars.getById(id as string);
                if (res?.success && res.data) {
                    setCar(res.data);
                } else {
                    setError(isRTL ? 'لم يتم العثور على السيارة' : 'Car not found');
                }
            } catch (err) {
                console.error('Failed to load car:', err);
                setError(isRTL ? 'حدث خطأ في تحميل البيانات' : 'Failed to load car data');
            } finally {
                setLoading(false);
            }
        };
        if (id) loadCar();
    }, [id, isRTL]);

    // جلب رقم الواتساب من الإعدادات العامة
    useEffect(() => {
        api.settings.getPublic().then((res: any) => {
            if (res?.success && res.data?.socialLinks?.whatsapp) {
                setWhatsapp(res.data.socialLinks.whatsapp);
            } else {
                // [[ARABIC_COMMENT]] استخدم الرقم الكوري الافتراضي إذا لم يُعيّن الأدمن رقماً
                setWhatsapp('+821080880014');
            }
        }).catch(() => {
            setWhatsapp('+821080880014');
        });
    }, []);

    // إرسال رسالة واتساب مع فاتورة السيارة
    const handleWhatsappPurchase = () => {
        if (!car) return;
        const carMake = typeof car.make === 'object' ? car.make?.name : car.make;
        const baseUsd = getBaseUsd(car);
        const price = formatPriceFromUsd
            ? formatPriceFromUsd(baseUsd)
            : (formatPrice ? formatPrice(Number(car.priceSar || car.price || 0)) : `${Number(car.priceSar || car.price || 0).toLocaleString()} SAR`);

        // [[ARABIC_COMMENT]] بناء رسالة الواتساب مع كل تفاصيل السيارة
        const msg = isRTL
            ? `السلام عليكم،\n\n📋 *طلب شراء سيارة من المعرض*\n\n🚗 *معلومات السيارة:*\n• الاسم: ${car.title}\n• الماركة: ${carMake}\n• الموديل: ${car.model}\n• السنة: ${car.year}\n• اللون: ${car.color || 'غير محدد'}\n• المسافة: ${car.mileage ? car.mileage.toLocaleString() + ' كم' : 'غير محدد'}\n• نوع الوقود: ${car.fuelType || 'غير محدد'}\n• ناقل الحركة: ${car.transmission || 'غير محدد'}\n\n💰 *السعر: ${price}*\n\nأرجو التواصل معي للاستفسار عن هذه السيارة.`
            : `Hello,\n\n📋 *Car Purchase Request from Showroom*\n\n🚗 *Car Details:*\n• Name: ${car.title}\n• Make: ${carMake}\n• Model: ${car.model}\n• Year: ${car.year}\n• Color: ${car.color || 'N/A'}\n• Mileage: ${car.mileage ? car.mileage.toLocaleString() + ' km' : 'N/A'}\n• Fuel: ${car.fuelType || 'N/A'}\n• Transmission: ${car.transmission || 'N/A'}\n\n💰 *Price: ${price}*\n\nPlease contact me regarding this vehicle.`;

        // [[ARABIC_COMMENT]] استخدم الرقم المحفوظ أو الافتراضي - دائماً يعمل
        const phone = String(whatsapp || '+821080880014').replace(/\D/g, '');
        window.open(`https://wa.me/${phone}?text=${encodeURIComponent(msg)}`, '_blank');
    };


    // عرض شاشة التحميل
    if (loading) {
        return (
            <div className="min-h-screen bg-black flex items-center justify-center">
                <Navbar />
                <div className="text-center space-y-4">
                    <div className="w-16 h-16 border-2 border-[#c9a96e]/30 border-t-[#c9a96e] rounded-full animate-spin mx-auto" />
                    <p className="text-white/30 text-[11px] uppercase tracking-[0.4em] font-black animate-pulse">
                        {isRTL ? 'جاري التحميل...' : 'LOADING...'}
                    </p>
                </div>
            </div>
        );
    }

    // عرض رسالة الخطأ
    if (error || !car) {
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6">
                <Navbar />
                <AlertCircle className="w-20 h-20 text-white/10" />
                <h1 className="text-2xl font-black uppercase text-white/30 tracking-widest">
                    {error || (isRTL ? 'لم يتم العثور على السيارة' : 'Car not found')}
                </h1>
                <button
                    onClick={() => router.back()}
                    className="px-8 py-4 bg-[#c9a96e]/10 border border-[#c9a96e]/30 rounded-2xl text-[#c9a96e] text-[11px] font-black uppercase tracking-widest hover:bg-[#c9a96e]/20 transition-all"
                >
                    {isRTL ? 'العودة' : 'GO BACK'}
                </button>
            </div>
        );
    }

    const getBaseUsd = (payload: any) => {
        const baseUsd = toFiniteNumber(payload?.basePriceUsd);
        if (baseUsd && baseUsd > 0) return baseUsd;

        const priceUsd = toFiniteNumber(payload?.priceUsd);
        if (priceUsd && priceUsd > 0) return priceUsd;

        const priceSar = toFiniteNumber(payload?.priceSar ?? payload?.price);
        if (priceSar && priceSar > 0) return priceSar / Number(currency.usdToSar || 1);

        const priceKrw = toFiniteNumber(payload?.priceKrw);
        if (priceKrw && priceKrw > 0) return priceKrw / Number(currency.usdToKrw || 1);

        return 0;
    };

    const carMake = typeof car.make === 'object' ? car.make?.name : car.make;
    const images = car.images?.filter(Boolean) || [];
    const baseUsd = getBaseUsd(car);
    const displayPrice = formatPriceFromUsd
        ? formatPriceFromUsd(baseUsd)
        : (formatPrice ? formatPrice(Number(car.priceSar || car.price || 0)) : `${Number(car.priceSar || car.price || 0).toLocaleString()} SAR`);

    const specs = [
        { icon: Calendar, label: isRTL ? 'السنة' : 'YEAR', value: car.year },
        { icon: Gauge, label: isRTL ? 'المسافة' : 'MILEAGE', value: car.mileage ? `${car.mileage.toLocaleString()} ${isRTL ? 'كم' : 'KM'}` : '—' },
        { icon: Fuel, label: isRTL ? 'الوقود' : 'FUEL', value: car.fuelType || '—' },
        { icon: Settings2, label: isRTL ? 'ناقل الحركة' : 'TRANSMISSION', value: car.transmission || '—' },
        { icon: Car, label: isRTL ? 'الفئة' : 'CATEGORY', value: car.category || '—' },
        { icon: Tag, label: isRTL ? 'اللون' : 'COLOR', value: car.color || '—' },
    ];

    return (
        <div
            className="relative min-h-screen bg-[#050505] text-white overflow-x-hidden"
            dir={isRTL ? 'rtl' : 'ltr'}
        >
            <Navbar />

            {/* خلفية زخرفية */}
            <div className="fixed inset-0 pointer-events-none z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_30%_20%,rgba(201,169,110,0.05)_0%,transparent_60%)]" />
            </div>

            <main className="relative z-10 pt-28 pb-24 px-4 sm:px-6 max-w-7xl mx-auto">

                {/* زر العودة */}
                <motion.button
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    onClick={() => router.back()}
                    className="flex items-center gap-2 mb-10 px-4 py-2 rounded-xl bg-white/5 border border-white/10 text-white/60 hover:text-white hover:bg-white/10 transition-all group w-fit"
                >
                    <ChevronLeft className={cn('w-4 h-4 transition-transform group-hover:-translate-x-1', isRTL && 'rotate-180 group-hover:translate-x-1')} />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">
                        {isRTL ? 'العودة للمعرض' : 'BACK TO SHOWROOM'}
                    </span>
                </motion.button>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">

                    {/* قسم الصور */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6 }}
                        className="space-y-4"
                    >
                        {/* الصورة الرئيسية */}
                        <div className="relative aspect-[4/3] rounded-3xl overflow-hidden border border-white/10 bg-white/[0.02]">
                            {images.length > 0 ? (
                                <Image
                                    src={images[activeImage]}
                                    alt={car.title}
                                    fill
                                    className="object-cover"
                                    unoptimized
                                />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center">
                                    <ImageIcon className="w-20 h-20 text-white/10" />
                                </div>
                            )}

                            {/* شارة الحالة */}
                            <div className="absolute top-4 right-4 flex gap-2">
                                <span className="px-3 py-1 bg-[#c9a96e]/20 border border-[#c9a96e]/40 rounded-lg text-[10px] font-black text-[#c9a96e] uppercase tracking-widest backdrop-blur-md">
                                    {isRTL ? 'معرض' : 'SHOWROOM'}
                                </span>
                                {car.isActive && (
                                    <span className="px-3 py-1 bg-green-400/20 border border-green-400/40 rounded-lg text-[10px] font-black text-green-400 uppercase tracking-widest backdrop-blur-md flex items-center gap-1">
                                        <CheckCircle className="w-3 h-3" />
                                        {isRTL ? 'متوفر' : 'AVAILABLE'}
                                    </span>
                                )}
                            </div>
                        </div>

                        {/* الصور المصغرة */}
                        {images.length > 1 && (
                            <div className="flex gap-3 overflow-x-auto pb-2">
                                {images.map((img: string, idx: number) => (
                                    <button
                                        key={idx}
                                        onClick={() => setActiveImage(idx)}
                                        className={cn(
                                            'relative w-20 h-20 shrink-0 rounded-xl overflow-hidden border-2 transition-all',
                                            activeImage === idx
                                                ? 'border-[#c9a96e] shadow-[0_0_15px_rgba(201,169,110,0.4)]'
                                                : 'border-white/10 opacity-50 hover:opacity-80'
                                        )}
                                    >
                                        <Image src={img} alt={`صورة ${idx + 1}`} fill className="object-cover" unoptimized />
                                    </button>
                                ))}
                            </div>
                        )}
                    </motion.div>

                    {/* قسم التفاصيل */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6, delay: 0.1 }}
                        className="space-y-8"
                    >
                        {/* العنوان والسعر */}
                        <div>
                            <div className="text-[11px] font-black text-[#c9a96e]/70 uppercase tracking-[0.4em] mb-2 italic">
                                {carMake}
                            </div>
                            <h1 className="text-4xl md:text-5xl font-black uppercase italic tracking-tighter mb-4 leading-tight">
                                {car.title}
                            </h1>
                            <div className="text-3xl font-black text-[#c9a96e]">
                                {displayPrice}
                            </div>
                        </div>

                        {/* المواصفات */}
                        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                            {specs.map((spec, i) => (
                                <motion.div
                                    key={spec.label}
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: i * 0.05 + 0.2 }}
                                    className="bg-white/[0.02] border border-white/8 rounded-2xl p-4 space-y-2 hover:border-[#c9a96e]/20 transition-all"
                                >
                                    <spec.icon className="w-4 h-4 text-[#c9a96e]/60" />
                                    <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/30">{spec.label}</div>
                                    <div className="text-sm font-black text-white/80 capitalize">{spec.value}</div>
                                </motion.div>
                            ))}
                        </div>

                        {/* الوصف */}
                        {car.description && (
                            <div className="bg-white/[0.02] border border-white/8 rounded-2xl p-6">
                                <div className="text-[9px] font-black uppercase tracking-[0.3em] text-white/30 mb-3">
                                    {isRTL ? 'الوصف' : 'DESCRIPTION'}
                                </div>
                                <p className="text-white/60 text-sm leading-relaxed">{car.description}</p>
                            </div>
                        )}

                        {/* أزرار الاضافة لطلباتي + واتساب */}
                        <div className="space-y-4 pt-4">
                            {/* زر الشراء عبر الواتساب */}
                            <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={handleWhatsappPurchase}
                                className="w-full py-5 bg-green-500/90 hover:bg-green-500 rounded-2xl text-black font-black uppercase text-[13px] tracking-[0.3em] shadow-[0_0_40px_rgba(34,197,94,0.3)] hover:shadow-[0_0_60px_rgba(34,197,94,0.5)] transition-all flex items-center justify-center gap-3"
                            >
                                <MessageCircle className="w-5 h-5" />
                                {isRTL ? 'طلب الشراء عبر واتساب' : 'BUY VIA WHATSAPP'}
                            </motion.button>

                            {/* زر عرض الفاتورة */}
                            <button
                                onClick={() => setShowInvoice(true)}
                                className="w-full py-4 bg-white/5 border border-white/10 rounded-2xl text-white/60 font-black uppercase text-[11px] tracking-[0.3em] hover:bg-white/10 hover:text-white transition-all"
                            >
                                {isRTL ? 'عرض الفاتورة' : 'VIEW INVOICE'}
                            </button>
                        </div>
                    </motion.div>
                </div>
            </main>

            {/* [[ARABIC_COMMENT]] نافذة الفاتورة */}
            <AnimatePresence>
                {showInvoice && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex items-center justify-center p-6"
                        onClick={() => setShowInvoice(false)}
                    >
                        <motion.div
                            initial={{ scale: 0.9, y: 20 }}
                            animate={{ scale: 1, y: 0 }}
                            exit={{ scale: 0.9, y: 20 }}
                            onClick={e => e.stopPropagation()}
                            className="bg-[#0a0a0a] border border-white/10 rounded-3xl w-full max-w-md overflow-hidden"
                        >
                            {/* رأس الفاتورة */}
                            <div className="p-8 border-b border-white/5 text-center bg-[#c9a96e]/5">
                                <div className="text-2xl font-black text-[#c9a96e] mb-1">HM CAR</div>
                                <div className="text-[10px] text-white/40 uppercase tracking-[0.3em]">
                                    {isRTL ? 'فاتورة مبدئية' : 'PRELIMINARY INVOICE'}
                                </div>
                            </div>

                            {/* تفاصيل الفاتورة */}
                            <div className="p-8 space-y-4">
                                {[
                                    { label: isRTL ? 'السيارة' : 'VEHICLE', value: car.title },
                                    { label: isRTL ? 'الماركة' : 'MAKE', value: carMake },
                                    { label: isRTL ? 'الموديل' : 'MODEL', value: car.model },
                                    { label: isRTL ? 'السنة' : 'YEAR', value: car.year },
                                    { label: isRTL ? 'اللون' : 'COLOR', value: car.color || '—' },
                                    { label: isRTL ? 'ناقل الحركة' : 'TRANSMISSION', value: car.transmission || '—' },
                                ].map(item => (
                                    <div key={item.label} className="flex justify-between items-center border-b border-white/5 pb-3">
                                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">{item.label}</span>
                                        <span className="text-[12px] font-bold text-white/80">{item.value}</span>
                                    </div>
                                ))}
                                <div className="flex justify-between items-center pt-4">
                                    <span className="text-[11px] font-black uppercase tracking-[0.3em] text-[#c9a96e]">
                                        {isRTL ? 'السعر الإجمالي' : 'TOTAL PRICE'}
                                    </span>
                                    <span className="text-xl font-black text-[#c9a96e]">{displayPrice}</span>
                                </div>
                            </div>

                            {/* أزرار الفاتورة */}
                            <div className="p-6 border-t border-white/5 grid grid-cols-2 gap-3">
                                <button
                                    onClick={handleWhatsappPurchase}
                                    className="py-4 bg-green-500/90 rounded-xl text-black font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2"
                                >
                                    <MessageCircle className="w-4 h-4" />
                                    {isRTL ? 'شراء' : 'BUY'}
                                </button>
                                <button
                                    onClick={() => setShowInvoice(false)}
                                    className="py-4 bg-white/5 border border-white/10 rounded-xl text-white/60 font-black text-[10px] uppercase tracking-widest"
                                >
                                    {isRTL ? 'إغلاق' : 'CLOSE'}
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import { Canvas, useFrame } from "@react-three/fiber";
import { Stars, Sparkles, Float, PerspectiveCamera } from "@react-three/drei";
import { EffectComposer, Bloom, Noise, Vignette } from "@react-three/postprocessing";
import { useRef, useMemo } from "react";
import * as THREE from "three";

function MovingGrid() {
  const gridRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (gridRef.current) {
      // Move grid towards camera to simulate speed
      gridRef.current.position.z = (state.clock.elapsedTime * 2) % 10;
    }
  });

  return (
    <group ref={gridRef} position={[0, -2, 0]}>
      <gridHelper args={[100, 50, 0x333333, 0x111111]} position={[0, 0, 0]} />
      <gridHelper args={[100, 50, 0x333333, 0x111111]} position={[0, 0, -100]} />
    </group>
  );
}

function FloatingParticles() {
  return (
    <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
      <Sparkles 
        count={200} 
        scale={20} 
        size={4} 
        speed={0.4} 
        opacity={0.6}
        color="#c9a96e"
      />
      <Sparkles 
        count={100} 
        scale={15} 
        size={6} 
        speed={0.3} 
        opacity={0.4}
        color="#ffffff"
      />
    </Float>
  );
}

function Scene() {
  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 0, 5]} fov={75} />
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1} color="#c9a96e" />

      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />
      <MovingGrid />
      <FloatingParticles />

      {/* Fog to hide the end of the grid */}
      <fog attach="fog" args={['#000000', 5, 30]} />
    </>
  );
}

export default function CinematicBackground() {
  return (
    <div className="fixed inset-0 z-[-1] bg-black">
      <Canvas dpr={[1, 2]} gl={{ antialias: false }}>
        <Scene />
        <EffectComposer enableNormalPass={false}>
