                                    className={`w-14 h-12 rounded-2xl border flex items-center justify-center transition-all ${isFavorite
                                        ? 'bg-red-500/20 border-red-500/40 text-red-400 shadow-[0_0_20px_rgba(239,68,68,0.2)]'
