            key: 'whatsapp',
            icon: MessageCircle,
            color: 'bg-green-500/10 hover:bg-green-500/20 border border-green-500/20',
            href: socialLinks.whatsapp ? `https://wa.me/${socialLinks.whatsapp.replace(/[^0-9]/g, '')}` : null,
            label: 'WhatsApp'
        },
        {
            key: 'instagram',
            icon: Instagram,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.instagram,
            label: 'Instagram'
        },
        {
            key: 'twitter',
            icon: XIcon,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.twitter,
            label: 'X'
        },
        {
            key: 'facebook',
            icon: Facebook,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.facebook,
            label: 'Facebook'
        },
        {
            key: 'youtube',
            icon: Youtube,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.youtube,
            label: 'YouTube'
        },
        {
            key: 'tiktok',
            icon: TikTokIcon,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.tiktok,
            label: 'TikTok'
        },
        {
            key: 'snapchat',
            icon: SnapchatIcon,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.snapchat ? `https://snapchat.com/add/${socialLinks.snapchat}` : null,
            label: 'Snapchat'
        },
        {
            key: 'telegram',
            icon: Send,
            color: 'bg-white/5 hover:bg-white/10 border border-white/10',
            href: socialLinks.telegram,
            label: 'Telegram'
        },
        {
            key: 'linkedin',
