export const WhatsAppService = {
    /**
     * توليد رابط واتساب لسيارة محددة من المعرض الكوري أو المحلي
     */
    generateCarLink: (car: any, phoneNumber: string, isRTL: boolean, formatPrice?: (p: number) => string) => {
        if (!car) return '';

        const carTitle = car.title || car.model || 'سيارة من المعرض';
        const carMake = typeof car.make === 'object' ? car.make?.name : car.make;
        const price = formatPrice ? formatPrice(Number(car.price || 0)) : `${Number(car.price || 0).toLocaleString()} SAR`;

        const msg = isRTL
            ? `السلام عليكم HM CAR،\n\nأرغب في الاستفسار عن هذه السيارة:\n🚗 *${carTitle}*\n🛠️ الماركة: ${carMake}\n📅 الموديل: ${car.year || 'غير محدد'}\n💰 السعر: ${price}\n\nأرجو تزويدي بمزيد من التفاصيل.`
            : `Hello HM CAR,\n\nI'm interested in this vehicle:\n🚗 *${carTitle}*\n🛠️ Make: ${carMake}\n📅 Year: ${car.year || 'N/A'}\n💰 Price: ${price}\n\nPlease provide more details.`;

        const cleanPhone = phoneNumber.replace(/\D/g, '');
        return `https://wa.me/${cleanPhone}?text=${encodeURIComponent(msg)}`;
    },

    /**
     * رابط عام لخدمة العملاء
     */
    getSupportLink: (phoneNumber: string, isRTL: boolean) => {
        const msg = isRTL 
            ? 'السلام عليكم، أحتاج إلى مساعدة بخصوص خدمات HM CAR.'
            : 'Hello, I need assistance regarding HM CAR services.';
        const cleanPhone = phoneNumber.replace(/\D/g, '');
        return `https://wa.me/${cleanPhone}?text=${encodeURIComponent(msg)}`;
    }
};

// [[ARABIC_HEADER]] هذا الملف (client-app/src/lib/api.ts) جزء من مشروع HM CAR ويحتوي تعليقات عربية لضمان الوضوح.

const isBrowser = typeof window !== 'undefined';
// الأفضل استخدام الرابط الثابت في الإنتاج إذا كان العميل والارسال منفصلين
const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || (isBrowser ? '' : 'https://car-auction-sand.vercel.app');

export async function fetchAPI(endpoint: string, options: RequestInit = {}) {
    const url = `${API_BASE_URL}${endpoint}`;

    // Don't set Content-Type for FormData — let the browser set it with the boundary
    const isFormData = options.body instanceof FormData;

    const defaultHeaders: Record<string, string> = isFormData
        ? { 'Accept': 'application/json' }
        : { 'Content-Type': 'application/json', 'Accept': 'application/json' };

    // If using JWT from local storage
    if (typeof window !== 'undefined') {
        const token = localStorage.getItem('hm_token');
        if (token) {
            defaultHeaders['Authorization'] = `Bearer ${token}`;
        }
    }

    const defaultOptions: RequestInit = {
        ...options,
        cache: 'no-store', // Disable aggressive Next.js built-in fetch caching
        headers: {
            ...defaultHeaders,
            ...(options.headers as Record<string, string> || {}),
        },
    };

    console.log(`[API Request] ${options.method || 'GET'} ${url}`, options.body && !isFormData ? JSON.parse(options.body as string) : options.body);

    try {
        const response = await fetch(url, defaultOptions);
        console.log(`[API Response Status] ${response.status} for ${url}`);

        const data = await response.json().catch(() => ({}));
        console.log(`[API Response Data]`, data);

        if (!response.ok) {
            let message = data.message || data.error || `فشل الطلب: ${response.status}`;

            // [[ARABIC_COMMENT]] معالجة خاصة لرسالة تخطي عدد الطلبات المسموح به
            if (response.status === 429) {
                message = 'لقد قمت بعدد كبير من المحاولات. يرجى الانتظار قليلاً قبل المحاولة مرة أخرى.';
            }

            const customError: any = new Error(message);
            customError.status = response.status;
            customError.banned = data.banned;
            customError.banCode = data.banCode;
            throw customError;
        }

        return data;
    } catch (error: any) {
        console.error(`[API Error] ${url}:`, error);
        throw error;
    }
}

